/* AUTO-GENERATED — Hawaii Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["HI"] = {"code":"HI","name":"Hawaii","agency":"Hawaii DOT","agencyShort":"DOT","handbook":"https://hidot.hawaii.gov/highways/files/2025/08/2025-06-CDL-Manual-rev.pdf","links":{},"en":[{"q":"Under Hawaii law, what is the maximum overall WIDTH (including load) of a vehicle that may be operated on a public highway without an oversize permit?","options":["8 feet","8 feet 6 inches","9 feet","10 feet"],"answer":2,"explanation":"HRS §291-34 prohibits operating a motor vehicle whose overall width, including load, exceeds nine feet on any public road, street, or highway in the State without a permit. (Hawaii Revised Statutes §291-34; Hawaii CDL Manual.)","handbook":"","hbref":""},{"q":"What is the maximum overall HEIGHT (including load) allowed for a vehicle on Hawaii highways without a permit?","options":["13 feet","13 feet 6 inches","14 feet","15 feet"],"answer":2,"explanation":"HRS §291-34 sets the maximum vehicle height, including load, at fourteen feet. Even within that limit, a vehicle may not pass under a bridge or structure if it exceeds the posted clearance for that structure. (Hawaii Revised Statutes §291-34.)","handbook":"","hbref":""},{"q":"On Hawaii highways, what is the maximum overall LENGTH of a single motor vehicle (a non-combination unit), including load, without a permit?","options":["40 feet","45 feet","53 feet","60 feet"],"answer":1,"explanation":"HRS §291-34 limits a single motor vehicle (not a combination) to forty-five feet in overall length, including load. (Hawaii Revised Statutes §291-34.)","handbook":"","hbref":""},{"q":"Under HRS §291-34, what is the maximum overall length of a truck-tractor and semitrailer COMBINATION, including load, allowed without a permit in Hawaii?","options":["60 feet","65 feet","70 feet","75 feet"],"answer":1,"explanation":"HRS §291-34 caps a truck-tractor and semitrailer combination at sixty-five feet in total overall length, including load. (Hawaii Revised Statutes §291-34.)","handbook":"","hbref":""},{"q":"In Hawaii, the maximum gross weight imposed on the highway by any one SINGLE AXLE may not exceed:","options":["18,000 pounds","20,000 pounds","22,500 pounds","34,000 pounds"],"answer":1,"explanation":"HRS §291-35 limits the gross weight on any single axle to twenty thousand pounds. (Hawaii Revised Statutes §291-35.)","handbook":"","hbref":""},{"q":"A 'tandem axle' in Hawaii (two consecutive axles spaced more than 40 inches but not more than 96 inches apart) may carry a maximum gross weight of:","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"answer":1,"explanation":"HRS §291-35 limits a tandem axle (axles spaced more than 40 inches but no more than 96 inches) to thirty-four thousand pounds. (Hawaii Revised Statutes §291-35.)","handbook":"","hbref":""},{"q":"Under Hawaii's weight law, the gross weight imposed on the highway by any one WHEEL, whether single or dual mounting, may not exceed:","options":["8,000 pounds","10,000 pounds","12,000 pounds","13,500 pounds"],"answer":1,"explanation":"HRS §291-35 limits the gross weight on any one wheel (single or dual mounting) to ten thousand pounds. (Hawaii Revised Statutes §291-35.)","handbook":"","hbref":""},{"q":"What is the maximum overall GROSS WEIGHT allowed for a vehicle or combination on Hawaii highways without an overweight permit?","options":["73,280 pounds","80,000 pounds","88,000 pounds","105,500 pounds"],"answer":1,"explanation":"HRS §291-35 caps the overall gross vehicular weight at eighty thousand pounds, consistent with the federal limit. (Hawaii Revised Statutes §291-35.)","handbook":"","hbref":""},{"q":"Two consecutive sets of tandem axles may each carry 34,000 pounds in Hawaii only if the distance between the first and last axles of the two tandem sets is at least:","options":["28 feet","32 feet","36 feet","40 feet"],"answer":2,"explanation":"HRS §291-35 allows two consecutive tandem-axle sets to carry 34,000 pounds each only when the overall distance between the first and last axles is thirty-six feet or more, and the total gross weight stays at or below 80,000 pounds. (Hawaii Revised Statutes §291-35.)","handbook":"","hbref":""},{"q":"The formula in HRS §291-35 that ties a group of axles' allowable gross weight to the spacing and number of axles is based on which federal standard?","options":["The Federal Bridge Formula (Bridge Gross Weight Formula)","The CARB axle-spacing rule","The AASHTO pavement loading index","The FMCSA hours-of-service table"],"answer":0,"explanation":"Hawaii's axle-group weight provisions in HRS §291-35 incorporate the Federal Bridge Formula, which relates allowable weight to the number of axles and the distance between the extreme axles of a group. (Hawaii Revised Statutes §291-35; 23 U.S.C. §127, applied as the Hawaii rule.)","handbook":"","hbref":""},{"q":"Who has the authority to issue a written permit allowing oversize or overweight movement on a STATE highway in Hawaii?","options":["The county police chief","The Director of Transportation","The Public Utilities Commission","The Honolulu Harbor Master"],"answer":1,"explanation":"Under HRS §291-36, the Director of Transportation issues oversize/overweight permits for state highways, while the county engineer issues them for county roads and streets. (Hawaii Revised Statutes §291-36; HIDOT Highways Division.)","handbook":"","hbref":""},{"q":"For movements on COUNTY roads and streets in Hawaii, who issues the oversize/overweight permit?","options":["The Director of Transportation","The county engineer","The mayor's office","The state Department of Public Safety"],"answer":1,"explanation":"HRS §291-36 assigns permit authority for county roads and streets to the county engineer (the Director of Transportation handles state highways). (Hawaii Revised Statutes §291-36.)","handbook":"","hbref":""},{"q":"How must an application for a Hawaii oversize/overweight permit be submitted?","options":["Orally by telephone to the district office","In writing on forms furnished by the Highways Division","Only through a licensed customs broker","By posting a notice at the weigh station"],"answer":1,"explanation":"HRS §291-36 requires a written application, and the HIDOT Highways Division requires it on its furnished forms, including sketches of the wheel arrangement, dimensions, and load distribution. (Hawaii Revised Statutes §291-36; HIDOT Oversize/Overweight permit procedures.)","handbook":"","hbref":""},{"q":"In addition to the application, what does the Hawaii Highways Division require an oversize/overweight permit applicant to have on file?","options":["A certificate of insurance","A commercial fishing license","A notarized harbor bond","A federal IRP cab card"],"answer":0,"explanation":"The HIDOT Highways Division requires a certificate of insurance on file before issuing an oversize/overweight permit. (HIDOT Oversize/Overweight Vehicles on State Highways permit procedures.)","handbook":"","hbref":""},{"q":"Per Hawaii's permit fee schedule, the fee for a SINGLE-TRIP permit for a load less than 1.35 times the allowable weight or less than 14 feet wide is:","options":["$5","$10","$25","$50"],"answer":0,"explanation":"Under HRS §291-36, a single-trip permit for a load less than 1.35 times the allowable load or less than 14 feet in width costs $5 (a continuous-trip permit in that range is $10). (Hawaii Revised Statutes §291-36; HIDOT.)","handbook":"","hbref":""},{"q":"Under Hawaii's permit fee schedule, the fee for an OVERWEIGHT permit for a load in EXCESS of 1.35 times the allowable load is:","options":["$5","$10","$25","$100"],"answer":2,"explanation":"HRS §291-36 sets a $25 fee for an overweight permit when the load exceeds 1.35 times the allowable load; the same $25 applies to an oversize permit exceeding 14 feet in width. (Hawaii Revised Statutes §291-36; HIDOT.)","handbook":"","hbref":""},{"q":"An oversize WIDTH permit in Hawaii is required (and carries the higher $25 fee) once a load's width exceeds:","options":["9 feet","10 feet","12 feet","14 feet"],"answer":3,"explanation":"While any width over 9 feet requires a permit, HRS §291-36's fee schedule treats a load exceeding 14 feet in width as requiring the $25 oversize permit category. (Hawaii Revised Statutes §291-36; HIDOT permit fee schedule.)","handbook":"","hbref":""},{"q":"Under Hawaii's agricultural provisions, when may the Director of Transportation issue a permit allowing weights exceeding the HRS §291-35 limits?","options":["Only for vehicles owned by the State","When carrying harvested products from where they are harvested or stored to where they are processed or used","Only between midnight and 5 a.m.","Never — no overweight farm permits are allowed"],"answer":1,"explanation":"HRS §291-36 authorizes a permit to exceed the §291-35 weight limits when carrying products from where they are harvested or stored to where they are processed or used. (Hawaii Revised Statutes §291-36.)","handbook":"","hbref":""},{"q":"Which agricultural movement in Hawaii requires NO permit at all under HRS §291-36?","options":["Any farm vehicle traveling 10 miles or less on a state highway","A vehicle used in agricultural operations that only CROSSES a public road at a location approved by the Director of Transportation or county engineer","Any vehicle hauling pineapple regardless of weight","A combination under 80,000 pounds carrying coffee"],"answer":1,"explanation":"HRS §291-36 provides that no permit is required for a vehicle used in agricultural operations that only crosses a public road, street, or highway at a location approved by the Director of Transportation (state highways) or county engineer (county roads). (Hawaii Revised Statutes §291-36.)","handbook":"","hbref":""},{"q":"If an engineering analysis shows a Hawaii bridge can safely carry less than the statutory maximum gross weight, what may the responsible authority do?","options":["Close the bridge permanently to all trucks","Post and maintain signs limiting the gross weight of vehicles crossing that bridge","Raise the statewide gross weight limit to compensate","Require a CDL upgrade for that route"],"answer":1,"explanation":"HRS §291-35 allows the Director of Transportation (or county engineer) to place and maintain signs limiting gross weight over a specific bridge or structure when engineering analysis shows its capacity is less than the statutory maximum; drivers must obey the posted limit. (Hawaii Revised Statutes §291-35.)","handbook":"","hbref":""},{"q":"In Hawaii, which CDL class is required to drive any combination of vehicles with a gross combination weight rating (GCWR) of 26,001 pounds or more, when the vehicle(s) being towed have a GVWR over 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"Hawaii defines a Class A CDL as any combination of vehicles with a GCWR of 26,001 lbs or more provided the towed unit's GVWR exceeds 10,000 lbs. Source: HRS Sec. 286-239 and the Honolulu Commercial Driver Licensing Office. There is no federal/Hawaii 'Class D' CDL.","handbook":"","hbref":""},{"q":"Under Hawaii law, a single vehicle with a gross vehicle weight rating (GVWR) of 26,001 pounds or more (or such a vehicle towing a unit not over 10,000 pounds) requires which CDL class?","options":["Class A","Class B","Class C","Class M"],"answer":1,"explanation":"Hawaii classifies a single vehicle with a GVWR of 26,001 lbs or more as a Class B commercial motor vehicle. Source: HRS Sec. 286-239; Honolulu CDL Office. 'Class M' is a motorcycle category, not a CDL.","handbook":"","hbref":""},{"q":"A Hawaii driver operates a vehicle under 26,001 lbs GVWR that is designed to carry 16 or more passengers (including the driver) or is placarded for hazardous materials. Which CDL class applies?","options":["Class A","Class B","Class C","No CDL needed"],"answer":2,"explanation":"A Class C CDL covers vehicles that meet neither Class A nor B but are designed to transport 16+ passengers (including the driver) or carry placarded hazmat. Source: HRS Sec. 286-239; Honolulu CDL Office.","handbook":"","hbref":""},{"q":"Which endorsement code on a Hawaii CDL authorizes driving a vehicle that transports hazardous materials requiring placards?","options":["Endorsement N","Endorsement T","Endorsement H","Endorsement P"],"answer":2,"explanation":"The H (HazMat) endorsement authorizes operating a vehicle carrying placarded hazardous materials. Source: Hawaii CDL Manual / Honolulu CDL Office; 49 CFR Part 383 (adopted by Hawaii).","handbook":"","hbref":""},{"q":"On a Hawaii CDL, which endorsement is required to drive double and triple trailers?","options":["Endorsement T","Endorsement N","Endorsement S","Endorsement H"],"answer":0,"explanation":"The T endorsement authorizes operating double and triple trailers. Source: Hawaii CDL Manual / Honolulu CDL Office; 49 CFR 383.93.","handbook":"","hbref":""},{"q":"Which endorsement does Hawaii require to drive a tank vehicle, generally one designed to haul liquids or gases in a permanently mounted tank with a rated capacity over 1,000 gallons?","options":["Endorsement P","Endorsement N","Endorsement T","Endorsement X"],"answer":1,"explanation":"The N (Tanker) endorsement is required for tank vehicles; Hawaii references tanks exceeding 1,000 gallons. Source: Honolulu CDL Office; 49 CFR 383.93. The X code denotes a combined tank + hazmat, not tanker alone.","handbook":"","hbref":""},{"q":"What endorsement must a Hawaii CDL holder obtain to drive a vehicle designed to carry 16 or more passengers (including the driver)?","options":["Endorsement S","Endorsement N","Endorsement P","Endorsement T"],"answer":2,"explanation":"The P (Passenger) endorsement is required to carry 16 or more passengers, including the driver. Source: Honolulu CDL Office; 49 CFR 383.93. The S endorsement is specifically for school buses.","handbook":"","hbref":""},{"q":"To drive a school bus in Hawaii, a CDL holder must hold the S endorsement. Which additional passenger-related endorsement is also required?","options":["Endorsement N","Endorsement T","Endorsement H","Endorsement P"],"answer":3,"explanation":"A school bus driver must hold both the S (School Bus) and P (Passenger) endorsements. Source: Hawaii CDL Manual; 49 CFR 383.93, adopted by Hawaii.","handbook":"","hbref":""},{"q":"What is the minimum age required to obtain a Hawaii CDL authorizing interstate (across state lines) commercial driving?","options":["18 years old","19 years old","20 years old","21 years old"],"answer":3,"explanation":"Interstate commercial driving requires a minimum age of 21. Intrastate-only operation may be allowed at 18. Source: Honolulu CDL Office; 49 CFR 391.11(b).","handbook":"","hbref":""},{"q":"Before applying for a Hawaii CDL, a driver must first obtain which credential by passing the required knowledge test(s)?","options":["Commercial Learner Permit (CLP)","Provisional CDL","Temporary HazMat card","Class C instruction permit"],"answer":0,"explanation":"Applicants must first obtain a Commercial Learner Permit (CLP) by passing the knowledge test(s) before taking the CDL skills test. Source: Honolulu CDL Office; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"Under federal rules adopted by Hawaii, how long must a driver hold a Commercial Learner Permit before being eligible to take the CDL skills test?","options":["At least 7 days","At least 14 days","At least 30 days","At least 60 days"],"answer":1,"explanation":"A driver must hold the CLP for at least 14 days before taking the skills test; Hawaii schedules the skills test no sooner than 14 days after the permit is issued. Source: Honolulu CDL Office; 49 CFR 383.25(e).","handbook":"","hbref":""},{"q":"For how long is a Hawaii Commercial Learner Permit (CLP) valid before it must be renewed?","options":["90 days","180 days","1 year","2 years"],"answer":1,"explanation":"A Hawaii CLP is valid for 180 days. Source: Hawaii CDL Manual / DMV guidance; 49 CFR 383.25(c).","handbook":"","hbref":""},{"q":"While driving on a Hawaii Commercial Learner Permit, the permit holder must:","options":["Drive alone during daylight hours only","Be accompanied by a CDL holder seated next to them","Have a passenger endorsement before any practice","Drive only on private property"],"answer":1,"explanation":"A CLP holder must be accompanied at all times by a person who holds a valid CDL (for the class/endorsements being practiced) seated in the front seat. Source: Hawaii CDL Manual; 49 CFR 383.25(a).","handbook":"","hbref":""},{"q":"Which document does Hawaii's CDL issuing office accept as proof of identity and lawful presence for a U.S. citizen applicant?","options":["A library card","A certified U.S. birth certificate","A vehicle registration","A utility bill only"],"answer":1,"explanation":"Hawaii requires a certified U.S. birth certificate (or other approved proof) to establish identity and lawful presence. Source: Honolulu CDL Office document list.","handbook":"","hbref":""},{"q":"How many proof-of-residence documents does Hawaii's CDL office require an applicant to present?","options":["None","One","Two","Four"],"answer":2,"explanation":"Hawaii requires two proof-of-residence documents to establish Hawaii residency for a CDL. Source: Honolulu CDL Office document checklist.","handbook":"","hbref":""},{"q":"Which medical document must a Hawaii CDL applicant submit to certify their physical qualification to drive?","options":["A current DOT Medical Examiner's Certificate (MCSA-5876)","A dental clearance form","A notarized health affidavit","A primary-care prescription"],"answer":0,"explanation":"Applicants must submit a current DOT physical / Medical Examiner's Certificate (Form MCSA-5876). Source: Honolulu CDL Office; 49 CFR 391.43.","handbook":"","hbref":""},{"q":"Which medical self-certification category applies to a Hawaii CDL driver who operates across state lines and is subject to and meets the federal medical-certificate requirement?","options":["Excepted Interstate","Non-Excepted Interstate","Excepted Intrastate","Non-Excepted Intrastate"],"answer":1,"explanation":"A driver in interstate commerce who must meet the federal Part 391 medical-certificate requirement self-certifies as Non-Excepted Interstate. Source: 49 CFR 383.71(b), adopted by Hawaii.","handbook":"","hbref":""},{"q":"Since February 7, 2022, before taking the skills test for a first Hawaii Class A or B CDL (or a first P, S, or H endorsement), an applicant must complete which requirement?","options":["A 5-year clean driving record","FMCSA Entry-Level Driver Training (ELDT) from a registered provider","A defensive-driving course at any school","A two-year apprenticeship"],"answer":1,"explanation":"ELDT is required for first-time Class A/B CDLs and first-time P, S, or H endorsements; training must come from a provider on the FMCSA Training Provider Registry. Source: 49 CFR Part 380 (effective Feb. 7, 2022); Honolulu CDL Office.","handbook":"","hbref":""},{"q":"In addition to passing the HazMat knowledge test, what must a Hawaii applicant complete before the H (HazMat) endorsement is issued?","options":["A TSA security threat assessment (background check)","A road test in a tank vehicle","An emissions inspection","A boating safety course"],"answer":0,"explanation":"Federal law requires every HazMat-endorsement applicant to pass a TSA security threat assessment (background check with fingerprinting) before issuance, in addition to the knowledge test and ELDT. Source: 49 CFR 1572 (TSA); 49 CFR 383.141; Hawaii CDL Office.","handbook":"","hbref":""},{"q":"In Hawaii, a person commits a major disqualifying offense by operating a commercial motor vehicle (CMV) while having a blood alcohol concentration (BAC) of at least what level?","options":["0.02","0.04","0.08","0.10"],"answer":1,"explanation":"Hawaii sets the CMV alcohol limit at 0.04 BAC, half the 0.08 limit for ordinary drivers. Operating a CMV at 0.04 or greater is a major offense. Source: Hawaii CDL Manual (Hawaii DOT) and HRS 286-240; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Hawaii's implied-consent law, by driving on the state's highways a commercial driver is deemed to have given consent to what?","options":["A vehicle inspection at any weigh station","A test of breath, blood, or urine for alcohol or drug content if arrested","A search of the cab without a warrant","A medical recertification exam every year"],"answer":1,"explanation":"Hawaii's implied-consent law deems any driver to have consented to a test of breath, blood, or urine to determine alcohol concentration or drug content when lawfully arrested. Source: HRS 291E-11 (implied consent); Hawaii CDL Manual.","handbook":"","hbref":""},{"q":"A Hawaii CDL holder is convicted of a first major offense (such as DUI in a CMV) while NOT transporting placarded hazardous materials. The minimum disqualification period is:","options":["60 days","120 days","1 year","3 years"],"answer":2,"explanation":"A first major offense carries a minimum 1-year CDL disqualification in Hawaii. Source: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"If the first major offense occurs while the driver is operating a CMV transporting hazardous materials requiring placards, the disqualification period increases to:","options":["1 year","18 months","3 years","5 years"],"answer":2,"explanation":"A first major offense committed while transporting placarded hazardous materials raises the disqualification from 1 year to 3 years. Source: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"What is the disqualification period in Hawaii for a SECOND major offense (committed in a CMV) within the driver's lifetime?","options":["3 years","5 years","10 years","Lifetime (life)"],"answer":3,"explanation":"A second major offense results in a lifetime CDL disqualification in Hawaii. Source: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"A Hawaii commercial driver who REFUSES to submit to the required alcohol/drug test is disqualified from operating a CMV for a minimum of:","options":["30 days","60 days","1 year","90 days"],"answer":2,"explanation":"Refusing the required test under the implied-consent law is treated as a major offense, carrying the same minimum 1-year CDL disqualification as a first DUI (3 years if placarded HazMat). Source: HRS 286-240 and HRS 291E-11; Hawaii CDL Manual.","handbook":"","hbref":""},{"q":"Which of the following is a MAJOR offense (not merely a serious traffic violation) for a Hawaii CDL holder?","options":["Following another vehicle too closely","Speeding 15 mph or more over the limit","Using a CMV to commit a felony","An improper or erratic lane change"],"answer":2,"explanation":"Using a CMV in the commission of a felony is a major offense. Following too closely, excessive speeding, and improper lane changes are serious traffic violations, not major offenses. Source: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Conviction of TWO serious traffic violations in a CMV, arising from separate incidents within a 3-year period, disqualifies a Hawaii CDL holder for:","options":["30 days","60 days","120 days","1 year"],"answer":1,"explanation":"Two serious traffic violations within 3 years result in a 60-day disqualification. Source: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"Conviction of THREE serious traffic violations in a CMV within a 3-year period disqualifies a Hawaii CDL holder for:","options":["60 days","90 days","120 days","180 days"],"answer":2,"explanation":"Three serious traffic violations within 3 years result in a 120-day disqualification, served in addition to the 60-day period for the prior two. Source: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"How much over the posted speed limit must a CMV driver be cited for in Hawaii for the offense to count as a 'serious traffic violation'?","options":["10 mph or more","15 mph or more","20 mph or more","25 mph or more"],"answer":1,"explanation":"Excessive speeding of 15 mph or more over the posted limit is a serious traffic violation. Source: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"Which of these is classified as a SERIOUS traffic violation for a Hawaii CDL holder?","options":["Having a BAC of 0.04 in a CMV","Reckless driving","Refusing a chemical test","Leaving the scene of an accident"],"answer":1,"explanation":"Reckless driving is a serious traffic violation. The other three are major offenses. Source: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51 Tables 1 and 2.","handbook":"","hbref":""},{"q":"Driving a CMV without the proper class of CDL or without the CDL in the driver's possession is treated in Hawaii as a:","options":["Major offense","Serious traffic violation","Out-of-service order violation","Railroad-crossing violation"],"answer":1,"explanation":"Driving a CMV without the proper class of license/endorsement, or without the CDL in possession, is a serious traffic violation. Source: Hawaii CDL Manual (Hawaii DOT); HRS 286-240; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"Under the rules applying to Hawaii CMV drivers, texting while driving and using a hand-held mobile phone are categorized as:","options":["Major offenses","Serious traffic violations","Equipment violations with no disqualification","Out-of-service violations"],"answer":1,"explanation":"Texting and hand-held phone use while driving a CMV are serious traffic violations; two in 3 years bring a 60-day disqualification and three bring 120 days. Source: Hawaii CDL Manual; 49 CFR 383.51 and 392.80/392.82 (FMCSA).","handbook":"","hbref":""},{"q":"For a Hawaii CMV driver, the maximum federal civil penalty for an individual driver who texts or uses a hand-held phone while driving is approximately:","options":["$500","$1,000","$2,750","$11,000"],"answer":2,"explanation":"A driver may be fined up to $2,750 (inflation-adjusted) for texting or hand-held phone use in a CMV; employers who allow it face up to $11,000. Source: FMCSA 49 CFR 392.80/392.82 and 383.51, applicable in Hawaii.","handbook":"","hbref":""},{"q":"A Hawaii CDL holder's FIRST conviction for failing to obey a railroad-highway grade crossing law in a CMV results in a disqualification of:","options":["60 days","120 days","1 year","30 days"],"answer":0,"explanation":"A first railroad-highway grade crossing violation carries a minimum 60-day disqualification. Source: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"A SECOND railroad-highway grade crossing violation within a 3-year period disqualifies a Hawaii CDL holder for at least:","options":["60 days","120 days","1 year","180 days"],"answer":1,"explanation":"A second grade-crossing violation within 3 years carries a minimum 120-day disqualification. Source: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"A THIRD railroad-highway grade crossing violation within a 3-year period results in a disqualification of at least:","options":["120 days","180 days","1 year","3 years"],"answer":2,"explanation":"A third grade-crossing violation within 3 years carries a minimum 1-year disqualification. Source: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"A Hawaii CDL holder's FIRST conviction for violating a driver or vehicle out-of-service (OOS) order results in a disqualification of:","options":["At least 30 days","At least 90 days","At least 180 days (up to 1 year)","At least 2 years"],"answer":2,"explanation":"A first out-of-service order violation carries a disqualification of 180 days up to 1 year (180 days to 2 years if transporting HazMat or passengers). Source: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51 Table 4.","handbook":"","hbref":""},{"q":"A SECOND out-of-service order violation in a CMV within a 10-year period disqualifies a Hawaii CDL holder for:","options":["180 days to 1 year","2 to 5 years","1 to 3 years","Lifetime"],"answer":1,"explanation":"A second OOS-order violation within 10 years carries a 2-to-5-year disqualification (3 to 5 years for HazMat/passenger). Source: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 4.","handbook":"","hbref":""},{"q":"When a Hawaii disqualification period is imposed on top of a previously imposed period (for example, a third serious violation following the prior two), the new period is:","options":["Served concurrently with the prior period","Reduced by half","Added to (served consecutively with) the prior period","Waived if a hearing is requested"],"answer":2,"explanation":"Hawaii disqualification periods run consecutively: a newly imposed period is in addition to any previously imposed period of disqualification. Source: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51.","handbook":"","hbref":""},{"q":"Under Hawaii's Move Over law, when a commercial driver approaches a stopped emergency vehicle displaying flashing lights on a multi-lane road, the law requires the driver to do which of the following?","options":["Slow to a reasonable and prudent speed and, when safe, move into a non-adjacent lane away from the emergency vehicle","Maintain the posted speed but sound the horn twice while passing","Stop completely on the shoulder until the emergency vehicle's lights are turned off","Reduce speed by exactly 10 mph below the posted limit and stay in the right lane"],"answer":0,"explanation":"Hawaii's Move Over law (HRS 291C-27) requires an approaching driver to slow to a reasonable and prudent speed for conditions and, if safe, change into the adjacent lane away from the emergency vehicle (or two lanes over, leaving one lane between). Source: HRS 291C-27.","handbook":"","hbref":""},{"q":"Hawaii's Move Over law protects vehicles stopped with flashing lights. Which of the following is specifically named as a protected 'emergency vehicle' under the Hawaii statute?","options":["A taxicab waiting for a fare","A tow truck","A delivery van with hazard lights on","A passenger car changing a flat tire"],"answer":1,"explanation":"HRS 291C-27 lists tow trucks among protected emergency vehicles, along with police, fire, EMS, ocean safety, freeway service patrol, sheriff, civil defense, harbors division, and DLNR enforcement vehicles. Source: HRS 291C-27.","handbook":"","hbref":""},{"q":"When a placarded hazardous-materials vehicle or a bus carrying passengers must stop at a railroad crossing in Hawaii, where must it stop relative to the nearest rail?","options":["Not less than 5 feet but not more than 25 feet from the nearest rail","Not less than 25 feet but not more than 75 feet from the nearest rail","Not less than 15 feet but not more than 50 feet from the nearest rail","Exactly 30 feet from the nearest rail"],"answer":2,"explanation":"Hawaii law (HRS 291C-93), mirrored in the Hawaii CDL Manual, requires the vehicle to stop within 50 feet but not less than 15 feet from the nearest rail, then listen and look both ways. Source: HRS 291C-93; Hawaii CDL Manual.","handbook":"","hbref":""},{"q":"According to Hawaii law and the Hawaii CDL Manual, which vehicle is required to stop at every railroad grade crossing even when no train is in sight?","options":["An empty flatbed straight truck","Any tractor-trailer over 40 feet long","A pickup truck towing a utility trailer","A vehicle carrying explosive substances or flammable liquids as cargo"],"answer":3,"explanation":"HRS 291C-93 requires vehicles carrying passengers for hire, school buses carrying children, and vehicles carrying explosive substances or flammable liquids as cargo to stop. An empty or general-freight truck is not required to stop unless placarded. Source: HRS 291C-93; Hawaii CDL Manual.","handbook":"","hbref":""},{"q":"When a Hawaii CDL driver must stop at a railroad crossing and then proceed across the tracks, what does the law require regarding gears?","options":["Downshift to the lowest gear once the front wheels are on the first rail","Cross in a gear that needs no gear change, and do not shift gears while on the tracks","Shift to neutral and coast across the tracks","Use the highest gear possible to clear the tracks quickly"],"answer":1,"explanation":"HRS 291C-93 requires the driver to cross in a gear that will not require changing gears, and the driver must not shift gears while crossing the tracks. Source: HRS 291C-93; Hawaii CDL Manual.","handbook":"","hbref":""},{"q":"Under Hawaii law, a bus or placarded vehicle that normally must stop at a railroad crossing is NOT required to stop in which situation?","options":["When the crossing has only two tracks","When the driver can see at least 400 feet down the track","When a police officer or a traffic-control signal directs traffic to proceed","When the vehicle is running behind schedule"],"answer":2,"explanation":"HRS 291C-93 exempts the mandatory stop where a police officer or a functioning traffic-control signal directs traffic to proceed; it also does not apply at street-railway grade crossings within a business or residence district. Source: HRS 291C-93.","handbook":"","hbref":""},{"q":"Hawaii's school-bus passing law applies when a stopped bus has its visual signals activated in what setting?","options":["Only in a marked school zone","Only on roads posted at 25 mph or less","Anywhere a bus stops, including limited-access freeways","In a residential area"],"answer":3,"explanation":"HRS 291C-95 keys the stopping requirement to a school bus stopped on a highway or road in a residential area with its visual signals actuated. Source: HRS 291C-95.","handbook":"","hbref":""},{"q":"When Hawaii's school-bus law requires you to stop for a bus loading or unloading children, how far from the bus must you stop?","options":["Not less than 20 feet from the school bus","Not less than 10 feet from the school bus","Not less than 30 feet from the school bus","Not less than 50 feet from the school bus"],"answer":0,"explanation":"HRS 291C-95 requires drivers in the bus's lane and adjacent lanes to stop not less than 20 feet from the school bus and remain stopped until it resumes motion and the signals are off. Many states simply say 'stop'; Hawaii specifies 20 feet. Source: HRS 291C-95.","handbook":"","hbref":""},{"q":"On an undivided two-lane residential road in Hawaii, a school bus stops with red lights flashing and its stop arm out. Who must stop?","options":["Only traffic behind the bus must stop","Only traffic in the same lane as the bus must stop","Traffic in both directions must stop","No one must stop because there is no median"],"answer":2,"explanation":"On an undivided roadway, HRS 291C-95 applies to vehicles in the bus's lane and all adjacent lanes regardless of direction, so traffic both behind and oncoming must stop at least 20 feet away. Source: HRS 291C-95.","handbook":"","hbref":""},{"q":"Under Hawaii's school-bus law, when does the divided-roadway exception let oncoming traffic continue WITHOUT stopping for a stopped bus?","options":["Whenever the road has two or more lanes in each direction","Whenever the road has a painted center line","Only when a crossing guard waves traffic through","When the bus and the vehicle are on different roadways separated by an intervening space, physical barrier, or clearly indicated dividing section"],"answer":3,"explanation":"HRS 291C-95 says the stop requirement does not apply when bus and vehicle are on different roadways; where a residential road is divided by an intervening space, physical barrier, or clearly indicated dividing section, only drivers on the same side as the bus must stop. Source: HRS 291C-95.","handbook":"","hbref":""},{"q":"A school bus in Hawaii signals a stop with its alternately flashing red lamps. How far away must those signal lamps be plainly visible under the law?","options":["200 feet in normal sunlight","500 feet in normal sunlight","1,000 feet in normal sunlight","300 feet in normal sunlight"],"answer":1,"explanation":"HRS 291C-95 describes the bus's four red signal lamps as flashing alternately and being plainly visible at a distance of 500 feet in normal sunlight. Source: HRS 291C-95.","handbook":"","hbref":""},{"q":"Hawaii's 2024 left-lane restriction for heavy commercial vehicles applies at what vehicle weight?","options":["10,000 pounds or more","5,000 pounds or more","26,001 pounds or more","80,000 pounds or more"],"answer":0,"explanation":"HRS 291C-55 (effective January 1, 2024) bars a commercial vehicle weighing 10,000 pounds or more from the far-left lane where there are three or more lanes in the same direction, unless keeping pace, passing, or turning/exiting left. Source: HRS 291C-55.","handbook":"","hbref":""},{"q":"Hawaii's heavy-vehicle left-lane prohibition (effective 2024) applies on roadways with how many lanes in the same direction?","options":["Two or more lanes in the same direction","Four or more lanes in the same direction","Any multi-lane road regardless of lane count","Three or more lanes in the same direction"],"answer":3,"explanation":"HRS 291C-55 applies only where a roadway has three or more lanes for traffic moving in the same direction; there, a commercial vehicle of 10,000 lbs or more may not use the far-left lane except to keep pace, pass, or turn/exit left. Source: HRS 291C-55.","handbook":"","hbref":""},{"q":"Under Hawaii's left-lane law for heavy commercial vehicles, which use of the far-left lane is still permitted?","options":["Cruising in the left lane to keep a steady speed on a long downgrade","Overtaking and passing another vehicle going the same direction","Staying left to avoid frequent merging traffic on the right","Using the left lane any time traffic is light"],"answer":1,"explanation":"HRS 291C-55 allows a heavy commercial vehicle in the far-left lane only when keeping pace with existing traffic flow, overtaking and passing, or preparing to turn left or exit. Source: HRS 291C-55.","handbook":"","hbref":""},{"q":"On a Hawaii multi-lane highway, a commercial vehicle that is moving slower than the normal speed of traffic should generally travel in which lane?","options":["The center lane to balance traffic flow","The far-left lane to stay out of merging traffic","The right-hand lane available, or as close as practicable to the right edge of the roadway","Any lane, as long as turn signals are used"],"answer":2,"explanation":"HRS 291C-41 requires a vehicle traveling slower than normal traffic speed to keep right—in the right-hand lane or as close as practicable to the right edge—except when passing or preparing to turn left. Source: HRS 291C-41.","handbook":"","hbref":""},{"q":"How is the maximum speed limit for a stretch of Hawaii highway legally established?","options":["By county ordinance or by official signs placed by the director of transportation","By a single fixed statewide maximum of 70 mph for all highways","By the federal government for all interstate routes only","By each individual police district's discretion"],"answer":0,"explanation":"Hawaii has no single statutory statewide maximum; under HRS 291C-102 the maximum (and minimum) speed limit is set by county ordinance or by official signs placed by the director of transportation, and drivers must obey the posted limit. Source: HRS 291C-102.","handbook":"","hbref":""},{"q":"What is the basic speed rule a Hawaii CDL driver must follow regardless of the posted limit?","options":["Always drive at least at the posted limit to keep traffic moving","Match the speed of the slowest vehicle on the road at all times","Drive 5 mph under the posted limit whenever carrying cargo","Never drive faster than is reasonable and prudent for actual and potential conditions"],"answer":3,"explanation":"HRS 291C-101 (the basic rule) prohibits driving faster than is reasonable and prudent given actual and potential hazards and conditions; a CMV may need to go below the posted limit in rain, fog, or heavy traffic. Source: HRS 291C-101.","handbook":"","hbref":""},{"q":"After a Hawaii CDL driver stops a truck on a two-lane, two-way road, where must the three reflective warning triangles be placed?","options":["All three placed in a row 50 feet behind the vehicle","Within 10 feet of the rear, 200 feet behind, and 200 feet ahead of the vehicle","Within 10 feet of the rear, about 100 feet behind, and about 100 feet ahead of the vehicle","One at the front bumper and two on the shoulder beside the cab"],"answer":2,"explanation":"The Hawaii CDL Manual (following 49 CFR 392.22) directs, on a two-way road, placing one triangle within 10 feet of the rear on the traffic side, one about 100 feet to the rear, and one about 100 feet to the front. Source: Hawaii CDL Manual.","handbook":"","hbref":""},{"q":"When a Hawaii CDL driver stops on a one-way or divided highway, where should the warning triangles be placed?","options":["Equally spaced at 50, 100, and 150 feet ahead of the vehicle","About 10 feet, 100 feet, and 200 feet toward the approaching traffic behind the vehicle","One 10 feet behind and two 500 feet behind on the shoulder","All three within 25 feet of the rear of the vehicle"],"answer":1,"explanation":"The Hawaii CDL Manual directs that on a one-way or divided highway the triangles go toward the approaching traffic at about 10 feet, 100 feet, and 200 feet from the vehicle. Source: Hawaii CDL Manual.","handbook":"","hbref":""},{"q":"A Hawaii CDL driver stops on a two-lane road just beyond the crest of a hill that blocks the view of approaching traffic. What should the driver do with the rear warning triangle?","options":["Leave it at the standard 100 feet because the distances never change","Place it directly on the centerline 10 feet behind the truck only","Skip the rear triangle since the hill already hides the truck","Move the rear triangle back to the far side of the hill, up to 500 feet from the truck, to warn drivers before the obstruction"],"answer":3,"explanation":"The Hawaii CDL Manual states that if a hill, curve, or other obstruction keeps drivers from seeing the truck within 500 feet, the rear warning device should be moved back down the road—up to 500 feet—so approaching drivers get adequate warning. Source: Hawaii CDL Manual.","handbook":"","hbref":""},{"q":"In Hawaii, where does a CDL applicant actually go to apply for and obtain a commercial driver's license?","options":["At a regional FMCSA field office","At one of the county driver licensing offices (e.g., Honolulu Customer Services, Maui/Kauai Finance, Hawaii County VRLD)","By mailing the application to the Hawaii DOT headquarters in Honolulu","At any U.S. Postal Service location statewide"],"answer":1,"explanation":"Hawaii CDLs are issued through the four county driver licensing offices, operating under State of Hawaii DOT Motor Vehicle Safety Office (MVSO) oversight. Source: Hawaii DOT MVSO 'How to Apply for a CDL' notice and county CDL pages (Honolulu CSD, Maui/Kauai Finance, Hawaii County VRLD).","handbook":"","hbref":""},{"q":"How many distinct self-certification categories of commercial operation must a Hawaii CDL applicant choose from when self-certifying their type of driving?","options":["Two","Four","Three","Six"],"answer":1,"explanation":"Hawaii applicants self-certify to one of four categories: Non-excepted interstate, Excepted interstate, Non-excepted intrastate, or Excepted intrastate. Source: Hawaii DOT MVSO CDL Medical Certification Requirements FAQ (Rev. 5/19/2025).","handbook":"","hbref":""},{"q":"Which of the four Hawaii self-certification categories does NOT require submitting a Medical Examiner's Certificate (Form MCSA-5876)?","options":["Excepted interstate","Non-excepted interstate","Non-excepted intrastate","All four categories require the MEC"],"answer":0,"explanation":"Per the Hawaii MVSO FAQ, drivers self-certifying as 'Excepted interstate' (or excepted intrastate) are not required to submit an MEC; only Non-excepted interstate and Non-excepted intrastate drivers must. Source: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025).","handbook":"","hbref":""},{"q":"Beginning May 19, 2025, how must a Hawaii Non-excepted CDL driver's Medical Examiner's Certificate (MCSA-5876) be submitted?","options":["As a physical paper copy dropped off at the county CDL office","Uploaded by the driver to the Hawaii DOT MVSO website portal","Mailed by the driver's employer to FMCSA","Directly to the FMCSA National Registry database through the certified medical examiner"],"answer":3,"explanation":"As of May 19, 2025, HDOT and county CDL offices no longer accept physical MEC copies; the certified medical examiner submits the MEC directly to the FMCSA National Registry, which transmits the data to Hawaii's driver license system. Source: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025).","handbook":"","hbref":""},{"q":"Which three parts make up the Hawaii CDL skills test, all of which must be passed at the same appointment?","options":["Air brakes, written hazmat, and on-road driving","Pre-trip inspection, vision screening, and general knowledge test","Pre-trip inspection, basic vehicle control, and on-road driving","Backing, coupling/uncoupling, and a written endorsement exam"],"answer":2,"explanation":"The Hawaii CDL skills test has three parts: pre-trip inspection, basic vehicle control, and the on-road driving test, all passed at one appointment. Source: Hawaii DOT MVSO 'How to Apply for a CDL' notice and Honolulu CSD CDL office page.","handbook":"","hbref":""},{"q":"How long is a Hawaii CDL instruction (commercial learner) permit valid?","options":["Six months","One year","Two years","180 days"],"answer":1,"explanation":"Hawaii's CDL instruction permit is valid for one year and lets the holder practice driving under supervision. Source: Hawaii DOT MVSO 'How to Apply for a CDL' notice.","handbook":"","hbref":""},{"q":"After a Hawaii CLP is issued, how long must the holder wait before they may take the CDL skills test?","options":["30 days","7 days","10 days","14 days"],"answer":3,"explanation":"Federal rule applied in Hawaii requires holding the CLP at least 14 days before the skills test; Honolulu CSD notes skills-test appointments can be made 14 days after the permit is issued. Source: Honolulu CSD CDL office page; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"What training must a Hawaii Class A/B CDL applicant complete BEFORE taking the CDL skills test (effective Feb. 7, 2022)?","options":["A state-run defensive driving course","A 40-hour Hawaii DOT classroom safety seminar","An employer-only on-the-job apprenticeship","FMCSA-registered Entry-Level Driver Training (ELDT)"],"answer":3,"explanation":"Since Feb. 7, 2022, applicants for an initial Class A/B CDL (and certain endorsements) must complete FMCSA Entry-Level Driver Training with a provider on the FMCSA Training Provider Registry before testing. Source: FMCSA ELDT rule as applied by Honolulu CSD CDL office page.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a full (unrestricted) Hawaii CDL?","options":["18","19","25","21"],"answer":3,"explanation":"Hawaii requires an applicant to be age 21 for a full CDL (a CDL permit can be obtained at 18). Source: Hawaii DOT MVSO 'How to Apply for a CDL' notice and Honolulu CSD CDL office page.","handbook":"","hbref":""},{"q":"What is the minimum vision standard a Hawaii CDL applicant must meet on the vision test?","options":["20/40 in each eye (corrected acceptable)","20/20 in each eye, uncorrected only","20/50 in the better eye","20/30 combined with both eyes"],"answer":0,"explanation":"Hawaii requires a minimum of 20/40 in each eye, with corrective lenses permitted, for the CDL vision test. Source: Honolulu CSD CDL office page; Hawaii DOT MVSO.","handbook":"","hbref":""},{"q":"Which of these is part of the required documentation when applying for a Hawaii CDL?","options":["A notarized letter from a current trucking employer","A valid basic (non-commercial) Hawaii driver's license plus proof of identity, SSN, and residence","A passport that is the only acceptable proof of identity","Three years of certified tax returns"],"answer":1,"explanation":"Hawaii CDL applicants must present a valid Hawaii driver's license and prove identity/age (e.g., birth certificate), Social Security number, and residence. Source: Hawaii DOT MVSO 'How to Apply for a CDL' notice and Honolulu CSD CDL office page.","handbook":"","hbref":""},{"q":"If a Hawaii driver operates in BOTH excepted and non-excepted interstate commerce, which status must they self-certify as?","options":["Non-excepted interstate","Excepted interstate","Excepted intrastate","Either one, the driver may pick freely"],"answer":0,"explanation":"Hawaii MVSO requires a driver operating in both types to choose 'Non-excepted interstate' so they remain qualified for both, which also requires submitting an MEC. Source: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025).","handbook":"","hbref":""},{"q":"During the transition to electronic MEC submission, for how long does Hawaii MVSO recommend a CDL driver carry a copy of their Medical Examiner's Certificate after it is submitted to the medical examiner?","options":["No longer than 30 days from submission","No longer than 60 days from submission","No longer than 15 days from submission","Exactly one year"],"answer":2,"explanation":"Hawaii MVSO recommends carrying the MEC copy for no longer than 15 days from when it was submitted to the medical examiner, to cover potential electronic-update delays. Source: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025).","handbook":"","hbref":""},{"q":"A Hawaii CDL holder's medical certificate expires and they do NOT submit a new one. On what day are all CDL privileges removed, requiring an in-person trip to a CDL office?","options":["Day 54","Day 30","Day 90","Day 15"],"answer":0,"explanation":"Per Hawaii MVSO, if the MEC is updated within 53 days no in-person appearance or reinstatement fee is needed; on day 54 all CDL privileges are removed and the driver must visit a CDL office to reinstate. Source: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025).","handbook":"","hbref":""},{"q":"What happens to a Hawaii driver's eligibility the moment their DOT medical certificate expires?","options":["They are immediately not eligible to drive a commercial motor vehicle","They keep full CDL privileges for a 90-day automatic grace period","Nothing changes until the next CDL renewal date","They may continue driving intrastate only without any medical card"],"answer":0,"explanation":"Hawaii MVSO states that the moment the medical certificate expires, the driver is not eligible to operate a CMV; MVSO then mails notice that the driver is no longer physically qualified. Source: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025).","handbook":"","hbref":""},{"q":"In Hawaii, how far in advance of expiration may a CDL holder typically renew their commercial driver's license?","options":["Only on or after the exact expiration date","Up to 30 days before the expiration date","Up to 6 months before the expiration date","Up to 2 years before the expiration date"],"answer":2,"explanation":"Hawaii county offices (e.g., Maui) allow CDL renewal within six (6) months prior to the expiration date. Source: Maui County 'Renewal of Commercial Drivers License' page.","handbook":"","hbref":""},{"q":"How often must a Hawaii CDL holder renew a Hazardous Materials (HazMat) endorsement, regardless of the base license cycle?","options":["Every 8 years with no background check","Every 2 years with a new road test","Every 5 years, including a TSA security threat assessment","Only once, it never expires after first issuance"],"answer":2,"explanation":"A HazMat endorsement must be renewed every 5 years and requires passing the HazMat knowledge test plus a TSA security threat assessment (fingerprint-based background check). Source: Maui County CDL renewal page; TSA HazMat Endorsement program; 49 CFR Part 1572.","handbook":"","hbref":""},{"q":"Hawaii drivers who hold a Class 3 or Class 4 driver's license and operate a CMV have what medical-certificate obligation?","options":["They must submit the MEC to the FMCSA National Registry like Class A holders","They do not submit the MEC to a medical examiner but must carry a copy when operating a CMV","They are fully exempt and need no medical certificate at all","They must mail a paper MEC to MVSO every year"],"answer":1,"explanation":"Hawaii MVSO states Class 3/4 license holders operating a CMV do not submit the MEC to their medical examiner but are still required to carry a copy of the MEC when operating a CMV. Source: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025).","handbook":"","hbref":""},{"q":"Which Hawaii agency is responsible for oversight of the CDL medical-certification process and to which a self-certification is directed?","options":["The Hawaii State Department of Health","The Honolulu Police Department Traffic Division","The Hawaii DOT Motor Vehicle Safety Office (MVSO)","The U.S. Department of Labor"],"answer":2,"explanation":"The Hawaii DOT Motor Vehicle Safety Office (MVSO) administers CDL medical certification and self-certification, working with the county CDL offices and FMCSA. Source: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025).","handbook":"","hbref":""},{"q":"Under Hawaii's updated rules following 49 CFR 391.46, what is now true for a driver with properly controlled insulin-treated diabetes mellitus (ITDM) seeking medical certification?","options":["The driver must still apply to MVSO for a separate intrastate ITDM waiver before any certification","The driver is permanently disqualified from holding a CDL in Hawaii","The driver only needs a note from any pharmacist, not a medical examiner","A certified medical examiner can issue the MEC; a separate MVSO intrastate ITDM waiver application is no longer required"],"answer":3,"explanation":"Per 49 CFR 391.46 as adopted by Hawaii MVSO, a certified medical examiner may issue the MEC for a stable, properly controlled ITDM driver (using the MCSA-5870 assessment); a separate MVSO intrastate ITDM waiver application is no longer required. Source: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025).","handbook":"","hbref":""}],"ru":{"0":{"q":"Согласно законодательству Гавайев, какова максимальная общая ШИРИНА (включая груз) транспортного средства, которое может двигаться по дорогам общего пользования без разрешения на негабаритный груз?","options":["8 футов","8 футов 6 дюймов","9 футов","10 футов"],"explanation":"HRS §291-34 запрещает эксплуатацию автомобиля, общая ширина которого, включая груз, превышает девять футов, на любой дороге, улице или шоссе общего пользования в штате без разрешения. (Hawaii Revised Statutes §291-34; Hawaii CDL Manual.)"},"1":{"q":"Какова максимальная общая ВЫСОТА (включая груз), разрешённая для транспортного средства на дорогах Гавайев без разрешения?","options":["13 футов","13 футов 6 дюймов","14 футов","15 футов"],"explanation":"HRS §291-34 устанавливает максимальную высоту транспортного средства, включая груз, в четырнадцать футов. Даже в пределах этого ограничения транспортное средство не может проезжать под мостом или сооружением, если оно превышает указанную для этого сооружения высоту проезда. (Hawaii Revised Statutes §291-34.)"},"2":{"q":"На дорогах Гавайев какова максимальная общая ДЛИНА одиночного автомобиля (несоставного транспортного средства), включая груз, без разрешения?","options":["40 футов","45 футов","53 фута","60 футов"],"explanation":"HRS §291-34 ограничивает одиночный автомобиль (не состав) сорока пятью футами общей длины, включая груз. (Hawaii Revised Statutes §291-34.)"},"3":{"q":"Согласно HRS §291-34, какова максимальная общая длина СОСТАВА из седельного тягача и полуприцепа, включая груз, разрешённая без разрешения на Гавайях?","options":["60 футов","65 футов","70 футов","75 футов"],"explanation":"HRS §291-34 ограничивает состав из седельного тягача и полуприцепа шестьюдесятью пятью футами общей длины, включая груз. (Hawaii Revised Statutes §291-34.)"},"4":{"q":"На Гавайях максимальная полная нагрузка, передаваемая на дорогу любой ОДИНОЧНОЙ ОСЬЮ, не может превышать:","options":["18,000 фунтов","20,000 фунтов","22,500 фунтов","34,000 фунтов"],"explanation":"HRS §291-35 ограничивает полную нагрузку на любую одиночную ось двадцатью тысячами фунтов. (Hawaii Revised Statutes §291-35.)"},"5":{"q":"«Сдвоенная ось» на Гавайях (две последовательные оси, расположенные на расстоянии более 40 дюймов, но не более 96 дюймов друг от друга) может нести максимальную полную нагрузку:","options":["32,000 фунтов","34,000 фунтов","36,000 фунтов","40,000 фунтов"],"explanation":"HRS §291-35 ограничивает сдвоенную ось (оси, расположенные на расстоянии более 40 дюймов, но не более 96 дюймов) тридцатью четырьмя тысячами фунтов. (Hawaii Revised Statutes §291-35.)"},"6":{"q":"Согласно закону Гавайев о весе, полная нагрузка, передаваемая на дорогу любым одним КОЛЕСОМ, будь то с одинарной или двойной установкой, не может превышать:","options":["8,000 фунтов","10,000 фунтов","12,000 фунтов","13,500 фунтов"],"explanation":"HRS §291-35 ограничивает полную нагрузку на любое одно колесо (с одинарной или двойной установкой) десятью тысячами фунтов. (Hawaii Revised Statutes §291-35.)"},"7":{"q":"Каков максимальный общий ПОЛНЫЙ ВЕС, разрешённый для транспортного средства или состава на дорогах Гавайев без разрешения на перевес?","options":["73,280 фунтов","80,000 фунтов","88,000 фунтов","105,500 фунтов"],"explanation":"HRS §291-35 ограничивает общий полный вес транспортного средства восемьюдесятью тысячами фунтов, что соответствует федеральному пределу. (Hawaii Revised Statutes §291-35.)"},"8":{"q":"Два последовательных набора сдвоенных осей могут нести по 34,000 фунтов каждый на Гавайях только в том случае, если расстояние между первой и последней осями этих двух сдвоенных наборов составляет не менее:","options":["28 футов","32 фута","36 футов","40 футов"],"explanation":"HRS §291-35 разрешает двум последовательным наборам сдвоенных осей нести по 34,000 фунтов каждый только тогда, когда общее расстояние между первой и последней осями составляет тридцать шесть футов или более, а суммарный полный вес остаётся на уровне или ниже 80,000 фунтов. (Hawaii Revised Statutes §291-35.)"},"9":{"q":"Формула в HRS §291-35, которая связывает допустимый полный вес группы осей с расстоянием между ними и их количеством, основана на каком федеральном стандарте?","options":["Федеральная мостовая формула (Bridge Gross Weight Formula)","Правило расстояния между осями CARB","Индекс дорожной нагрузки AASHTO","Таблица режима труда и отдыха FMCSA"],"explanation":"Положения о весе группы осей в HRS §291-35 включают Федеральную мостовую формулу (Federal Bridge Formula), которая связывает допустимый вес с количеством осей и расстоянием между крайними осями группы. (Hawaii Revised Statutes §291-35; 23 U.S.C. §127, применяется как правило Гавайев.)"},"10":{"q":"Кто имеет полномочия выдавать письменное разрешение на перемещение негабаритного или перевесного груза по ГОСУДАРСТВЕННОЙ автодороге на Гавайях?","options":["Начальник полиции округа","Директор Департамента транспорта (Director of Transportation)","Комиссия по коммунальным услугам (Public Utilities Commission)","Начальник порта Гонолулу (Honolulu Harbor Master)"],"explanation":"Согласно HRS §291-36, Director of Transportation выдаёт разрешения на негабаритные/перевесные грузы для государственных автодорог, тогда как окружной инженер выдаёт их для окружных дорог и улиц. (Hawaii Revised Statutes §291-36; HIDOT Highways Division.)"},"11":{"q":"Для перемещений по ОКРУЖНЫМ дорогам и улицам на Гавайях кто выдаёт разрешение на негабаритный/перевесный груз?","options":["Director of Transportation","Окружной инженер (county engineer)","Канцелярия мэра","Департамент общественной безопасности штата (Department of Public Safety)"],"explanation":"HRS §291-36 возлагает полномочия по выдаче разрешений для окружных дорог и улиц на окружного инженера (Director of Transportation занимается государственными автодорогами). (Hawaii Revised Statutes §291-36.)"},"12":{"q":"Каким образом должна подаваться заявка на гавайское разрешение на негабаритный/перевесный груз?","options":["Устно по телефону в районный офис","Письменно на бланках, предоставляемых Highways Division","Только через лицензированного таможенного брокера","Путём размещения объявления на весовой станции"],"explanation":"HRS §291-36 требует письменной заявки, а HIDOT Highways Division требует, чтобы она подавалась на предоставляемых им бланках, включая схемы расположения колёс, размеры и распределение нагрузки. (Hawaii Revised Statutes §291-36; процедуры выдачи разрешений HIDOT на негабаритные/перевесные грузы.)"},"13":{"q":"Помимо заявки, что Hawaii Highways Division требует иметь в деле у заявителя на разрешение на негабаритный/перевесный груз?","options":["Сертификат страхования (certificate of insurance)","Лицензию на коммерческое рыболовство","Нотариально заверенную портовую гарантию","Федеральную карту кабины IRP (IRP cab card)"],"explanation":"HIDOT Highways Division требует наличия сертификата страхования (certificate of insurance) в деле до выдачи разрешения на негабаритный/перевесный груз. (Процедуры выдачи разрешений HIDOT на негабаритные/перевесные транспортные средства на государственных автодорогах.)"},"14":{"q":"Согласно тарифной сетке Гавайев на разрешения, плата за РАЗОВОЕ разрешение для груза менее чем в 1.35 раза превышающего допустимый вес или шириной менее 14 футов составляет:","options":["$5","$10","$25","$50"],"explanation":"Согласно HRS §291-36, разовое разрешение для груза менее чем в 1.35 раза превышающего допустимую нагрузку или шириной менее 14 футов стоит $5 (разрешение на непрерывную поездку в этом диапазоне стоит $10). (Hawaii Revised Statutes §291-36; HIDOT.)"},"15":{"q":"Согласно тарифной сетке Гавайев на разрешения, плата за разрешение на ПЕРЕВЕС для груза, ПРЕВЫШАЮЩЕГО допустимую нагрузку в 1.35 раза, составляет:","options":["$5","$10","$25","$100"],"explanation":"HRS §291-36 устанавливает плату в $25 за разрешение на перевес, когда груз превышает допустимую нагрузку в 1.35 раза; те же $25 применяются к разрешению на негабарит шириной более 14 футов. (Hawaii Revised Statutes §291-36; HIDOT.)"},"16":{"q":"Разрешение на негабаритную ШИРИНУ на Гавайях требуется (и влечёт более высокую плату в $25), как только ширина груза превышает:","options":["9 футов","10 футов","12 футов","14 футов"],"explanation":"Хотя любая ширина свыше 9 футов требует разрешения, тарифная сетка HRS §291-36 относит груз шириной более 14 футов к категории, требующей разрешения на негабарит за $25. (Hawaii Revised Statutes §291-36; тарифная сетка HIDOT на разрешения.)"},"17":{"q":"Согласно сельскохозяйственным положениям Гавайев, в каких случаях Director of Transportation может выдать разрешение, допускающее вес, превышающий ограничения HRS §291-35?","options":["Только для транспортных средств, принадлежащих штату","При перевозке собранной продукции от места её сбора или хранения к месту её переработки или использования","Только в период с полуночи до 5 часов утра","Никогда — разрешения на перевес для фермерских грузов не допускаются"],"explanation":"HRS §291-36 разрешает выдачу разрешения на превышение весовых ограничений §291-35 при перевозке продукции от места её сбора или хранения к месту её переработки или использования. (Hawaii Revised Statutes §291-36.)"},"18":{"q":"Какое сельскохозяйственное перемещение на Гавайях НЕ требует разрешения вообще согласно HRS §291-36?","options":["Любое фермерское транспортное средство, проезжающее 10 миль или менее по государственной автодороге","Транспортное средство, используемое в сельскохозяйственных операциях, которое только ПЕРЕСЕКАЕТ дорогу общего пользования в месте, одобренном Director of Transportation или окружным инженером","Любое транспортное средство, перевозящее ананасы, независимо от веса","Состав весом менее 80,000 фунтов, перевозящий кофе"],"explanation":"HRS §291-36 предусматривает, что разрешение не требуется для транспортного средства, используемого в сельскохозяйственных операциях, которое только пересекает дорогу, улицу или шоссе общего пользования в месте, одобренном Director of Transportation (государственные автодороги) или окружным инженером (окружные дороги). (Hawaii Revised Statutes §291-36.)"},"19":{"q":"Если инженерный анализ показывает, что гавайский мост может безопасно выдержать вес меньше установленного законом максимального полного веса, что может сделать ответственный орган?","options":["Закрыть мост навсегда для всех грузовиков","Установить и поддерживать знаки, ограничивающие полный вес транспортных средств, пересекающих этот мост","Поднять общештатное ограничение полного веса для компенсации","Потребовать повышение категории CDL для этого маршрута"],"explanation":"HRS §291-35 позволяет Director of Transportation (или окружному инженеру) устанавливать и поддерживать знаки, ограничивающие полный вес на конкретном мосту или сооружении, когда инженерный анализ показывает, что его несущая способность меньше установленного законом максимума; водители должны соблюдать указанное ограничение. (Hawaii Revised Statutes §291-35.)"},"20":{"q":"На Гавайях какой класс CDL требуется для управления любым составом транспортных средств с полной массой состава (GCWR) 26,001 фунт или более, когда буксируемое(ые) транспортное(ые) средство(а) имеют GVWR более 10,000 фунтов?","options":["Класс A","Класс B","Класс C","Класс D"],"explanation":"Гавайи определяют CDL класса A как любой состав транспортных средств с GCWR 26,001 фунт или более при условии, что GVWR буксируемого блока превышает 10,000 фунтов. Источник: HRS Sec. 286-239 и Honolulu Commercial Driver Licensing Office. Федерального/гавайского CDL «класса D» не существует."},"21":{"q":"Согласно законодательству Гавайев, одиночное транспортное средство с полной массой (GVWR) 26,001 фунт или более (либо такое транспортное средство, буксирующее блок не более 10,000 фунтов) требует какого класса CDL?","options":["Класс A","Класс B","Класс C","Класс M"],"explanation":"Гавайи классифицируют одиночное транспортное средство с GVWR 26,001 фунт или более как коммерческое транспортное средство класса B. Источник: HRS Sec. 286-239; Honolulu CDL Office. «Класс M» — это категория для мотоциклов, а не CDL."},"22":{"q":"Водитель на Гавайях управляет транспортным средством с GVWR менее 26,001 фунта, которое рассчитано на перевозку 16 или более пассажиров (включая водителя) либо имеет таблички (placards) для опасных грузов. Какой класс CDL применяется?","options":["Класс A","Класс B","Класс C","CDL не требуется"],"explanation":"CDL класса C охватывает транспортные средства, которые не соответствуют ни классу A, ни классу B, но рассчитаны на перевозку 16+ пассажиров (включая водителя) или перевозят опасные грузы с табличками. Источник: HRS Sec. 286-239; Honolulu CDL Office."},"23":{"q":"Какой код отметки (endorsement) в гавайском CDL даёт право управлять транспортным средством, перевозящим опасные грузы, требующие табличек (placards)?","options":["Отметка N","Отметка T","Отметка H","Отметка P"],"explanation":"Отметка H (HazMat) даёт право управлять транспортным средством, перевозящим опасные грузы с табличками. Источник: Hawaii CDL Manual / Honolulu CDL Office; 49 CFR Part 383 (принято Гавайями)."},"24":{"q":"В гавайском CDL какая отметка требуется для управления двойными и тройными прицепами?","options":["Отметка T","Отметка N","Отметка S","Отметка H"],"explanation":"Отметка T даёт право управлять двойными и тройными прицепами. Источник: Hawaii CDL Manual / Honolulu CDL Office; 49 CFR 383.93."},"25":{"q":"Какую отметку требуют Гавайи для управления транспортным средством-цистерной, как правило рассчитанным на перевозку жидкостей или газов в стационарно установленной цистерне с номинальной ёмкостью более 1,000 галлонов?","options":["Отметка P","Отметка N","Отметка T","Отметка X"],"explanation":"Отметка N (Tanker) требуется для транспортных средств-цистерн; Гавайи ссылаются на цистерны ёмкостью более 1,000 галлонов. Источник: Honolulu CDL Office; 49 CFR 383.93. Код X обозначает совмещённую цистерну + HazMat, а не только цистерну."},"26":{"q":"Какую отметку должен получить владелец гавайского CDL, чтобы управлять транспортным средством, рассчитанным на перевозку 16 или более пассажиров (включая водителя)?","options":["Отметка S","Отметка N","Отметка P","Отметка T"],"explanation":"Отметка P (Passenger) требуется для перевозки 16 или более пассажиров, включая водителя. Источник: Honolulu CDL Office; 49 CFR 383.93. Отметка S предназначена именно для школьных автобусов."},"27":{"q":"Чтобы управлять школьным автобусом на Гавайях, владелец CDL должен иметь отметку S. Какая дополнительная пассажирская отметка также требуется?","options":["Отметка N","Отметка T","Отметка H","Отметка P"],"explanation":"Водитель школьного автобуса должен иметь как отметку S (School Bus), так и отметку P (Passenger). Источник: Hawaii CDL Manual; 49 CFR 383.93, принято Гавайями."},"28":{"q":"Каков минимальный возраст, необходимый для получения гавайского CDL, дающего право на межштатное (через границы штатов) коммерческое вождение?","options":["18 лет","19 лет","20 лет","21 год"],"explanation":"Межштатное коммерческое вождение требует минимального возраста 21 год. Эксплуатация только внутри штата может быть разрешена с 18 лет. Источник: Honolulu CDL Office; 49 CFR 391.11(b)."},"29":{"q":"Прежде чем подать заявление на гавайский CDL, водитель должен сначала получить какой документ, сдав требуемый теоретический экзамен(ы)?","options":["Commercial Learner Permit (CLP)","Временный CDL","Временную карту HazMat","Учебное разрешение класса C"],"explanation":"Заявители должны сначала получить Commercial Learner Permit (CLP), сдав теоретический экзамен(ы), прежде чем проходить экзамен по навыкам CDL. Источник: Honolulu CDL Office; 49 CFR 383.25."},"30":{"q":"Согласно федеральным правилам, принятым Гавайями, как долго водитель должен иметь Commercial Learner Permit, прежде чем получит право сдавать экзамен по навыкам CDL?","options":["Не менее 7 дней","Не менее 14 дней","Не менее 30 дней","Не менее 60 дней"],"explanation":"Водитель должен иметь CLP не менее 14 дней, прежде чем сдавать экзамен по навыкам; Гавайи назначают экзамен по навыкам не ранее чем через 14 дней после выдачи разрешения. Источник: Honolulu CDL Office; 49 CFR 383.25(e)."},"31":{"q":"Как долго действителен гавайский Commercial Learner Permit (CLP) до того, как его необходимо продлить?","options":["90 дней","180 дней","1 год","2 года"],"explanation":"Гавайский CLP действителен в течение 180 дней. Источник: Hawaii CDL Manual / руководство DMV; 49 CFR 383.25(c)."},"32":{"q":"Управляя транспортным средством по гавайскому Commercial Learner Permit, владелец разрешения должен:","options":["Ездить в одиночку только в светлое время суток","Находиться в сопровождении владельца CDL, сидящего рядом с ним","Иметь пассажирскую отметку до любой практики","Ездить только на частной территории"],"explanation":"Владелец CLP должен в любое время находиться в сопровождении лица, имеющего действительный CDL (соответствующего класса/отметок для практикуемой категории), сидящего на переднем сиденье. Источник: Hawaii CDL Manual; 49 CFR 383.25(a)."},"33":{"q":"Какой документ принимает гавайский офис выдачи CDL в качестве доказательства личности и законного пребывания для заявителя-гражданина США?","options":["Читательский билет","Заверенное свидетельство о рождении США","Регистрацию транспортного средства","Только счёт за коммунальные услуги"],"explanation":"Гавайи требуют заверенное свидетельство о рождении США (или иное одобренное доказательство) для установления личности и законного пребывания. Источник: список документов Honolulu CDL Office."},"34":{"q":"Сколько документов, подтверждающих место жительства, требует предъявить гавайский офис CDL от заявителя?","options":["Ни одного","Один","Два","Четыре"],"explanation":"Гавайи требуют два документа, подтверждающих место жительства, для установления проживания на Гавайях при получении CDL. Источник: контрольный список документов Honolulu CDL Office."},"35":{"q":"Какой медицинский документ должен представить заявитель на гавайский CDL для подтверждения своей физической пригодности к вождению?","options":["Действующий DOT Medical Examiner's Certificate (MCSA-5876)","Справку о стоматологическом допуске","Нотариально заверенный аффидевит о состоянии здоровья","Рецепт от лечащего врача"],"explanation":"Заявители должны представить действующий медосмотр DOT / Medical Examiner's Certificate (форма MCSA-5876). Источник: Honolulu CDL Office; 49 CFR 391.43."},"36":{"q":"Какая категория медицинской самосертификации применяется к водителю гавайского CDL, который ездит через границы штатов и подпадает под федеральное требование о медицинской справке и соответствует ему?","options":["Excepted Interstate","Non-Excepted Interstate","Excepted Intrastate","Non-Excepted Intrastate"],"explanation":"Водитель в межштатных перевозках, который должен соответствовать федеральному требованию о медицинской справке согласно Part 391, самосертифицируется как Non-Excepted Interstate. Источник: 49 CFR 383.71(b), принято Гавайями."},"37":{"q":"С 7 февраля 2022 года, прежде чем сдавать экзамен по навыкам для первого гавайского CDL класса A или B (либо первой отметки P, S или H), заявитель должен выполнить какое требование?","options":["Иметь безупречную историю вождения за 5 лет","Пройти FMCSA Entry-Level Driver Training (ELDT) у зарегистрированного провайдера","Пройти курс безопасного вождения в любой школе","Пройти двухлетнее ученичество"],"explanation":"ELDT требуется для впервые получаемых CDL класса A/B и впервые получаемых отметок P, S или H; обучение должно проводиться провайдером из FMCSA Training Provider Registry. Источник: 49 CFR Part 380 (вступило в силу 7 февраля 2022 года); Honolulu CDL Office."},"38":{"q":"Помимо сдачи теоретического экзамена по HazMat, что должен пройти заявитель на Гавайях, прежде чем будет выдана отметка H (HazMat)?","options":["Оценку угрозы безопасности TSA (security threat assessment, проверку биографии)","Дорожный экзамен на транспортном средстве-цистерне","Проверку выбросов","Курс безопасности на воде"],"explanation":"Федеральный закон требует, чтобы каждый заявитель на отметку HazMat прошёл оценку угрозы безопасности TSA (security threat assessment — проверку биографии со снятием отпечатков пальцев) до выдачи, в дополнение к теоретическому экзамену и ELDT. Источник: 49 CFR 1572 (TSA); 49 CFR 383.141; Hawaii CDL Office."},"39":{"q":"На Гавайях лицо совершает крупное дисквалифицирующее правонарушение, управляя коммерческим транспортным средством (CMV) при концентрации алкоголя в крови (BAC) не менее какого уровня?","options":["0.02","0.04","0.08","0.10"],"explanation":"Гавайи устанавливают предел содержания алкоголя для CMV на уровне 0.04 BAC, что вдвое меньше предела 0.08 для обычных водителей. Управление CMV при 0.04 или выше является крупным правонарушением. Источник: Hawaii CDL Manual (Hawaii DOT) и HRS 286-240; 49 CFR 383.51."},"40":{"q":"Согласно гавайскому закону о подразумеваемом согласии, управляя транспортным средством на дорогах штата, коммерческий водитель считается давшим согласие на что?","options":["Осмотр транспортного средства на любой весовой станции","Тест дыхания, крови или мочи на содержание алкоголя или наркотиков в случае ареста","Обыск кабины без ордера","Ежегодный экзамен на медицинскую ресертификацию"],"explanation":"Гавайский закон о подразумеваемом согласии считает любого водителя давшим согласие на тест дыхания, крови или мочи для определения концентрации алкоголя или содержания наркотиков при законном аресте. Источник: HRS 291E-11 (подразумеваемое согласие); Hawaii CDL Manual."},"41":{"q":"Владелец гавайского CDL осуждён за первое крупное правонарушение (такое как DUI на CMV), НЕ перевозя при этом опасные грузы с табличками. Минимальный срок дисквалификации составляет:","options":["60 дней","120 дней","1 год","3 года"],"explanation":"Первое крупное правонарушение влечёт минимальную дисквалификацию CDL на 1 год на Гавайях. Источник: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 1."},"42":{"q":"Если первое крупное правонарушение совершено во время управления водителем CMV, перевозящим опасные грузы, требующие табличек, срок дисквалификации увеличивается до:","options":["1 года","18 месяцев","3 лет","5 лет"],"explanation":"Первое крупное правонарушение, совершённое при перевозке опасных грузов с табличками, повышает дисквалификацию с 1 года до 3 лет. Источник: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51 Table 1."},"43":{"q":"Каков срок дисквалификации на Гавайях за ВТОРОЕ крупное правонарушение (совершённое на CMV) в течение жизни водителя?","options":["3 года","5 лет","10 лет","Пожизненно (life)"],"explanation":"Второе крупное правонарушение влечёт пожизненную дисквалификацию CDL на Гавайях. Источник: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 1."},"44":{"q":"Гавайский коммерческий водитель, который ОТКАЗЫВАЕТСЯ пройти требуемый тест на алкоголь/наркотики, дисквалифицируется от управления CMV на срок не менее:","options":["30 дней","60 дней","1 года","90 дней"],"explanation":"Отказ от требуемого теста согласно закону о подразумеваемом согласии рассматривается как крупное правонарушение, влекущее ту же минимальную дисквалификацию CDL на 1 год, что и первое DUI (3 года при перевозке HazMat с табличками). Источник: HRS 286-240 и HRS 291E-11; Hawaii CDL Manual."},"45":{"q":"Какое из следующего является КРУПНЫМ правонарушением (а не просто серьёзным нарушением ПДД) для владельца гавайского CDL?","options":["Слишком близкое следование за другим транспортным средством","Превышение скорости на 15 mph или более","Использование CMV для совершения тяжкого преступления (felony)","Неправильная или беспорядочная смена полосы движения"],"explanation":"Использование CMV при совершении тяжкого преступления (felony) является крупным правонарушением. Слишком близкое следование, чрезмерное превышение скорости и неправильная смена полосы — это серьёзные нарушения ПДД, а не крупные правонарушения. Источник: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51."},"46":{"q":"Осуждение за ДВА серьёзных нарушения ПДД на CMV, возникших в результате отдельных инцидентов в течение 3-летнего периода, дисквалифицирует владельца гавайского CDL на:","options":["30 дней","60 дней","120 дней","1 год"],"explanation":"Два серьёзных нарушения ПДД в течение 3 лет влекут дисквалификацию на 60 дней. Источник: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 2."},"47":{"q":"Осуждение за ТРИ серьёзных нарушения ПДД на CMV в течение 3-летнего периода дисквалифицирует владельца гавайского CDL на:","options":["60 дней","90 дней","120 дней","180 дней"],"explanation":"Три серьёзных нарушения ПДД в течение 3 лет влекут дисквалификацию на 120 дней, отбываемую в дополнение к 60-дневному периоду за предыдущие два. Источник: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51 Table 2."},"48":{"q":"Насколько превысить установленную скорость должен водитель CMV на Гавайях, чтобы правонарушение засчиталось как «серьёзное нарушение ПДД»?","options":["На 10 mph или более","На 15 mph или более","На 20 mph или более","На 25 mph или более"],"explanation":"Чрезмерное превышение скорости на 15 mph или более сверх установленного предела является серьёзным нарушением ПДД. Источник: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 2."},"49":{"q":"Что из перечисленного классифицируется как СЕРЬЁЗНОЕ нарушение ПДД для владельца гавайского CDL?","options":["BAC 0.04 на CMV","Безрассудное вождение (reckless driving)","Отказ от химического теста","Оставление места происшествия"],"explanation":"Безрассудное вождение (reckless driving) является серьёзным нарушением ПДД. Остальные три — крупные правонарушения. Источник: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51 Tables 1 and 2."},"50":{"q":"Управление CMV без надлежащего класса CDL или без CDL при себе на Гавайях рассматривается как:","options":["Крупное правонарушение","Серьёзное нарушение ПДД","Нарушение приказа о выводе из эксплуатации (out-of-service order)","Нарушение на железнодорожном переезде"],"explanation":"Управление CMV без надлежащего класса лицензии/отметки или без CDL при себе является серьёзным нарушением ПДД. Источник: Hawaii CDL Manual (Hawaii DOT); HRS 286-240; 49 CFR 383.51 Table 2."},"51":{"q":"Согласно правилам, применяемым к гавайским водителям CMV, отправка текстовых сообщений во время вождения и использование ручного мобильного телефона классифицируются как:","options":["Крупные правонарушения","Серьёзные нарушения ПДД","Нарушения по оборудованию без дисквалификации","Нарушения приказа о выводе из эксплуатации (out-of-service)"],"explanation":"Отправка текстовых сообщений и использование ручного телефона во время вождения CMV являются серьёзными нарушениями ПДД; два за 3 года влекут дисквалификацию на 60 дней, а три — на 120 дней. Источник: Hawaii CDL Manual; 49 CFR 383.51 и 392.80/392.82 (FMCSA)."},"52":{"q":"Для гавайского водителя CMV максимальный федеральный гражданский штраф для отдельного водителя, который отправляет текстовые сообщения или использует ручной телефон во время вождения, составляет примерно:","options":["$500","$1,000","$2,750","$11,000"],"explanation":"Водитель может быть оштрафован на сумму до $2,750 (с поправкой на инфляцию) за отправку текстовых сообщений или использование ручного телефона на CMV; работодатели, которые это допускают, подлежат штрафу до $11,000. Источник: FMCSA 49 CFR 392.80/392.82 и 383.51, применимо на Гавайях."},"53":{"q":"ПЕРВОЕ осуждение владельца гавайского CDL за несоблюдение закона о железнодорожном переезде на CMV влечёт дисквалификацию на:","options":["60 дней","120 дней","1 год","30 дней"],"explanation":"Первое нарушение на железнодорожном переезде влечёт минимальную дисквалификацию на 60 дней. Источник: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 3."},"54":{"q":"ВТОРОЕ нарушение на железнодорожном переезде в течение 3-летнего периода дисквалифицирует владельца гавайского CDL не менее чем на:","options":["60 дней","120 дней","1 год","180 дней"],"explanation":"Второе нарушение на железнодорожном переезде в течение 3 лет влечёт минимальную дисквалификацию на 120 дней. Источник: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51 Table 3."},"55":{"q":"ТРЕТЬЕ нарушение на железнодорожном переезде в течение 3-летнего периода влечёт дисквалификацию не менее чем на:","options":["120 дней","180 дней","1 год","3 года"],"explanation":"Третье нарушение на железнодорожном переезде в течение 3 лет влечёт минимальную дисквалификацию на 1 год. Источник: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 3."},"56":{"q":"ПЕРВОЕ осуждение владельца гавайского CDL за нарушение приказа о выводе из эксплуатации (out-of-service, OOS) водителя или транспортного средства влечёт дисквалификацию на:","options":["Не менее 30 дней","Не менее 90 дней","Не менее 180 дней (до 1 года)","Не менее 2 лет"],"explanation":"Первое нарушение приказа о выводе из эксплуатации влечёт дисквалификацию от 180 дней до 1 года (от 180 дней до 2 лет при перевозке HazMat или пассажиров). Источник: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51 Table 4."},"57":{"q":"ВТОРОЕ нарушение приказа о выводе из эксплуатации на CMV в течение 10-летнего периода дисквалифицирует владельца гавайского CDL на:","options":["От 180 дней до 1 года","От 2 до 5 лет","От 1 до 3 лет","Пожизненно"],"explanation":"Второе нарушение приказа OOS в течение 10 лет влечёт дисквалификацию на срок от 2 до 5 лет (от 3 до 5 лет при перевозке HazMat/пассажиров). Источник: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 4."},"58":{"q":"Когда гавайский срок дисквалификации налагается поверх ранее наложенного срока (например, третье серьёзное нарушение после двух предыдущих), новый срок:","options":["Отбывается одновременно с предыдущим сроком","Сокращается вдвое","Прибавляется к предыдущему сроку (отбывается последовательно с ним)","Аннулируется, если запрошено слушание"],"explanation":"Гавайские сроки дисквалификации отбываются последовательно: вновь наложенный срок добавляется к любому ранее наложенному сроку дисквалификации. Источник: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51."},"59":{"q":"Согласно закону Гавайев «Move Over» (уступи дорогу), когда коммерческий водитель приближается к остановившемуся аварийному транспортному средству с включёнными проблесковыми маячками на многополосной дороге, закон требует от водителя выполнить одно из следующих действий?","options":["Снизить скорость до разумной и безопасной и, когда это безопасно, перестроиться в неприлегающую полосу, отдалённую от аварийного транспортного средства","Сохранять установленную скорость, но дважды подать звуковой сигнал при проезде","Полностью остановиться на обочине, пока маячки аварийного транспортного средства не будут выключены","Снизить скорость ровно на 10 mph ниже установленного ограничения и оставаться в правой полосе"],"explanation":"Закон Гавайев «Move Over» (HRS 291C-27) требует от приближающегося водителя снизить скорость до разумной и безопасной с учётом условий и, если это безопасно, перестроиться в прилегающую полосу, отдалённую от аварийного транспортного средства (или на две полосы в сторону, оставив одну полосу между ними). Источник: HRS 291C-27."},"60":{"q":"Закон Гавайев «Move Over» защищает транспортные средства, остановившиеся с включёнными проблесковыми маячками. Какое из перечисленных средств прямо названо защищаемым «аварийным транспортным средством» в законе Гавайев?","options":["Такси, ожидающее пассажира","Эвакуатор (буксировочный грузовик)","Фургон доставки с включённой аварийной сигнализацией","Легковой автомобиль, у которого меняют спущенное колесо"],"explanation":"HRS 291C-27 относит эвакуаторы (буксировочные грузовики) к защищаемым аварийным транспортным средствам наряду с полицией, пожарными, EMS, службой безопасности на воде (ocean safety), патрулём обслуживания автомагистралей, шерифом, гражданской обороной, отделом гаваней (harbors division) и транспортными средствами правоприменения DLNR. Источник: HRS 291C-27."},"61":{"q":"Когда транспортное средство с табличками опасных грузов (placarded) или автобус с пассажирами должны остановиться на железнодорожном переезде на Гавайях, на каком расстоянии от ближайшего рельса оно должно остановиться?","options":["Не менее 5 футов, но не более 25 футов от ближайшего рельса","Не менее 25 футов, но не более 75 футов от ближайшего рельса","Не менее 15 футов, но не более 50 футов от ближайшего рельса","Ровно 30 футов от ближайшего рельса"],"explanation":"Закон Гавайев (HRS 291C-93), отражённый в Руководстве CDL Гавайев, требует, чтобы транспортное средство остановилось в пределах 50 футов, но не ближе 15 футов от ближайшего рельса, а затем прислушалось и осмотрелось в обе стороны. Источник: HRS 291C-93; Hawaii CDL Manual."},"62":{"q":"Согласно закону Гавайев и Руководству CDL Гавайев, какое транспортное средство обязано останавливаться на каждом железнодорожном переезде, даже когда поезда не видно?","options":["Пустой бортовой одиночный грузовик (straight truck)","Любой тягач с прицепом длиной более 40 футов","Пикап, буксирующий хозяйственный прицеп","Транспортное средство, перевозящее взрывчатые вещества или легковоспламеняющиеся жидкости в качестве груза"],"explanation":"HRS 291C-93 требует остановки от транспортных средств, перевозящих пассажиров за плату, школьных автобусов с детьми и транспортных средств, перевозящих взрывчатые вещества или легковоспламеняющиеся жидкости в качестве груза. Пустой грузовик или грузовик с обычным грузом не обязан останавливаться, если на нём нет табличек опасных грузов (placarded). Источник: HRS 291C-93; Hawaii CDL Manual."},"63":{"q":"Когда водитель CDL Гавайев должен остановиться на железнодорожном переезде, а затем продолжить движение через пути, что требует закон относительно передач?","options":["Переключиться на низшую передачу, как только передние колёса окажутся на первом рельсе","Пересекать на передаче, не требующей переключения, и не переключать передачи, находясь на путях","Включить нейтраль и проехать через пути накатом","Использовать максимально высокую передачу, чтобы быстрее освободить пути"],"explanation":"HRS 291C-93 требует, чтобы водитель пересекал пути на передаче, которая не потребует переключения, и водитель не должен переключать передачи во время пересечения путей. Источник: HRS 291C-93; Hawaii CDL Manual."},"64":{"q":"Согласно закону Гавайев, автобус или транспортное средство с табличками опасных грузов, которое обычно обязано останавливаться на железнодорожном переезде, НЕ обязано останавливаться в какой ситуации?","options":["Когда на переезде всего два пути","Когда водитель видит как минимум на 400 футов вдоль пути","Когда сотрудник полиции или сигнал регулирования движения разрешает движение","Когда транспортное средство отстаёт от графика"],"explanation":"HRS 291C-93 освобождает от обязательной остановки там, где сотрудник полиции или исправный сигнал регулирования движения разрешает движение; это также не относится к переездам трамвайных путей в деловом или жилом районе. Источник: HRS 291C-93."},"65":{"q":"Закон Гавайев об объезде школьного автобуса применяется, когда остановившийся автобус включил свои визуальные сигналы в каких условиях?","options":["Только в обозначенной школьной зоне","Только на дорогах с ограничением 25 mph или менее","Везде, где автобус останавливается, включая скоростные автомагистрали ограниченного доступа","В жилом районе"],"explanation":"HRS 291C-95 привязывает требование об остановке к школьному автобусу, остановившемуся на шоссе или дороге в жилом районе с включёнными визуальными сигналами. Источник: HRS 291C-95."},"66":{"q":"Когда закон Гавайев о школьных автобусах требует от вас остановиться перед автобусом, высаживающим или подбирающим детей, на каком расстоянии от автобуса вы должны остановиться?","options":["Не менее 20 футов от школьного автобуса","Не менее 10 футов от школьного автобуса","Не менее 30 футов от школьного автобуса","Не менее 50 футов от школьного автобуса"],"explanation":"HRS 291C-95 требует, чтобы водители в полосе автобуса и в прилегающих полосах останавливались не ближе 20 футов от школьного автобуса и оставались на месте, пока он не начнёт движение и сигналы не будут выключены. Во многих штатах просто сказано «остановиться»; на Гавайях указано 20 футов. Источник: HRS 291C-95."},"67":{"q":"На неразделённой двухполосной жилой дороге на Гавайях школьный автобус останавливается с мигающими красными огнями и выдвинутым знаком «стоп» (stop arm). Кто должен остановиться?","options":["Остановиться должны только те, кто едет позади автобуса","Остановиться должны только те, кто едет в той же полосе, что и автобус","Остановиться должно движение в обоих направлениях","Никто не обязан останавливаться, потому что нет разделительной полосы"],"explanation":"На неразделённой проезжей части HRS 291C-95 применяется к транспортным средствам в полосе автобуса и во всех прилегающих полосах независимо от направления, поэтому движение и позади, и навстречу должно остановиться не ближе 20 футов. Источник: HRS 291C-95."},"68":{"q":"Согласно закону Гавайев о школьных автобусах, когда исключение для разделённой проезжей части позволяет встречному движению продолжать движение БЕЗ остановки перед остановившимся автобусом?","options":["Всегда, когда на дороге две или более полосы в каждом направлении","Всегда, когда на дороге есть нанесённая краской центральная линия","Только когда регулировщик пропускает движение взмахом руки","Когда автобус и транспортное средство находятся на разных проезжих частях, разделённых промежуточным пространством, физическим барьером или чётко обозначенным разделительным участком"],"explanation":"HRS 291C-95 гласит, что требование об остановке не применяется, когда автобус и транспортное средство находятся на разных проезжих частях; там, где жилая дорога разделена промежуточным пространством, физическим барьером или чётко обозначенным разделительным участком, остановиться должны только водители на той же стороне, что и автобус. Источник: HRS 291C-95."},"69":{"q":"Школьный автобус на Гавайях сигнализирует об остановке попеременно мигающими красными лампами. На каком расстоянии эти сигнальные лампы должны быть отчётливо видны согласно закону?","options":["200 футов при обычном солнечном свете","500 футов при обычном солнечном свете","1,000 футов при обычном солнечном свете","300 футов при обычном солнечном свете"],"explanation":"HRS 291C-95 описывает четыре красные сигнальные лампы автобуса как попеременно мигающие и отчётливо видимые на расстоянии 500 футов при обычном солнечном свете. Источник: HRS 291C-95."},"70":{"q":"Ограничение Гавайев 2024 года на использование левой полосы для тяжёлых коммерческих транспортных средств применяется при каком весе транспортного средства?","options":["10,000 фунтов или более","5,000 фунтов или более","26,001 фунт или более","80,000 фунтов или более"],"explanation":"HRS 291C-55 (вступил в силу 1 января 2024 года) запрещает коммерческому транспортному средству массой 10,000 фунтов или более использовать крайнюю левую полосу там, где есть три или более полосы в одном направлении, за исключением случаев поддержания темпа движения, обгона или поворота/съезда налево. Источник: HRS 291C-55."},"71":{"q":"Запрет Гавайев на использование левой полосы для тяжёлых транспортных средств (вступивший в силу в 2024 году) применяется на проезжих частях с каким количеством полос в одном направлении?","options":["Две или более полосы в одном направлении","Четыре или более полосы в одном направлении","Любая многополосная дорога независимо от количества полос","Три или более полосы в одном направлении"],"explanation":"HRS 291C-55 применяется только там, где у проезжей части три или более полосы для движения в одном направлении; там коммерческое транспортное средство массой 10,000 lbs или более не может использовать крайнюю левую полосу, кроме как для поддержания темпа движения, обгона или поворота/съезда налево. Источник: HRS 291C-55."},"72":{"q":"Согласно закону Гавайев о левой полосе для тяжёлых коммерческих транспортных средств, какое использование крайней левой полосы по-прежнему разрешено?","options":["Движение в левой полосе для поддержания постоянной скорости на длинном спуске","Обгон и проезд другого транспортного средства, движущегося в том же направлении","Движение слева, чтобы избежать частого вливающегося движения справа","Использование левой полосы в любое время, когда движение слабое"],"explanation":"HRS 291C-55 разрешает тяжёлому коммерческому транспортному средству находиться в крайней левой полосе только при поддержании темпа существующего потока движения, обгоне и проезде, либо при подготовке к повороту налево или съезду. Источник: HRS 291C-55."},"73":{"q":"На многополосном шоссе Гавайев коммерческое транспортное средство, движущееся медленнее обычной скорости потока, как правило должно двигаться в какой полосе?","options":["В центральной полосе для уравновешивания потока движения","В крайней левой полосе, чтобы держаться подальше от вливающегося движения","В правой доступной полосе или как можно ближе к правому краю проезжей части","В любой полосе, при условии использования указателей поворота"],"explanation":"HRS 291C-41 требует, чтобы транспортное средство, движущееся медленнее обычной скорости потока, держалось правее — в правой полосе или как можно ближе к правому краю — за исключением обгона или подготовки к повороту налево. Источник: HRS 291C-41."},"74":{"q":"Как юридически устанавливается максимальное ограничение скорости на участке шоссе Гавайев?","options":["Постановлением округа или официальными знаками, установленными директором транспорта","Единым фиксированным общештатным максимумом в 70 mph для всех шоссе","Федеральным правительством только для всех маршрутов между штатами","По усмотрению каждого отдельного полицейского округа"],"explanation":"На Гавайях нет единого законодательного общештатного максимума; согласно HRS 291C-102 максимальное (и минимальное) ограничение скорости устанавливается постановлением округа или официальными знаками, установленными директором транспорта, и водители должны соблюдать установленное ограничение. Источник: HRS 291C-102."},"75":{"q":"Каково основное правило скорости, которое водитель CDL Гавайев должен соблюдать независимо от установленного ограничения?","options":["Всегда двигаться как минимум на установленном ограничении, чтобы поддерживать движение","Всегда подстраиваться под скорость самого медленного транспортного средства на дороге","Двигаться на 5 mph ниже установленного ограничения всякий раз при перевозке груза","Никогда не двигаться быстрее, чем это разумно и безопасно для фактических и потенциальных условий"],"explanation":"HRS 291C-101 (основное правило) запрещает движение быстрее, чем это разумно и безопасно с учётом фактических и потенциальных опасностей и условий; CMV может потребоваться двигаться ниже установленного ограничения при дожде, тумане или плотном движении. Источник: HRS 291C-101."},"76":{"q":"После того как водитель CDL Гавайев остановил грузовик на двухполосной дороге с двусторонним движением, где должны быть размещены три светоотражающих предупреждающих треугольника?","options":["Все три в ряд на расстоянии 50 футов позади транспортного средства","В пределах 10 футов от задней части, 200 футов позади и 200 футов впереди транспортного средства","В пределах 10 футов от задней части, примерно в 100 футах позади и примерно в 100 футах впереди транспортного средства","Один у переднего бампера и два на обочине рядом с кабиной"],"explanation":"Руководство CDL Гавайев (следуя 49 CFR 392.22) предписывает на дороге с двусторонним движением размещать один треугольник в пределах 10 футов от задней части со стороны движения, один примерно в 100 футах позади и один примерно в 100 футах впереди. Источник: Hawaii CDL Manual."},"77":{"q":"Когда водитель CDL Гавайев останавливается на дороге с односторонним движением или на разделённом шоссе, где должны быть размещены предупреждающие треугольники?","options":["Равномерно на расстоянии 50, 100 и 150 футов впереди транспортного средства","Примерно в 10 футах, 100 футах и 200 футах в сторону приближающегося движения позади транспортного средства","Один в 10 футах позади и два в 500 футах позади на обочине","Все три в пределах 25 футов от задней части транспортного средства"],"explanation":"Руководство CDL Гавайев предписывает, чтобы на дороге с односторонним движением или разделённом шоссе треугольники размещались в сторону приближающегося движения примерно в 10 футах, 100 футах и 200 футах от транспортного средства. Источник: Hawaii CDL Manual."},"78":{"q":"Водитель CDL Гавайев останавливается на двухполосной дороге сразу за вершиной холма, который перекрывает обзор приближающегося движения. Что водитель должен сделать с задним предупреждающим треугольником?","options":["Оставить его на стандартных 100 футах, потому что расстояния никогда не меняются","Разместить его прямо на центральной линии в 10 футах позади грузовика и только там","Пропустить задний треугольник, поскольку холм и так скрывает грузовик","Отодвинуть задний треугольник за вершину холма, на расстояние до 500 футов от грузовика, чтобы предупредить водителей до препятствия"],"explanation":"Руководство CDL Гавайев гласит, что если холм, поворот или иное препятствие мешает водителям видеть грузовик в пределах 500 футов, заднее предупреждающее устройство следует отодвинуть назад по дороге — на расстояние до 500 футов — чтобы приближающиеся водители получили достаточное предупреждение. Источник: Hawaii CDL Manual."},"79":{"q":"Куда на Гавайях фактически обращается соискатель CDL, чтобы подать заявление и получить коммерческие водительские права?","options":["В региональное полевое отделение FMCSA","В одно из окружных отделений по выдаче водительских прав (например, Honolulu Customer Services, Maui/Kauai Finance, Hawaii County VRLD)","Отправив заявление почтой в штаб-квартиру Hawaii DOT в Гонолулу","В любое отделение Почтовой службы США по всему штату"],"explanation":"CDL Гавайев выдаются через четыре окружных отделения по выдаче водительских прав, действующих под надзором State of Hawaii DOT Motor Vehicle Safety Office (MVSO). Источник: уведомление Hawaii DOT MVSO «How to Apply for a CDL» и страницы окружных CDL (Honolulu CSD, Maui/Kauai Finance, Hawaii County VRLD)."},"80":{"q":"Из скольких отдельных категорий самосертификации коммерческой деятельности должен выбрать соискатель CDL Гавайев при самосертификации своего типа вождения?","options":["Две","Четыре","Три","Шесть"],"explanation":"Соискатели на Гавайях самосертифицируются по одной из четырёх категорий: Non-excepted interstate, Excepted interstate, Non-excepted intrastate или Excepted intrastate. Источник: Hawaii DOT MVSO CDL Medical Certification Requirements FAQ (Rev. 5/19/2025)."},"81":{"q":"Какая из четырёх категорий самосертификации Гавайев НЕ требует подачи Сертификата медицинского эксперта (Form MCSA-5876)?","options":["Excepted interstate","Non-excepted interstate","Non-excepted intrastate","Все четыре категории требуют MEC"],"explanation":"Согласно FAQ Hawaii MVSO, водители, самосертифицирующиеся как «Excepted interstate» (или excepted intrastate), не обязаны подавать MEC; это обязаны делать только водители Non-excepted interstate и Non-excepted intrastate. Источник: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)."},"82":{"q":"Начиная с 19 мая 2025 года, каким образом должен подаваться Сертификат медицинского эксперта (MCSA-5876) водителя CDL Гавайев категории Non-excepted?","options":["В виде бумажной копии, сданной в окружное отделение CDL","Загруженным водителем на веб-портал Hawaii DOT MVSO","Отправленным работодателем водителя почтой в FMCSA","Напрямую в базу данных FMCSA National Registry через сертифицированного медицинского эксперта"],"explanation":"По состоянию на 19 мая 2025 года HDOT и окружные отделения CDL больше не принимают бумажные копии MEC; сертифицированный медицинский эксперт подаёт MEC напрямую в FMCSA National Registry, который передаёт данные в систему водительских прав Гавайев. Источник: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)."},"83":{"q":"Какие три части составляют экзамен на навыки CDL Гавайев, все из которых должны быть сданы на одном приёме?","options":["Воздушные тормоза, письменный экзамен по hazmat и вождение по дороге","Предрейсовый осмотр, проверка зрения и тест на общие знания","Предрейсовый осмотр, базовое управление транспортным средством и вождение по дороге","Движение задним ходом, сцепка/расцепка и письменный экзамен на дополнение (endorsement)"],"explanation":"Экзамен на навыки CDL Гавайев состоит из трёх частей: предрейсовый осмотр, базовое управление транспортным средством и тест по вождению на дороге, все сдаются на одном приёме. Источник: уведомление Hawaii DOT MVSO «How to Apply for a CDL» и страница отделения CDL Honolulu CSD."},"84":{"q":"Как долго действует учебное (commercial learner) разрешение CDL Гавайев?","options":["Шесть месяцев","Один год","Два года","180 дней"],"explanation":"Учебное разрешение CDL Гавайев действует один год и позволяет его держателю практиковаться в вождении под наблюдением. Источник: уведомление Hawaii DOT MVSO «How to Apply for a CDL»."},"85":{"q":"После того как на Гавайях выдан CLP, как долго его держатель должен ждать, прежде чем сможет сдавать экзамен на навыки CDL?","options":["30 дней","7 дней","10 дней","14 дней"],"explanation":"Федеральное правило, применяемое на Гавайях, требует владеть CLP не менее 14 дней до экзамена на навыки; Honolulu CSD отмечает, что записаться на экзамен по навыкам можно через 14 дней после выдачи разрешения. Источник: страница отделения CDL Honolulu CSD; 49 CFR 383.25."},"86":{"q":"Какое обучение должен пройти соискатель CDL класса A/B на Гавайях ПЕРЕД сдачей экзамена на навыки CDL (вступило в силу 7 февраля 2022 года)?","options":["Государственный курс защитного вождения","40-часовой аудиторный семинар по безопасности Hawaii DOT","Стажировку на рабочем месте только у работодателя","Зарегистрированное в FMCSA обучение водителей начального уровня (ELDT)"],"explanation":"С 7 февраля 2022 года соискатели на первичный CDL класса A/B (и некоторые дополнения) должны пройти Entry-Level Driver Training FMCSA у провайдера из FMCSA Training Provider Registry до сдачи экзамена. Источник: правило FMCSA ELDT в применении на странице отделения CDL Honolulu CSD."},"87":{"q":"Каков минимальный возраст для получения полного (без ограничений) CDL Гавайев?","options":["18","19","25","21"],"explanation":"Гавайи требуют, чтобы соискателю был 21 год для полного CDL (учебное разрешение CDL можно получить в 18 лет). Источник: уведомление Hawaii DOT MVSO «How to Apply for a CDL» и страница отделения CDL Honolulu CSD."},"88":{"q":"Какой минимальный стандарт зрения должен соответствовать соискатель CDL Гавайев при проверке зрения?","options":["20/40 на каждый глаз (с коррекцией допустимо)","20/20 на каждый глаз, только без коррекции","20/50 на лучшем глазу","20/30 суммарно обоими глазами"],"explanation":"Гавайи требуют минимум 20/40 на каждый глаз, с разрешённым использованием корректирующих линз, для проверки зрения CDL. Источник: страница отделения CDL Honolulu CSD; Hawaii DOT MVSO."},"89":{"q":"Что из перечисленного входит в обязательную документацию при подаче заявления на CDL Гавайев?","options":["Нотариально заверенное письмо от текущего работодателя в сфере грузоперевозок","Действующие базовые (некоммерческие) водительские права Гавайев плюс подтверждение личности, SSN и места жительства","Паспорт как единственное приемлемое подтверждение личности","Заверенные налоговые декларации за три года"],"explanation":"Соискатели CDL Гавайев должны предъявить действующие водительские права Гавайев и подтвердить личность/возраст (например, свидетельством о рождении), номер социального страхования и место жительства. Источник: уведомление Hawaii DOT MVSO «How to Apply for a CDL» и страница отделения CDL Honolulu CSD."},"90":{"q":"Если водитель на Гавайях работает в коммерции между штатами КАК excepted, ТАК и non-excepted, какой статус он должен самосертифицировать?","options":["Non-excepted interstate","Excepted interstate","Excepted intrastate","Любой из них, водитель может выбирать свободно"],"explanation":"Hawaii MVSO требует, чтобы водитель, работающий в обоих типах, выбирал «Non-excepted interstate», чтобы оставаться квалифицированным для обоих, что также требует подачи MEC. Источник: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)."},"91":{"q":"Во время перехода на электронную подачу MEC, в течение какого срока Hawaii MVSO рекомендует водителю CDL иметь при себе копию Сертификата медицинского эксперта после его подачи медицинскому эксперту?","options":["Не дольше 30 дней с момента подачи","Не дольше 60 дней с момента подачи","Не дольше 15 дней с момента подачи","Ровно один год"],"explanation":"Hawaii MVSO рекомендует иметь при себе копию MEC не дольше 15 дней с момента её подачи медицинскому эксперту, чтобы покрыть возможные задержки электронного обновления. Источник: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)."},"92":{"q":"У держателя CDL Гавайев истекает медицинский сертификат, и он НЕ подаёт новый. В какой день все привилегии CDL аннулируются, требуя личного визита в отделение CDL?","options":["День 54","День 30","День 90","День 15"],"explanation":"Согласно Hawaii MVSO, если MEC обновлён в течение 53 дней, личная явка и плата за восстановление не требуются; на 54-й день все привилегии CDL аннулируются, и водитель должен посетить отделение CDL для восстановления. Источник: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)."},"93":{"q":"Что происходит с правом водителя Гавайев на вождение в момент истечения его медицинского сертификата DOT?","options":["Он немедленно теряет право управлять коммерческим транспортным средством","Он сохраняет полные привилегии CDL в течение автоматического льготного периода в 90 дней","Ничего не меняется до следующей даты продления CDL","Он может продолжать водить только внутри штата без какой-либо медицинской карты"],"explanation":"Hawaii MVSO заявляет, что в момент истечения медицинского сертификата водитель теряет право управлять CMV; затем MVSO направляет почтой уведомление о том, что водитель больше не годен по состоянию здоровья. Источник: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)."},"94":{"q":"На Гавайях, за какое время до истечения срока держатель CDL обычно может продлить свои коммерческие водительские права?","options":["Только в день истечения срока или после него","До 30 дней до даты истечения срока","До 6 месяцев до даты истечения срока","До 2 лет до даты истечения срока"],"explanation":"Окружные отделения Гавайев (например, Maui) разрешают продление CDL в течение шести (6) месяцев до даты истечения срока. Источник: страница округа Maui «Renewal of Commercial Drivers License»."},"95":{"q":"Как часто держатель CDL Гавайев должен продлевать дополнение на перевозку опасных грузов (HazMat), независимо от цикла базовой лицензии?","options":["Каждые 8 лет без проверки данных","Каждые 2 года с новым тестом по вождению","Каждые 5 лет, включая оценку угрозы безопасности TSA","Только один раз, оно никогда не истекает после первой выдачи"],"explanation":"Дополнение HazMat должно продлеваться каждые 5 лет и требует сдачи теста на знание HazMat плюс оценки угрозы безопасности TSA (проверка данных на основе отпечатков пальцев). Источник: страница продления CDL округа Maui; программа TSA HazMat Endorsement; 49 CFR Part 1572."},"96":{"q":"Какое обязательство по медицинскому сертификату имеют водители Гавайев, которые имеют водительские права класса 3 или класса 4 и управляют CMV?","options":["Они должны подавать MEC в FMCSA National Registry, как держатели класса A","Они не подают MEC медицинскому эксперту, но должны иметь при себе копию при управлении CMV","Они полностью освобождены и вообще не нуждаются в медицинском сертификате","Они должны ежегодно отправлять бумажный MEC почтой в MVSO"],"explanation":"Hawaii MVSO заявляет, что держатели прав класса 3/4, управляющие CMV, не подают MEC своему медицинскому эксперту, но по-прежнему обязаны иметь при себе копию MEC при управлении CMV. Источник: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)."},"97":{"q":"Какое ведомство Гавайев отвечает за надзор за процессом медицинской сертификации CDL и которому направляется самосертификация?","options":["Департамент здравоохранения штата Гавайи","Отдел дорожного движения полицейского управления Гонолулу","Hawaii DOT Motor Vehicle Safety Office (MVSO)","Министерство труда США"],"explanation":"Hawaii DOT Motor Vehicle Safety Office (MVSO) ведает медицинской сертификацией CDL и самосертификацией, взаимодействуя с окружными отделениями CDL и FMCSA. Источник: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)."},"98":{"q":"Согласно обновлённым правилам Гавайев, следующим за 49 CFR 391.46, что теперь верно для водителя с надлежащим образом контролируемым инсулинозависимым сахарным диабетом (ITDM), добивающегося медицинской сертификации?","options":["Водитель всё ещё должен подать в MVSO заявление на отдельный внутриштатный отказ (waiver) по ITDM до какой-либо сертификации","Водитель навсегда лишён права иметь CDL на Гавайях","Водителю нужна лишь справка от любого фармацевта, а не от медицинского эксперта","Сертифицированный медицинский эксперт может выдать MEC; отдельное заявление на внутриштатный отказ (waiver) по ITDM в MVSO больше не требуется"],"explanation":"Согласно 49 CFR 391.46 в редакции, принятой Hawaii MVSO, сертифицированный медицинский эксперт может выдать MEC водителю со стабильным, надлежащим образом контролируемым ITDM (с использованием оценки MCSA-5870); отдельное заявление на внутриштатный отказ (waiver) по ITDM в MVSO больше не требуется. Источник: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)."}},"tr":{"0":{"q":"Hawaii yasalarına göre, fazla boyut izni (oversize permit) olmadan kamuya açık bir karayolunda işletilebilecek bir aracın (yük dahil) izin verilen azami toplam GENİŞLİĞİ nedir?","options":["8 feet","8 feet 6 inches","9 feet","10 feet"],"explanation":"HRS §291-34, izin olmaksızın eyalet içindeki herhangi bir kamu yolunda, caddesinde veya karayolunda, yük dahil toplam genişliği dokuz feeti aşan bir motorlu aracın işletilmesini yasaklar. (Hawaii Revised Statutes §291-34; Hawaii CDL Manual.)"},"1":{"q":"Hawaii karayollarında, izin olmadan bir araç için izin verilen azami toplam YÜKSEKLİK (yük dahil) nedir?","options":["13 feet","13 feet 6 inches","14 feet","15 feet"],"explanation":"HRS §291-34, yük dahil azami araç yüksekliğini on dört feet olarak belirler. Bu sınır dahilinde kalsa bile, bir araç, ilgili yapı için ilan edilen geçiş açıklığını aşıyorsa bir köprü veya yapının altından geçemez. (Hawaii Revised Statutes §291-34.)"},"2":{"q":"Hawaii karayollarında, tek bir motorlu aracın (kombinasyon olmayan tekli bir birim) yük dahil, izin olmadan izin verilen azami toplam UZUNLUĞU nedir?","options":["40 feet","45 feet","53 feet","60 feet"],"explanation":"HRS §291-34, tek bir motorlu aracı (kombinasyon olmayan) yük dahil toplam uzunlukta kırk beş feet ile sınırlar. (Hawaii Revised Statutes §291-34.)"},"3":{"q":"HRS §291-34 uyarınca, Hawaii'de izin olmadan bir çekici (truck-tractor) ve yarı römork KOMBİNASYONUNUN yük dahil izin verilen azami toplam uzunluğu nedir?","options":["60 feet","65 feet","70 feet","75 feet"],"explanation":"HRS §291-34, bir çekici ve yarı römork kombinasyonunu yük dahil toplam uzunlukta altmış beş feet ile sınırlar. (Hawaii Revised Statutes §291-34.)"},"4":{"q":"Hawaii'de, herhangi bir TEK AKS tarafından karayoluna uygulanan azami brüt ağırlık şu değeri aşamaz:","options":["18,000 pounds","20,000 pounds","22,500 pounds","34,000 pounds"],"explanation":"HRS §291-35, herhangi bir tek aks üzerindeki brüt ağırlığı yirmi bin pound ile sınırlar. (Hawaii Revised Statutes §291-35.)"},"5":{"q":"Hawaii'de bir 'tandem aks' (birbirinden 40 inçten fazla ancak 96 inçten fazla olmayacak şekilde aralıklı iki ardışık aks) en fazla şu brüt ağırlığı taşıyabilir:","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"HRS §291-35, bir tandem aksı (birbirinden 40 inçten fazla ancak 96 inçten fazla olmayacak şekilde aralıklı akslar) otuz dört bin pound ile sınırlar. (Hawaii Revised Statutes §291-35.)"},"6":{"q":"Hawaii'nin ağırlık yasası uyarınca, tekli veya çiftli montaj olsun, herhangi bir TEK TEKERLEK tarafından karayoluna uygulanan brüt ağırlık şu değeri aşamaz:","options":["8,000 pounds","10,000 pounds","12,000 pounds","13,500 pounds"],"explanation":"HRS §291-35, herhangi bir tek tekerlek (tekli veya çiftli montaj) üzerindeki brüt ağırlığı on bin pound ile sınırlar. (Hawaii Revised Statutes §291-35.)"},"7":{"q":"Hawaii karayollarında, fazla ağırlık izni (overweight permit) olmadan bir araç veya kombinasyon için izin verilen azami toplam BRÜT AĞIRLIK nedir?","options":["73,280 pounds","80,000 pounds","88,000 pounds","105,500 pounds"],"explanation":"HRS §291-35, federal sınırla tutarlı olarak, toplam araç brüt ağırlığını seksen bin pound ile sınırlar. (Hawaii Revised Statutes §291-35.)"},"8":{"q":"Hawaii'de iki ardışık tandem aks seti, yalnızca iki tandem setinin ilk ve son aksları arasındaki mesafe en az şu değerde olduğunda her biri 34,000 pound taşıyabilir:","options":["28 feet","32 feet","36 feet","40 feet"],"explanation":"HRS §291-35, iki ardışık tandem aks setinin her birinin 34,000 pound taşımasına yalnızca ilk ve son akslar arasındaki toplam mesafe otuz altı feet veya daha fazla olduğunda ve toplam brüt ağırlık 80,000 pound'da veya altında kaldığında izin verir. (Hawaii Revised Statutes §291-35.)"},"9":{"q":"HRS §291-35'te bir aks grubunun izin verilen brüt ağırlığını aks aralığı ve sayısına bağlayan formül hangi federal standarda dayanır?","options":["Federal Köprü Formülü (Bridge Gross Weight Formula)","CARB aks-aralığı kuralı","AASHTO kaplama yükleme endeksi","FMCSA hizmet saatleri (hours-of-service) tablosu"],"explanation":"Hawaii'nin HRS §291-35'teki aks grubu ağırlık hükümleri, izin verilen ağırlığı aks sayısı ile bir grubun uç aksları arasındaki mesafeye bağlayan Federal Köprü Formülünü içerir. (Hawaii Revised Statutes §291-35; Hawaii kuralı olarak uygulanan 23 U.S.C. §127.)"},"10":{"q":"Hawaii'de bir EYALET karayolunda fazla boyut veya fazla ağırlık hareketine izin veren yazılı bir izin (permit) verme yetkisine kim sahiptir?","options":["İlçe (county) emniyet şefi","Ulaştırma Müdürü (Director of Transportation)","Kamu Hizmetleri Komisyonu (Public Utilities Commission)","Honolulu Liman Müdürü (Honolulu Harbor Master)"],"explanation":"HRS §291-36 uyarınca, Ulaştırma Müdürü (Director of Transportation) eyalet karayolları için fazla boyut/fazla ağırlık izinlerini verirken, ilçe mühendisi (county engineer) ilçe yolları ve caddeleri için bunları verir. (Hawaii Revised Statutes §291-36; HIDOT Highways Division.)"},"11":{"q":"Hawaii'de İLÇE (county) yollarındaki ve caddelerindeki hareketler için fazla boyut/fazla ağırlık iznini kim verir?","options":["Ulaştırma Müdürü (Director of Transportation)","İlçe mühendisi (county engineer)","Belediye başkanlığı ofisi","Eyalet Kamu Güvenliği Bakanlığı (Department of Public Safety)"],"explanation":"HRS §291-36, ilçe yolları ve caddeleri için izin verme yetkisini ilçe mühendisine (county engineer) verir (Ulaştırma Müdürü eyalet karayollarını yönetir). (Hawaii Revised Statutes §291-36.)"},"12":{"q":"Bir Hawaii fazla boyut/fazla ağırlık izni başvurusu nasıl yapılmalıdır?","options":["Bölge ofisine telefonla sözlü olarak","Highways Division tarafından sağlanan formlar üzerinde yazılı olarak","Yalnızca lisanslı bir gümrük müşaviri aracılığıyla","Tartı istasyonuna bir bildirim asarak"],"explanation":"HRS §291-36 yazılı bir başvuru gerektirir ve HIDOT Highways Division bunu, tekerlek düzeninin krokileri, boyutlar ve yük dağılımı dahil olmak üzere kendi sağladığı formlar üzerinde talep eder. (Hawaii Revised Statutes §291-36; HIDOT Oversize/Overweight izin prosedürleri.)"},"13":{"q":"Başvuruya ek olarak, Hawaii Highways Division bir fazla boyut/fazla ağırlık izni başvurusunda bulunan kişinin dosyasında neyi bulundurmasını ister?","options":["Bir sigorta belgesi (certificate of insurance)","Bir ticari balıkçılık lisansı","Noter tasdikli bir liman teminatı (harbor bond)","Bir federal IRP kabin kartı (cab card)"],"explanation":"HIDOT Highways Division, bir fazla boyut/fazla ağırlık izni vermeden önce dosyada bir sigorta belgesi (certificate of insurance) bulunmasını gerektirir. (HIDOT Oversize/Overweight Vehicles on State Highways izin prosedürleri.)"},"14":{"q":"Hawaii'nin izin ücreti tarifesine göre, izin verilen ağırlığın 1.35 katından daha az veya 14 feetten daha az genişlikteki bir yük için TEK SEFERLİK izin (single-trip permit) ücreti şudur:","options":["$5","$10","$25","$50"],"explanation":"HRS §291-36 uyarınca, izin verilen yükün 1.35 katından az veya genişliği 14 feetten az olan bir yük için tek seferlik izin $5 tutarındadır (bu aralıkta sürekli sefer izni (continuous-trip permit) $10'dur). (Hawaii Revised Statutes §291-36; HIDOT.)"},"15":{"q":"Hawaii'nin izin ücreti tarifesine göre, izin verilen yükün 1.35 katını AŞAN bir yük için FAZLA AĞIRLIK izni (overweight permit) ücreti şudur:","options":["$5","$10","$25","$100"],"explanation":"HRS §291-36, yük izin verilen yükün 1.35 katını aştığında fazla ağırlık izni için $25 ücret belirler; aynı $25, genişliği 14 feeti aşan bir fazla boyut izni için de geçerlidir. (Hawaii Revised Statutes §291-36; HIDOT.)"},"16":{"q":"Hawaii'de bir fazla boyut GENİŞLİK izni, bir yükün genişliği şu değeri aştığında gereklidir (ve daha yüksek olan $25 ücretini taşır):","options":["9 feet","10 feet","12 feet","14 feet"],"explanation":"9 feeti aşan herhangi bir genişlik bir izin gerektirse de, HRS §291-36'nın ücret tarifesi, genişliği 14 feeti aşan bir yükü $25'lık fazla boyut izni kategorisinde değerlendirir. (Hawaii Revised Statutes §291-36; HIDOT izin ücreti tarifesi.)"},"17":{"q":"Hawaii'nin tarımsal hükümleri uyarınca, Ulaştırma Müdürü HRS §291-35 sınırlarını aşan ağırlıklara izin veren bir izin (permit) ne zaman verebilir?","options":["Yalnızca Eyalete ait araçlar için","Hasat edilmiş ürünleri, hasat edildikleri veya depolandıkları yerden işlendikleri veya kullanıldıkları yere taşırken","Yalnızca gece yarısı ile sabah 5 arası","Hiçbir zaman — fazla ağırlık çiftlik izinlerine izin verilmez"],"explanation":"HRS §291-36, ürünleri hasat edildikleri veya depolandıkları yerden işlendikleri veya kullanıldıkları yere taşırken §291-35 ağırlık sınırlarını aşmak için bir izne yetki verir. (Hawaii Revised Statutes §291-36.)"},"18":{"q":"Hawaii'de hangi tarımsal hareket HRS §291-36 uyarınca hiçbir izin GEREKTİRMEZ?","options":["Bir eyalet karayolunda 10 mil veya daha az yol kateden herhangi bir çiftlik aracı","Tarımsal operasyonlarda kullanılan ve yalnızca Ulaştırma Müdürü veya ilçe mühendisi tarafından onaylanmış bir konumda bir kamu yolunu KESEN bir araç","Ağırlığı ne olursa olsun ananas taşıyan herhangi bir araç","Kahve taşıyan 80,000 pound altındaki bir kombinasyon"],"explanation":"HRS §291-36, tarımsal operasyonlarda kullanılan ve yalnızca Ulaştırma Müdürü (eyalet karayolları) veya ilçe mühendisi (ilçe yolları) tarafından onaylanmış bir konumda bir kamu yolunu, caddesini veya karayolunu kesen bir araç için hiçbir izin gerekmediğini öngörür. (Hawaii Revised Statutes §291-36.)"},"19":{"q":"Bir mühendislik analizi, bir Hawaii köprüsünün yasal azami brüt ağırlıktan daha azını güvenle taşıyabileceğini gösterirse, yetkili merci ne yapabilir?","options":["Köprüyü tüm kamyonlara kalıcı olarak kapatabilir","O köprüyü geçen araçların brüt ağırlığını sınırlayan tabelalar yerleştirip bunları muhafaza edebilir","Telafi etmek için eyalet genelindeki brüt ağırlık sınırını yükseltebilir","O güzergah için bir CDL yükseltmesi (upgrade) talep edebilir"],"explanation":"HRS §291-35, mühendislik analizi kapasitesinin yasal azamiden daha az olduğunu gösterdiğinde Ulaştırma Müdürünün (veya ilçe mühendisinin) belirli bir köprü veya yapı üzerindeki brüt ağırlığı sınırlayan tabelalar yerleştirmesine ve muhafaza etmesine izin verir; sürücüler ilan edilen sınıra uymak zorundadır. (Hawaii Revised Statutes §291-35.)"},"20":{"q":"Hawaii'de, çekilen araç(lar)ın GVWR'si 10,000 pound'un üzerinde olduğunda, brüt kombinasyon ağırlık derecelendirmesi (GCWR) 26,001 pound veya daha fazla olan herhangi bir araç kombinasyonunu sürmek için hangi CDL sınıfı gereklidir?","options":["Class A","Class B","Class C","Class D"],"explanation":"Hawaii, çekilen birimin GVWR'si 10,000 lbs'yi aştığı sürece, GCWR'si 26,001 lbs veya daha fazla olan herhangi bir araç kombinasyonunu Class A CDL olarak tanımlar. Kaynak: HRS Sec. 286-239 ve Honolulu Commercial Driver Licensing Office. Federal/Hawaii bir 'Class D' CDL yoktur."},"21":{"q":"Hawaii yasalarına göre, brüt araç ağırlık derecelendirmesi (GVWR) 26,001 pound veya daha fazla olan tek bir araç (veya 10,000 pound'u aşmayan bir birimi çeken böyle bir araç) hangi CDL sınıfını gerektirir?","options":["Class A","Class B","Class C","Class M"],"explanation":"Hawaii, GVWR'si 26,001 lbs veya daha fazla olan tek bir aracı Class B ticari motorlu araç olarak sınıflandırır. Kaynak: HRS Sec. 286-239; Honolulu CDL Office. 'Class M' bir CDL değil, bir motosiklet kategorisidir."},"22":{"q":"Bir Hawaii sürücüsü, 26,001 lbs GVWR altında, 16 veya daha fazla yolcu (sürücü dahil) taşımak için tasarlanmış veya tehlikeli maddeler için plakalı (placarded) bir aracı işletir. Hangi CDL sınıfı geçerlidir?","options":["Class A","Class B","Class C","CDL gerekmez"],"explanation":"Bir Class C CDL, Class A veya B'yi karşılamayan ancak 16+ yolcu (sürücü dahil) taşımak için tasarlanmış veya plakalı (placarded) hazmat taşıyan araçları kapsar. Kaynak: HRS Sec. 286-239; Honolulu CDL Office."},"23":{"q":"Bir Hawaii CDL üzerindeki hangi onay kodu (endorsement), plaka (placard) gerektiren tehlikeli maddeleri taşıyan bir aracı sürmeye yetki verir?","options":["Endorsement N","Endorsement T","Endorsement H","Endorsement P"],"explanation":"H (HazMat) onayı, plakalı (placarded) tehlikeli maddeler taşıyan bir aracı işletmeye yetki verir. Kaynak: Hawaii CDL Manual / Honolulu CDL Office; 49 CFR Part 383 (Hawaii tarafından kabul edilmiştir)."},"24":{"q":"Bir Hawaii CDL'sinde, çiftli (double) ve üçlü (triple) römork sürmek için hangi onay (endorsement) gereklidir?","options":["Endorsement T","Endorsement N","Endorsement S","Endorsement H"],"explanation":"T onayı, çiftli (double) ve üçlü (triple) römorkları işletmeye yetki verir. Kaynak: Hawaii CDL Manual / Honolulu CDL Office; 49 CFR 383.93."},"25":{"q":"Hawaii, genellikle 1,000 galonu aşan dereceli kapasiteye sahip kalıcı olarak monte edilmiş bir tankta sıvı veya gaz taşımak için tasarlanmış bir tank aracını sürmek için hangi onayı (endorsement) gerektirir?","options":["Endorsement P","Endorsement N","Endorsement T","Endorsement X"],"explanation":"Tank araçları için N (Tanker) onayı gereklidir; Hawaii, 1,000 galonu aşan tanklara atıfta bulunur. Kaynak: Honolulu CDL Office; 49 CFR 383.93. X kodu yalnızca tanker değil, birleşik bir tank + hazmat'ı ifade eder."},"26":{"q":"Bir Hawaii CDL sahibinin, 16 veya daha fazla yolcu (sürücü dahil) taşımak için tasarlanmış bir aracı sürmek için hangi onayı (endorsement) alması gerekir?","options":["Endorsement S","Endorsement N","Endorsement P","Endorsement T"],"explanation":"Sürücü dahil 16 veya daha fazla yolcu taşımak için P (Passenger) onayı gereklidir. Kaynak: Honolulu CDL Office; 49 CFR 383.93. S onayı özellikle okul otobüsleri içindir."},"27":{"q":"Hawaii'de bir okul otobüsü sürmek için, bir CDL sahibinin S onayına (endorsement) sahip olması gerekir. Hangi ek yolcu ile ilgili onay da gereklidir?","options":["Endorsement N","Endorsement T","Endorsement H","Endorsement P"],"explanation":"Bir okul otobüsü sürücüsünün hem S (School Bus) hem de P (Passenger) onaylarına sahip olması gerekir. Kaynak: Hawaii CDL Manual; Hawaii tarafından kabul edilen 49 CFR 383.93."},"28":{"q":"Eyaletler arası (eyalet sınırları boyunca) ticari sürüşe yetki veren bir Hawaii CDL'si almak için gereken asgari yaş nedir?","options":["18 yaş","19 yaş","20 yaş","21 yaş"],"explanation":"Eyaletler arası (interstate) ticari sürüş asgari 21 yaş gerektirir. Yalnızca eyalet içi (intrastate) operasyona 18 yaşında izin verilebilir. Kaynak: Honolulu CDL Office; 49 CFR 391.11(b)."},"29":{"q":"Bir Hawaii CDL'sine başvurmadan önce, bir sürücünün gerekli bilgi testini/testlerini geçerek önce hangi belgeyi alması gerekir?","options":["Ticari Öğrenci İzni (Commercial Learner Permit - CLP)","Geçici (Provisional) CDL","Geçici HazMat kartı","Class C eğitim izni"],"explanation":"Başvuru sahipleri, CDL beceri testini almadan önce bilgi testini/testlerini geçerek önce bir Ticari Öğrenci İzni (Commercial Learner Permit - CLP) almalıdır. Kaynak: Honolulu CDL Office; 49 CFR 383.25."},"30":{"q":"Hawaii tarafından kabul edilen federal kurallar uyarınca, bir sürücünün CDL beceri testini almaya uygun olmadan önce bir Ticari Öğrenci İznini (Commercial Learner Permit) ne kadar süre elinde tutması gerekir?","options":["En az 7 gün","En az 14 gün","En az 30 gün","En az 60 gün"],"explanation":"Bir sürücü, beceri testini almadan önce CLP'yi en az 14 gün elinde tutmalıdır; Hawaii, beceri testini iznin verilmesinden en erken 14 gün sonra planlar. Kaynak: Honolulu CDL Office; 49 CFR 383.25(e)."},"31":{"q":"Bir Hawaii Ticari Öğrenci İzni (CLP) yenilenmesi gerekmeden önce ne kadar süre geçerlidir?","options":["90 gün","180 gün","1 yıl","2 yıl"],"explanation":"Bir Hawaii CLP'si 180 gün geçerlidir. Kaynak: Hawaii CDL Manual / DMV rehberliği; 49 CFR 383.25(c)."},"32":{"q":"Bir Hawaii Ticari Öğrenci İzni ile araç sürerken, izin sahibi şunu yapmalıdır:","options":["Yalnızca gündüz saatlerinde tek başına araç sürmek","Yanında oturan bir CDL sahibi eşliğinde bulunmak","Herhangi bir pratikten önce bir yolcu onayına (passenger endorsement) sahip olmak","Yalnızca özel mülk üzerinde araç sürmek"],"explanation":"Bir CLP sahibi, her zaman ön koltukta oturan, geçerli bir CDL'ye (pratik yapılan sınıf/onaylar için) sahip bir kişi eşliğinde bulunmalıdır. Kaynak: Hawaii CDL Manual; 49 CFR 383.25(a)."},"33":{"q":"Hawaii'nin CDL veren ofisi, bir A.B.D. vatandaşı başvuru sahibi için kimlik ve yasal varlık (lawful presence) kanıtı olarak hangi belgeyi kabul eder?","options":["Bir kütüphane kartı","Onaylı bir A.B.D. doğum belgesi","Bir araç ruhsatı","Yalnızca bir fatura (utility bill)"],"explanation":"Hawaii, kimlik ve yasal varlığı (lawful presence) kanıtlamak için onaylı bir A.B.D. doğum belgesi (veya başka bir onaylanmış kanıt) gerektirir. Kaynak: Honolulu CDL Office belge listesi."},"34":{"q":"Hawaii'nin CDL ofisi, bir başvuru sahibinin kaç adet ikamet kanıtı belgesi sunmasını gerektirir?","options":["Hiçbiri","Bir","İki","Dört"],"explanation":"Hawaii, bir CDL için Hawaii ikametini kanıtlamak amacıyla iki adet ikamet kanıtı belgesi gerektirir. Kaynak: Honolulu CDL Office belge kontrol listesi."},"35":{"q":"Bir Hawaii CDL başvuru sahibi, araç sürmek için fiziksel yeterliliğini onaylamak amacıyla hangi tıbbi belgeyi sunmalıdır?","options":["Güncel bir DOT Tıbbi Muayene Sertifikası (MCSA-5876)","Bir diş muayenesi onay formu","Noter tasdikli bir sağlık beyannamesi","Bir aile hekimi reçetesi"],"explanation":"Başvuru sahipleri, güncel bir DOT fiziksel muayenesi / Tıbbi Muayene Sertifikası (Form MCSA-5876) sunmalıdır. Kaynak: Honolulu CDL Office; 49 CFR 391.43."},"36":{"q":"Eyalet sınırları boyunca araç işleten ve federal tıbbi sertifika gerekliliğine tabi olup bunu karşılayan bir Hawaii CDL sürücüsüne hangi tıbbi öz-belgelendirme (self-certification) kategorisi uygulanır?","options":["Excepted Interstate","Non-Excepted Interstate","Excepted Intrastate","Non-Excepted Intrastate"],"explanation":"Eyaletler arası ticarette federal Part 391 tıbbi sertifika gerekliliğini karşılaması gereken bir sürücü, kendisini Non-Excepted Interstate olarak öz-belgelendirir. Kaynak: Hawaii tarafından kabul edilen 49 CFR 383.71(b)."},"37":{"q":"7 Şubat 2022'den bu yana, ilk bir Hawaii Class A veya B CDL'si (veya ilk bir P, S veya H onayı) için beceri testini almadan önce, bir başvuru sahibi hangi gerekliliği tamamlamalıdır?","options":["5 yıllık temiz bir sürüş kaydı","Kayıtlı bir sağlayıcıdan FMCSA Giriş Seviyesi Sürücü Eğitimi (ELDT)","Herhangi bir okulda bir defansif sürüş kursu","İki yıllık bir çıraklık"],"explanation":"ELDT, ilk kez alınan Class A/B CDL'leri ve ilk kez alınan P, S veya H onayları için gereklidir; eğitim FMCSA Training Provider Registry'de yer alan bir sağlayıcıdan gelmelidir. Kaynak: 49 CFR Part 380 (7 Şubat 2022'de yürürlükte); Honolulu CDL Office."},"38":{"q":"HazMat bilgi testini geçmeye ek olarak, H (HazMat) onayı verilmeden önce bir Hawaii başvuru sahibi neyi tamamlamalıdır?","options":["Bir TSA güvenlik tehdidi değerlendirmesi (geçmiş kontrolü)","Bir tank aracında yol testi","Bir emisyon muayenesi","Bir tekne güvenliği kursu"],"explanation":"Federal yasa, her HazMat onayı başvuru sahibinin, bilgi testine ve ELDT'ye ek olarak, verilmeden önce bir TSA güvenlik tehdidi değerlendirmesini (parmak izi ile geçmiş kontrolü) geçmesini gerektirir. Kaynak: 49 CFR 1572 (TSA); 49 CFR 383.141; Hawaii CDL Office."},"39":{"q":"Hawaii'de bir kişi, ticari bir motorlu aracı (CMV) en az hangi düzeyde kandaki alkol konsantrasyonu (BAC) ile işleterek büyük (major) bir diskalifiye edici suç işler?","options":["0.02","0.04","0.08","0.10"],"explanation":"Hawaii, CMV alkol sınırını, sıradan sürücüler için olan 0.08 sınırının yarısı olan 0.04 BAC olarak belirler. Bir CMV'yi 0.04 veya daha yüksek değerde işletmek büyük (major) bir suçtur. Kaynak: Hawaii CDL Manual (Hawaii DOT) ve HRS 286-240; 49 CFR 383.51."},"40":{"q":"Hawaii'nin zımni rıza (implied-consent) yasası uyarınca, bir ticari sürücü eyaletin karayollarında araç sürerek neye rıza göstermiş sayılır?","options":["Herhangi bir tartı istasyonunda bir araç muayenesine","Tutuklanması halinde alkol veya uyuşturucu içeriği için bir nefes, kan veya idrar testine","Araç kabininde arama emri olmaksızın bir aramaya","Her yıl bir tıbbi yeniden sertifikalandırma muayenesine"],"explanation":"Hawaii'nin zımni rıza yasası, yasal olarak tutuklandığında herhangi bir sürücünün alkol konsantrasyonunu veya uyuşturucu içeriğini belirlemek için bir nefes, kan veya idrar testine rıza gösterdiğini varsayar. Kaynak: HRS 291E-11 (zımni rıza); Hawaii CDL Manual."},"41":{"q":"Bir Hawaii CDL sahibi, plakalı (placarded) tehlikeli maddeler taşımazken ilk büyük (major) suçtan (CMV içinde DUI gibi) mahkum edilir. Asgari diskalifiye süresi şudur:","options":["60 gün","120 gün","1 yıl","3 yıl"],"explanation":"İlk büyük (major) suç, Hawaii'de asgari 1 yıllık CDL diskalifiyesi taşır. Kaynak: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 1."},"42":{"q":"İlk büyük (major) suç, sürücü plaka (placard) gerektiren tehlikeli maddeler taşıyan bir CMV'yi işletirken meydana gelirse, diskalifiye süresi şu değere yükselir:","options":["1 yıl","18 ay","3 yıl","5 yıl"],"explanation":"Plakalı (placarded) tehlikeli maddeler taşınırken işlenen ilk büyük (major) suç, diskalifiyeyi 1 yıldan 3 yıla yükseltir. Kaynak: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51 Table 1."},"43":{"q":"Hawaii'de bir sürücünün hayatı boyunca (CMV içinde işlenen) İKİNCİ bir büyük (major) suç için diskalifiye süresi nedir?","options":["3 yıl","5 yıl","10 yıl","Ömür boyu (life)"],"explanation":"İkinci bir büyük (major) suç, Hawaii'de ömür boyu CDL diskalifiyesiyle sonuçlanır. Kaynak: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 1."},"44":{"q":"Gerekli alkol/uyuşturucu testine girmeyi REDDEDEN bir Hawaii ticari sürücüsü, bir CMV işletmekten asgari şu süreyle diskalifiye edilir:","options":["30 gün","60 gün","1 yıl","90 gün"],"explanation":"Zımni rıza yasası uyarınca gerekli testi reddetmek büyük (major) bir suç olarak değerlendirilir ve ilk DUI ile aynı asgari 1 yıllık CDL diskalifiyesini taşır (plakalı HazMat ise 3 yıl). Kaynak: HRS 286-240 ve HRS 291E-11; Hawaii CDL Manual."},"45":{"q":"Aşağıdakilerden hangisi bir Hawaii CDL sahibi için BÜYÜK (major) bir suçtur (yalnızca ciddi bir trafik ihlali değil)?","options":["Başka bir aracı çok yakından takip etmek","Sınırın 15 mph veya daha fazlası üzerinde hız yapmak","Bir suç (felony) işlemek için bir CMV kullanmak","Uygunsuz veya düzensiz bir şerit değişikliği"],"explanation":"Bir suçun (felony) işlenmesinde bir CMV kullanmak büyük (major) bir suçtur. Çok yakın takip, aşırı hız ve uygunsuz şerit değişiklikleri büyük suç değil, ciddi trafik ihlalleridir. Kaynak: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51."},"46":{"q":"Bir CMV içinde, 3 yıllık bir süre içinde ayrı olaylardan kaynaklanan İKİ ciddi trafik ihlalinden mahkum olmak, bir Hawaii CDL sahibini şu süreyle diskalifiye eder:","options":["30 gün","60 gün","120 gün","1 yıl"],"explanation":"3 yıl içinde iki ciddi trafik ihlali 60 günlük bir diskalifiye ile sonuçlanır. Kaynak: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 2."},"47":{"q":"Bir CMV içinde, 3 yıllık bir süre içinde ÜÇ ciddi trafik ihlalinden mahkum olmak, bir Hawaii CDL sahibini şu süreyle diskalifiye eder:","options":["60 gün","90 gün","120 gün","180 gün"],"explanation":"3 yıl içinde üç ciddi trafik ihlali, önceki ikisi için olan 60 günlük süreye ek olarak uygulanan 120 günlük bir diskalifiye ile sonuçlanır. Kaynak: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51 Table 2."},"48":{"q":"Bir ihlalin 'ciddi trafik ihlali' olarak sayılması için, Hawaii'de bir CMV sürücüsünün ilan edilen hız sınırının ne kadar üzerinde ceza alması gerekir?","options":["10 mph veya daha fazla","15 mph veya daha fazla","20 mph veya daha fazla","25 mph veya daha fazla"],"explanation":"İlan edilen sınırın 15 mph veya daha fazlası üzerinde aşırı hız yapmak ciddi bir trafik ihlalidir. Kaynak: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 2."},"49":{"q":"Bunlardan hangisi bir Hawaii CDL sahibi için CİDDİ bir trafik ihlali olarak sınıflandırılır?","options":["Bir CMV içinde 0.04 BAC'ye sahip olmak","Pervasız sürüş (reckless driving)","Bir kimyasal testi reddetmek","Bir kaza yerini terk etmek"],"explanation":"Pervasız sürüş (reckless driving) ciddi bir trafik ihlalidir. Diğer üçü büyük (major) suçlardır. Kaynak: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51 Tables 1 and 2."},"50":{"q":"Bir CMV'yi uygun CDL sınıfı olmadan veya CDL sürücünün üzerinde bulunmadan sürmek, Hawaii'de şu şekilde değerlendirilir:","options":["Büyük (major) suç","Ciddi trafik ihlali","Hizmet dışı (out-of-service) emri ihlali","Demiryolu geçidi ihlali"],"explanation":"Bir CMV'yi uygun lisans/onay sınıfı olmadan veya CDL üzerinde bulunmadan sürmek ciddi bir trafik ihlalidir. Kaynak: Hawaii CDL Manual (Hawaii DOT); HRS 286-240; 49 CFR 383.51 Table 2."},"51":{"q":"Hawaii CMV sürücülerine uygulanan kurallar uyarınca, araç kullanırken mesaj yazmak (texting) ve elde tutulan bir cep telefonu kullanmak şu şekilde kategorize edilir:","options":["Büyük (major) suçlar","Ciddi trafik ihlalleri","Diskalifiye olmayan ekipman ihlalleri","Hizmet dışı (out-of-service) ihlaller"],"explanation":"Bir CMV sürerken mesaj yazmak ve elde tutulan telefon kullanmak ciddi trafik ihlalleridir; 3 yıl içinde iki tanesi 60 günlük bir diskalifiye, üç tanesi 120 gün getirir. Kaynak: Hawaii CDL Manual; 49 CFR 383.51 ve 392.80/392.82 (FMCSA)."},"52":{"q":"Bir Hawaii CMV sürücüsü için, araç kullanırken mesaj yazan veya elde tutulan bir telefon kullanan bir bireysel sürücü için azami federal hukuki para cezası yaklaşık olarak şudur:","options":["$500","$1,000","$2,750","$11,000"],"explanation":"Bir sürücü, bir CMV içinde mesaj yazmak veya elde tutulan telefon kullanmak için en fazla $2,750 (enflasyona göre ayarlanmış) para cezasına çarptırılabilir; buna izin veren işverenler en fazla $11,000 ile karşı karşıya kalır. Kaynak: Hawaii'de geçerli olan FMCSA 49 CFR 392.80/392.82 ve 383.51."},"53":{"q":"Bir Hawaii CDL sahibinin, bir CMV içinde bir demiryolu-karayolu hemzemin geçit yasasına uymama nedeniyle İLK mahkumiyeti şu diskalifiye ile sonuçlanır:","options":["60 gün","120 gün","1 yıl","30 gün"],"explanation":"İlk demiryolu-karayolu hemzemin geçit ihlali, asgari 60 günlük bir diskalifiye taşır. Kaynak: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 3."},"54":{"q":"3 yıllık bir süre içinde İKİNCİ bir demiryolu-karayolu hemzemin geçit ihlali, bir Hawaii CDL sahibini en az şu süreyle diskalifiye eder:","options":["60 gün","120 gün","1 yıl","180 gün"],"explanation":"3 yıl içinde ikinci bir hemzemin geçit ihlali, asgari 120 günlük bir diskalifiye taşır. Kaynak: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51 Table 3."},"55":{"q":"3 yıllık bir süre içinde ÜÇÜNCÜ bir demiryolu-karayolu hemzemin geçit ihlali, en az şu süreyle bir diskalifiye ile sonuçlanır:","options":["120 gün","180 gün","1 yıl","3 yıl"],"explanation":"3 yıl içinde üçüncü bir hemzemin geçit ihlali, asgari 1 yıllık bir diskalifiye taşır. Kaynak: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 3."},"56":{"q":"Bir Hawaii CDL sahibinin, bir sürücü veya araç hizmet dışı (out-of-service - OOS) emrini ihlal etmesi nedeniyle İLK mahkumiyeti şu diskalifiye ile sonuçlanır:","options":["En az 30 gün","En az 90 gün","En az 180 gün (1 yıla kadar)","En az 2 yıl"],"explanation":"İlk hizmet dışı (out-of-service) emri ihlali, 180 günden 1 yıla kadar bir diskalifiye taşır (HazMat veya yolcu taşınıyorsa 180 günden 2 yıla kadar). Kaynak: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51 Table 4."},"57":{"q":"10 yıllık bir süre içinde bir CMV'de İKİNCİ bir hizmet dışı (out-of-service) emri ihlali, bir Hawaii CDL sahibini şu süreyle diskalifiye eder:","options":["180 gün ile 1 yıl","2 ile 5 yıl","1 ile 3 yıl","Ömür boyu"],"explanation":"10 yıl içinde ikinci bir OOS emri ihlali, 2 ile 5 yıl arası bir diskalifiye taşır (HazMat/yolcu için 3 ile 5 yıl). Kaynak: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 4."},"58":{"q":"Bir Hawaii diskalifiye süresi, daha önce uygulanmış bir sürenin üzerine (örneğin, önceki ikisini takip eden üçüncü bir ciddi ihlal) uygulandığında, yeni süre şöyledir:","options":["Önceki süreyle eş zamanlı (concurrently) olarak çekilir","Yarı yarıya azaltılır","Önceki süreye eklenir (ardışık - consecutively - olarak çekilir)","Bir duruşma talep edilirse feragat edilir"],"explanation":"Hawaii diskalifiye süreleri ardışık (consecutively) olarak işler: yeni uygulanan bir süre, daha önce uygulanmış herhangi bir diskalifiye süresine ek olarak gelir. Kaynak: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51."},"59":{"q":"Hawaii'nin Yol Ver (Move Over) yasasına göre, ticari bir sürücü çok şeritli bir yolda yanıp sönen ışıklar gösteren ve durmuş bir acil durum aracına yaklaştığında, yasa sürücünün aşağıdakilerden hangisini yapmasını gerektirir?","options":["Makul ve ihtiyatlı bir hıza yavaşlamak ve güvenli olduğunda acil durum aracından uzakta, bitişik olmayan bir şeride geçmek","Yazılı hız sınırını korumak ancak geçerken kornaya iki kez basmak","Acil durum aracının ışıkları kapatılana kadar banketin üzerinde tamamen durmak","Hızı yazılı sınırın tam olarak 10 mph altına düşürmek ve sağ şeritte kalmak"],"explanation":"Hawaii'nin Yol Ver yasası (HRS 291C-27), yaklaşan bir sürücünün koşullar için makul ve ihtiyatlı bir hıza yavaşlamasını ve güvenliyse acil durum aracından uzaktaki bitişik şeride geçmesini (veya iki şerit öteye geçerek arada bir şerit bırakmasını) gerektirir. Kaynak: HRS 291C-27."},"60":{"q":"Hawaii'nin Yol Ver yasası, yanıp sönen ışıklarla durmuş araçları korur. Aşağıdakilerden hangisi Hawaii kanununda korunan bir 'acil durum aracı' olarak özellikle adlandırılmıştır?","options":["Müşteri bekleyen bir taksi","Bir çekici (tow truck)","Dörtlü flaşörleri açık bir dağıtım minibüsü","Patlak lastik değiştiren bir binek otomobil"],"explanation":"HRS 291C-27, korunan acil durum araçları arasında çekicileri (tow trucks); ayrıca polis, itfaiye, EMS, okyanus güvenliği, otoyol servis devriyesi, şerif, sivil savunma, limanlar bölümü ve DLNR yaptırım araçlarını sayar. Kaynak: HRS 291C-27."},"61":{"q":"Plakartlı bir tehlikeli madde aracı veya yolcu taşıyan bir otobüs Hawaii'de bir demiryolu geçidinde durmak zorunda kaldığında, en yakın raya göre nerede durmalıdır?","options":["En yakın raydan 5 feet'ten az değil ancak 25 feet'ten fazla olmamak üzere","En yakın raydan 25 feet'ten az değil ancak 75 feet'ten fazla olmamak üzere","En yakın raydan 15 feet'ten az değil ancak 50 feet'ten fazla olmamak üzere","En yakın raydan tam olarak 30 feet uzakta"],"explanation":"Hawaii kanunu (HRS 291C-93), Hawaii CDL Kılavuzunda da yansıtıldığı üzere, aracın en yakın raydan 50 feet içinde ancak 15 feet'ten az olmamak kaydıyla durmasını, ardından her iki yöne dinleyip bakmasını gerektirir. Kaynak: HRS 291C-93; Hawaii CDL Manual."},"62":{"q":"Hawaii kanununa ve Hawaii CDL Kılavuzuna göre, görüş alanında hiçbir tren olmasa bile her demiryolu hemzemin geçidinde durmak zorunda olan araç hangisidir?","options":["Boş, açık platformlu (flatbed) bir düz kamyon","40 feet'ten uzun herhangi bir çekici-römork","Bir hizmet römorku çeken bir kamyonet","Yük olarak patlayıcı maddeler veya yanıcı sıvılar taşıyan bir araç"],"explanation":"HRS 291C-93, ücret karşılığı yolcu taşıyan araçların, çocuk taşıyan okul otobüslerinin ve yük olarak patlayıcı maddeler veya yanıcı sıvılar taşıyan araçların durmasını gerektirir. Boş veya genel yük taşıyan bir kamyon, plakartlı olmadıkça durmak zorunda değildir. Kaynak: HRS 291C-93; Hawaii CDL Manual."},"63":{"q":"Bir Hawaii CDL sürücüsü bir demiryolu geçidinde durup ardından rayların üzerinden geçmek zorunda kaldığında, yasa vites konusunda neyi gerektirir?","options":["Ön tekerlekler ilk rayın üzerine geldiğinde en düşük vitese düşürmek","Vites değişimi gerektirmeyen bir viteste geçmek ve raylar üzerindeyken vites değiştirmemek","Boş vitese alıp rayların üzerinden kayarak geçmek","Rayları hızlıca temizlemek için mümkün olan en yüksek vitesi kullanmak"],"explanation":"HRS 291C-93, sürücünün vites değiştirmeyi gerektirmeyecek bir viteste geçmesini gerektirir ve sürücü raylar üzerinden geçerken vites değiştirmemelidir. Kaynak: HRS 291C-93; Hawaii CDL Manual."},"64":{"q":"Hawaii kanununa göre, normalde bir demiryolu geçidinde durmak zorunda olan bir otobüs veya plakartlı araç, hangi durumda durmak zorunda DEĞİLDİR?","options":["Geçitte yalnızca iki ray olduğunda","Sürücü ray boyunca en az 400 feet ileriyi görebildiğinde","Bir polis memuru veya bir trafik kontrol sinyali trafiği geçmeye yönlendirdiğinde","Araç programının gerisinde kaldığında"],"explanation":"HRS 291C-93, bir polis memurunun veya çalışan bir trafik kontrol sinyalinin trafiği geçmeye yönlendirdiği yerde zorunlu durmayı muaf tutar; ayrıca bir iş veya konut bölgesi içindeki tramvay (street-railway) hemzemin geçitlerinde de uygulanmaz. Kaynak: HRS 291C-93."},"65":{"q":"Hawaii'nin okul otobüsü geçme yasası, durmuş bir otobüsün görsel sinyalleri ne tür bir ortamda etkinleştirildiğinde uygulanır?","options":["Yalnızca işaretlenmiş bir okul bölgesinde","Yalnızca 25 mph veya daha düşük hız sınırı olan yollarda","Sınırlı erişimli otoyollar dahil olmak üzere bir otobüsün durduğu her yerde","Bir konut bölgesinde"],"explanation":"HRS 291C-95, durma gerekliliğini, görsel sinyalleri etkinleştirilmiş halde bir konut bölgesindeki bir karayolu veya yolda durmuş bir okul otobüsüne bağlar. Kaynak: HRS 291C-95."},"66":{"q":"Hawaii'nin okul otobüsü yasası, çocuk indirip bindiren bir otobüs için durmanızı gerektirdiğinde, otobüsten ne kadar uzakta durmanız gerekir?","options":["Okul otobüsünden 20 feet'ten az olmamak üzere","Okul otobüsünden 10 feet'ten az olmamak üzere","Okul otobüsünden 30 feet'ten az olmamak üzere","Okul otobüsünden 50 feet'ten az olmamak üzere"],"explanation":"HRS 291C-95, otobüsün şeridindeki ve bitişik şeritlerdeki sürücülerin okul otobüsünden 20 feet'ten az olmamak üzere durmasını ve otobüs hareket edip sinyaller kapanana kadar durmuş halde kalmasını gerektirir. Birçok eyalet yalnızca 'durun' der; Hawaii 20 feet'i belirtir. Kaynak: HRS 291C-95."},"67":{"q":"Hawaii'de bölünmemiş iki şeritli bir konut yolunda, bir okul otobüsü kırmızı ışıkları yanıp sönerek ve dur kolu açık halde durur. Kimler durmak zorundadır?","options":["Yalnızca otobüsün arkasındaki trafik durmak zorundadır","Yalnızca otobüsle aynı şeritteki trafik durmak zorundadır","Her iki yöndeki trafik durmak zorundadır","Orta refüj olmadığı için kimse durmak zorunda değildir"],"explanation":"Bölünmemiş bir yolda HRS 291C-95, yönden bağımsız olarak otobüsün şeridindeki ve tüm bitişik şeritlerdeki araçlara uygulanır, dolayısıyla hem arkadaki hem de karşı yönden gelen trafik en az 20 feet uzakta durmak zorundadır. Kaynak: HRS 291C-95."},"68":{"q":"Hawaii'nin okul otobüsü yasasına göre, bölünmüş yol istisnası, durmuş bir otobüs için karşı yönden gelen trafiğin DURMADAN devam etmesine ne zaman izin verir?","options":["Yolun her yönde iki veya daha fazla şeridi olduğunda her zaman","Yolda boyalı bir orta çizgi olduğunda her zaman","Yalnızca bir geçit görevlisi trafiği geçmeye işaret ettiğinde","Otobüs ve araç, araya giren bir boşluk, fiziksel bir bariyer veya açıkça belirtilmiş bir ayırma bölümüyle ayrılmış farklı yollarda olduğunda"],"explanation":"HRS 291C-95, otobüs ve araç farklı yollarda olduğunda durma gerekliliğinin uygulanmadığını belirtir; bir konut yolu araya giren bir boşluk, fiziksel bariyer veya açıkça belirtilmiş bir ayırma bölümüyle bölünmüşse, yalnızca otobüsle aynı tarafta olan sürücüler durmak zorundadır. Kaynak: HRS 291C-95."},"69":{"q":"Hawaii'de bir okul otobüsü, dönüşümlü olarak yanıp sönen kırmızı lambalarıyla bir durma sinyali verir. Bu sinyal lambaları yasaya göre ne kadar uzaktan açıkça görülebilmelidir?","options":["Normal güneş ışığında 200 feet","Normal güneş ışığında 500 feet","Normal güneş ışığında 1.000 feet","Normal güneş ışığında 300 feet"],"explanation":"HRS 291C-95, otobüsün dört kırmızı sinyal lambasını dönüşümlü olarak yanıp sönen ve normal güneş ışığında 500 feet mesafeden açıkça görülebilen lambalar olarak tanımlar. Kaynak: HRS 291C-95."},"70":{"q":"Hawaii'nin 2024 tarihli ağır ticari araçlar için sol şerit kısıtlaması hangi araç ağırlığında uygulanır?","options":["10.000 pound veya daha fazla","5.000 pound veya daha fazla","26.001 pound veya daha fazla","80.000 pound veya daha fazla"],"explanation":"HRS 291C-55 (1 Ocak 2024 itibarıyla yürürlükte), aynı yönde üç veya daha fazla şerit bulunan yerlerde 10.000 pound veya daha ağır bir ticari aracın en sol şeridi kullanmasını yasaklar; ancak trafik akışına ayak uydurma, geçme veya sola dönme/çıkma durumları hariç. Kaynak: HRS 291C-55."},"71":{"q":"Hawaii'nin ağır araç sol şerit yasağı (2024'te yürürlükte), aynı yönde kaç şeridi olan yollarda uygulanır?","options":["Aynı yönde iki veya daha fazla şerit","Aynı yönde dört veya daha fazla şerit","Şerit sayısından bağımsız olarak herhangi bir çok şeritli yol","Aynı yönde üç veya daha fazla şerit"],"explanation":"HRS 291C-55, yalnızca bir yolun aynı yönde hareket eden trafik için üç veya daha fazla şeride sahip olduğu yerlerde uygulanır; orada 10.000 lbs veya daha ağır bir ticari araç, trafik akışına ayak uydurma, geçme veya sola dönme/çıkma dışında en sol şeridi kullanamaz. Kaynak: HRS 291C-55."},"72":{"q":"Hawaii'nin ağır ticari araçlar için sol şerit yasasına göre, en sol şeridin hangi kullanımına hâlâ izin verilir?","options":["Uzun bir iniş eğiminde sabit bir hız korumak için sol şeritte seyretmek","Aynı yönde giden başka bir aracı geçmek ve sollamak","Sağdaki sık katılan trafikten kaçınmak için solda kalmak","Trafik az olduğunda sol şeridi istediğiniz zaman kullanmak"],"explanation":"HRS 291C-55, ağır bir ticari aracın en sol şeritte yalnızca mevcut trafik akışına ayak uydururken, sollarken ve geçerken ya da sola dönmeye veya çıkmaya hazırlanırken bulunmasına izin verir. Kaynak: HRS 291C-55."},"73":{"q":"Hawaii'de çok şeritli bir karayolunda, normal trafik hızından daha yavaş giden bir ticari araç genellikle hangi şeritte seyretmelidir?","options":["Trafik akışını dengelemek için orta şerit","Katılan trafikten uzak durmak için en sol şerit","Mevcut en sağ şerit veya yolun sağ kenarına mümkün olduğunca yakın","Sinyaller kullanıldığı sürece herhangi bir şerit"],"explanation":"HRS 291C-41, normal trafik hızından daha yavaş giden bir aracın sağda kalmasını gerektirir; yani sağ şeritte veya sağ kenara mümkün olduğunca yakın seyretmelidir, geçiş yaparken veya sola dönmeye hazırlanırken hariç. Kaynak: HRS 291C-41."},"74":{"q":"Hawaii'de bir karayolu bölümü için azami hız sınırı yasal olarak nasıl belirlenir?","options":["İlçe yönetmeliğiyle veya ulaştırma müdürü tarafından yerleştirilen resmi işaretlerle","Tüm karayolları için 70 mph'lik tek sabit bir eyalet çapında azami sınırla","Yalnızca tüm eyaletler arası güzergahlar için federal hükümet tarafından","Her bir polis bölgesinin takdiriyle"],"explanation":"Hawaii'nin tek bir yasal eyalet çapında azami sınırı yoktur; HRS 291C-102 uyarınca azami (ve asgari) hız sınırı ilçe yönetmeliğiyle veya ulaştırma müdürü tarafından yerleştirilen resmi işaretlerle belirlenir ve sürücüler yazılı sınıra uymak zorundadır. Kaynak: HRS 291C-102."},"75":{"q":"Bir Hawaii CDL sürücüsünün yazılı hız sınırından bağımsız olarak uyması gereken temel hız kuralı nedir?","options":["Trafiği hareketli tutmak için her zaman en az yazılı sınırda sürmek","Her zaman yoldaki en yavaş aracın hızıyla eşleşmek","Yük taşırken her zaman yazılı sınırın 5 mph altında sürmek","Asla mevcut ve olası koşullar için makul ve ihtiyatlı olandan daha hızlı sürmemek"],"explanation":"HRS 291C-101 (temel kural), mevcut ve olası tehlikeler ve koşullar göz önüne alındığında makul ve ihtiyatlı olandan daha hızlı sürmeyi yasaklar; bir CMV'nin yağmurda, siste veya yoğun trafikte yazılı sınırın altına inmesi gerekebilir. Kaynak: HRS 291C-101."},"76":{"q":"Bir Hawaii CDL sürücüsü iki şeritli, çift yönlü bir yolda bir kamyonu durdurduktan sonra, üç yansıtıcı uyarı üçgeni nereye yerleştirilmelidir?","options":["Üçünün de aracın 50 feet arkasında bir sıra halinde yerleştirilmesi","Arkadan 10 feet içinde, aracın 200 feet arkasında ve 200 feet önünde","Arkadan 10 feet içinde, yaklaşık 100 feet arkada ve aracın yaklaşık 100 feet önünde","Biri ön tampona ve ikisi kabinin yanındaki bankete"],"explanation":"Hawaii CDL Kılavuzu (49 CFR 392.22'yi izleyerek), çift yönlü bir yolda bir üçgenin arkadan 10 feet içinde trafik tarafına, birinin yaklaşık 100 feet arkaya ve birinin yaklaşık 100 feet öne yerleştirilmesini yönlendirir. Kaynak: Hawaii CDL Manual."},"77":{"q":"Bir Hawaii CDL sürücüsü tek yönlü veya bölünmüş bir karayolunda durduğunda, uyarı üçgenleri nereye yerleştirilmelidir?","options":["Aracın 50, 100 ve 150 feet önünde eşit aralıklarla","Aracın arkasında yaklaşan trafiğe doğru yaklaşık 10 feet, 100 feet ve 200 feet'te","Biri 10 feet arkada ve ikisi bankette 500 feet arkada","Üçü de aracın arkasından 25 feet içinde"],"explanation":"Hawaii CDL Kılavuzu, tek yönlü veya bölünmüş bir karayolunda üçgenlerin yaklaşan trafiğe doğru aracın yaklaşık 10 feet, 100 feet ve 200 feet uzağına yerleştirilmesini yönlendirir. Kaynak: Hawaii CDL Manual."},"78":{"q":"Bir Hawaii CDL sürücüsü, yaklaşan trafiğin görüşünü engelleyen bir tepenin doruğunun hemen ötesinde iki şeritli bir yolda durur. Sürücü arka uyarı üçgeniyle ne yapmalıdır?","options":["Mesafeler asla değişmediği için standart 100 feet'te bırakmak","Yalnızca kamyonun 10 feet arkasında doğrudan orta çizginin üzerine yerleştirmek","Tepe zaten kamyonu gizlediği için arka üçgeni atlamak","Sürücülerin engelden önce uyarılması için arka üçgeni tepenin uzak tarafına, kamyondan 500 feet'e kadar geriye taşımak"],"explanation":"Hawaii CDL Kılavuzu, bir tepe, viraj veya başka bir engel sürücülerin kamyonu 500 feet içinde görmesini engelliyorsa, arka uyarı cihazının yol boyunca geriye (500 feet'e kadar) taşınması gerektiğini belirtir; böylece yaklaşan sürücüler yeterli uyarı alır. Kaynak: Hawaii CDL Manual."},"79":{"q":"Hawaii'de bir CDL başvuru sahibi, ticari sürücü belgesi başvurusu yapmak ve belgeyi almak için gerçekte nereye gider?","options":["Bölgesel bir FMCSA saha ofisine","İlçe sürücü belgesi ofislerinden birine (örneğin Honolulu Customer Services, Maui/Kauai Finance, Hawaii County VRLD)","Başvuruyu Honolulu'daki Hawaii DOT genel merkezine postalayarak","Eyalet çapında herhangi bir U.S. Postal Service noktasına"],"explanation":"Hawaii CDL'leri, State of Hawaii DOT Motor Vehicle Safety Office (MVSO) gözetiminde faaliyet gösteren dört ilçe sürücü belgesi ofisi aracılığıyla verilir. Kaynak: Hawaii DOT MVSO 'How to Apply for a CDL' bildirimi ve ilçe CDL sayfaları (Honolulu CSD, Maui/Kauai Finance, Hawaii County VRLD)."},"80":{"q":"Bir Hawaii CDL başvuru sahibi, sürüş türünü öz-sertifikalandırırken kaç farklı ticari faaliyet öz-sertifikasyon kategorisi arasından seçim yapmalıdır?","options":["İki","Dört","Üç","Altı"],"explanation":"Hawaii başvuru sahipleri dört kategoriden birine öz-sertifikasyon verir: Muaf olmayan eyaletler arası (Non-excepted interstate), Muaf eyaletler arası (Excepted interstate), Muaf olmayan eyalet içi (Non-excepted intrastate) veya Muaf eyalet içi (Excepted intrastate). Kaynak: Hawaii DOT MVSO CDL Medical Certification Requirements FAQ (Rev. 5/19/2025)."},"81":{"q":"Dört Hawaii öz-sertifikasyon kategorisinden hangisi bir Tıbbi Muayene Sertifikası (Form MCSA-5876) sunmayı GEREKTİRMEZ?","options":["Muaf eyaletler arası (Excepted interstate)","Muaf olmayan eyaletler arası (Non-excepted interstate)","Muaf olmayan eyalet içi (Non-excepted intrastate)","Dört kategorinin tümü MEC'yi gerektirir"],"explanation":"Hawaii MVSO FAQ'sine göre, kendilerini 'Excepted interstate' (veya muaf eyalet içi) olarak öz-sertifikalandıran sürücülerin MEC sunması gerekmez; yalnızca Non-excepted interstate ve Non-excepted intrastate sürücüleri sunmak zorundadır. Kaynak: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)."},"82":{"q":"19 Mayıs 2025'ten itibaren, muaf olmayan (Non-excepted) bir Hawaii CDL sürücüsünün Tıbbi Muayene Sertifikası (MCSA-5876) nasıl sunulmalıdır?","options":["İlçe CDL ofisine bırakılan fiziksel bir kağıt kopya olarak","Sürücü tarafından Hawaii DOT MVSO web sitesi portalına yüklenerek","Sürücünün işvereni tarafından FMCSA'ya postalanarak","Sertifikalı tıbbi muayene uzmanı aracılığıyla doğrudan FMCSA National Registry veritabanına"],"explanation":"19 Mayıs 2025 itibarıyla, HDOT ve ilçe CDL ofisleri artık fiziksel MEC kopyalarını kabul etmiyor; sertifikalı tıbbi muayene uzmanı MEC'yi doğrudan FMCSA National Registry'ye sunar ve burası verileri Hawaii'nin sürücü belgesi sistemine iletir. Kaynak: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)."},"83":{"q":"Hawaii CDL beceri testini oluşturan ve hepsi aynı randevuda geçilmesi gereken üç bölüm hangisidir?","options":["Hava frenleri, yazılı hazmat ve yolda sürüş","Yola çıkış öncesi muayene, görme taraması ve genel bilgi testi","Yola çıkış öncesi muayene, temel araç kontrolü ve yolda sürüş","Geri manevra, bağlama/ayırma ve yazılı bir onay (endorsement) sınavı"],"explanation":"Hawaii CDL beceri testinin üç bölümü vardır: yola çıkış öncesi muayene, temel araç kontrolü ve yolda sürüş testi; hepsi tek bir randevuda geçilir. Kaynak: Hawaii DOT MVSO 'How to Apply for a CDL' bildirimi ve Honolulu CSD CDL ofis sayfası."},"84":{"q":"Bir Hawaii CDL öğrenme (ticari öğrenci) izni ne kadar süre geçerlidir?","options":["Altı ay","Bir yıl","İki yıl","180 gün"],"explanation":"Hawaii'nin CDL öğrenme izni bir yıl geçerlidir ve sahibinin gözetim altında sürüş pratiği yapmasına olanak tanır. Kaynak: Hawaii DOT MVSO 'How to Apply for a CDL' bildirimi."},"85":{"q":"Bir Hawaii CLP'si verildikten sonra, sahibi CDL beceri testine girebilmek için ne kadar beklemek zorundadır?","options":["30 gün","7 gün","10 gün","14 gün"],"explanation":"Hawaii'de uygulanan federal kural, beceri testinden önce CLP'nin en az 14 gün tutulmasını gerektirir; Honolulu CSD, beceri testi randevularının izin verildikten 14 gün sonra alınabileceğini belirtir. Kaynak: Honolulu CSD CDL ofis sayfası; 49 CFR 383.25."},"86":{"q":"Bir Hawaii Class A/B CDL başvuru sahibi, CDL beceri testine girmeden ÖNCE hangi eğitimi tamamlamalıdır (7 Şubat 2022 itibarıyla yürürlükte)?","options":["Eyalet tarafından yürütülen bir savunmacı sürüş kursu","40 saatlik bir Hawaii DOT sınıf içi güvenlik semineri","Yalnızca işverene özgü bir işbaşı çıraklığı","FMCSA kayıtlı Giriş Seviyesi Sürücü Eğitimi (ELDT)"],"explanation":"7 Şubat 2022'den bu yana, ilk Class A/B CDL (ve belirli onaylar) için başvuranlar, test öncesinde FMCSA Training Provider Registry'de yer alan bir sağlayıcıyla FMCSA Entry-Level Driver Training'i tamamlamak zorundadır. Kaynak: Honolulu CSD CDL ofis sayfasında uygulandığı şekliyle FMCSA ELDT kuralı."},"87":{"q":"Tam (kısıtlamasız) bir Hawaii CDL almak için asgari yaş nedir?","options":["18","19","25","21"],"explanation":"Hawaii, tam bir CDL için başvuru sahibinin 21 yaşında olmasını gerektirir (CDL izni 18 yaşında alınabilir). Kaynak: Hawaii DOT MVSO 'How to Apply for a CDL' bildirimi ve Honolulu CSD CDL ofis sayfası."},"88":{"q":"Bir Hawaii CDL başvuru sahibinin görme testinde karşılaması gereken asgari görme standardı nedir?","options":["Her gözde 20/40 (düzeltilmiş olması kabul edilir)","Her gözde 20/20, yalnızca düzeltilmemiş","Daha iyi gözde 20/50","Her iki gözle birlikte 20/30"],"explanation":"Hawaii, CDL görme testi için düzeltici lenslere izin verilerek her gözde asgari 20/40 gerektirir. Kaynak: Honolulu CSD CDL ofis sayfası; Hawaii DOT MVSO."},"89":{"q":"Bir Hawaii CDL'sine başvururken gerekli belgelerin parçası aşağıdakilerden hangisidir?","options":["Mevcut bir nakliye işvereninden noter onaylı bir mektup","Geçerli bir temel (ticari olmayan) Hawaii sürücü belgesi ile birlikte kimlik, SSN ve ikamet kanıtı","Tek kabul edilebilir kimlik kanıtı olan bir pasaport","Üç yıllık onaylı vergi beyannameleri"],"explanation":"Hawaii CDL başvuru sahipleri geçerli bir Hawaii sürücü belgesi sunmalı ve kimlik/yaş (örneğin doğum belgesi), Social Security numarası ve ikamet kanıtı vermelidir. Kaynak: Hawaii DOT MVSO 'How to Apply for a CDL' bildirimi ve Honolulu CSD CDL ofis sayfası."},"90":{"q":"Bir Hawaii sürücüsü HEM muaf hem de muaf olmayan eyaletler arası ticarette faaliyet gösteriyorsa, hangi statüde öz-sertifikasyon vermelidir?","options":["Muaf olmayan eyaletler arası (Non-excepted interstate)","Muaf eyaletler arası (Excepted interstate)","Muaf eyalet içi (Excepted intrastate)","Her ikisi de olabilir, sürücü serbestçe seçebilir"],"explanation":"Hawaii MVSO, her iki türde de faaliyet gösteren bir sürücünün her ikisi için de yeterli kalabilmesi amacıyla 'Non-excepted interstate' seçmesini gerektirir; bu aynı zamanda bir MEC sunmayı da gerektirir. Kaynak: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)."},"91":{"q":"Elektronik MEC sunumuna geçiş sırasında, Hawaii MVSO bir CDL sürücüsünün Tıbbi Muayene Sertifikasının bir kopyasını, tıbbi muayene uzmanına sunulduktan sonra ne kadar süre taşımasını önerir?","options":["Sunumdan itibaren 30 günden fazla olmamak üzere","Sunumdan itibaren 60 günden fazla olmamak üzere","Sunumdan itibaren 15 günden fazla olmamak üzere","Tam olarak bir yıl"],"explanation":"Hawaii MVSO, olası elektronik güncelleme gecikmelerini karşılamak için MEC kopyasının tıbbi muayene uzmanına sunulduğu andan itibaren 15 günden fazla taşınmamasını önerir. Kaynak: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)."},"92":{"q":"Bir Hawaii CDL sahibinin tıbbi sertifikası süresi dolar ve yenisini sunmazlar. Tüm CDL ayrıcalıkları hangi günde kaldırılır ve bu da bir CDL ofisine bizzat gitmeyi gerektirir?","options":["54. gün","30. gün","90. gün","15. gün"],"explanation":"Hawaii MVSO'ya göre, MEC 53 gün içinde güncellenirse bizzat başvuru veya yeniden etkinleştirme ücreti gerekmez; 54. günde tüm CDL ayrıcalıkları kaldırılır ve sürücü yeniden etkinleştirme için bir CDL ofisini ziyaret etmek zorundadır. Kaynak: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)."},"93":{"q":"Bir Hawaii sürücüsünün DOT tıbbi sertifikasının süresi dolduğu anda uygunluğuna ne olur?","options":["Bir ticari motorlu taşıt kullanmaya derhal uygun olmaktan çıkarlar","90 günlük otomatik bir ödemesiz süre boyunca tam CDL ayrıcalıklarını korurlar","Bir sonraki CDL yenileme tarihine kadar hiçbir şey değişmez","Herhangi bir sağlık kartı olmadan yalnızca eyalet içi sürmeye devam edebilirler"],"explanation":"Hawaii MVSO, tıbbi sertifikanın süresi dolduğu anda sürücünün bir CMV kullanmaya uygun olmadığını belirtir; MVSO daha sonra sürücünün artık fiziksel olarak yeterli olmadığına dair bir bildirim postalar. Kaynak: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)."},"94":{"q":"Hawaii'de bir CDL sahibi ticari sürücü belgesini genellikle son kullanma tarihinden ne kadar önce yenileyebilir?","options":["Yalnızca tam son kullanma tarihinde veya sonrasında","Son kullanma tarihinden 30 gün öncesine kadar","Son kullanma tarihinden 6 ay öncesine kadar","Son kullanma tarihinden 2 yıl öncesine kadar"],"explanation":"Hawaii ilçe ofisleri (örneğin Maui), son kullanma tarihinden önceki altı (6) ay içinde CDL yenilemesine izin verir. Kaynak: Maui County 'Renewal of Commercial Drivers License' sayfası."},"95":{"q":"Bir Hawaii CDL sahibi, temel belge döngüsünden bağımsız olarak Tehlikeli Maddeler (HazMat) onayını ne sıklıkla yenilemelidir?","options":["Geçmiş kontrolü olmadan her 8 yılda bir","Yeni bir yol testiyle her 2 yılda bir","Bir TSA güvenlik tehdidi değerlendirmesi dahil olmak üzere her 5 yılda bir","Yalnızca bir kez, ilk verilişten sonra asla sona ermez"],"explanation":"Bir HazMat onayı her 5 yılda bir yenilenmelidir ve HazMat bilgi testini geçmenin yanı sıra bir TSA güvenlik tehdidi değerlendirmesini (parmak izine dayalı geçmiş kontrolü) gerektirir. Kaynak: Maui County CDL yenileme sayfası; TSA HazMat Endorsement programı; 49 CFR Part 1572."},"96":{"q":"Class 3 veya Class 4 sürücü belgesine sahip olan ve bir CMV kullanan Hawaii sürücülerinin tıbbi sertifika yükümlülüğü nedir?","options":["Class A sahipleri gibi MEC'yi FMCSA National Registry'ye sunmak zorundadırlar","MEC'yi bir tıbbi muayene uzmanına sunmazlar ancak bir CMV kullanırken bir kopyasını taşımak zorundadırlar","Tamamen muaftırlar ve hiçbir tıbbi sertifikaya ihtiyaç duymazlar","Her yıl MVSO'ya kağıt bir MEC postalamak zorundadırlar"],"explanation":"Hawaii MVSO, bir CMV kullanan Class 3/4 belge sahiplerinin MEC'yi tıbbi muayene uzmanlarına sunmadığını ancak yine de bir CMV kullanırken MEC'nin bir kopyasını taşımalarının gerektiğini belirtir. Kaynak: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)."},"97":{"q":"CDL tıbbi sertifikasyon sürecinin gözetiminden sorumlu olan ve bir öz-sertifikasyonun yönlendirildiği Hawaii kurumu hangisidir?","options":["Hawaii State Department of Health","Honolulu Police Department Traffic Division","Hawaii DOT Motor Vehicle Safety Office (MVSO)","U.S. Department of Labor"],"explanation":"Hawaii DOT Motor Vehicle Safety Office (MVSO), ilçe CDL ofisleri ve FMCSA ile birlikte çalışarak CDL tıbbi sertifikasyonunu ve öz-sertifikasyonunu yönetir. Kaynak: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)."},"98":{"q":"Hawaii'nin 49 CFR 391.46'yı izleyen güncellenmiş kurallarına göre, tıbbi sertifikasyon arayan ve düzgün şekilde kontrol altına alınmış insülinle tedavi edilen diabetes mellitus (ITDM) hastası bir sürücü için artık ne doğrudur?","options":["Sürücü, herhangi bir sertifikasyondan önce ayrı bir eyalet içi ITDM muafiyeti için yine de MVSO'ya başvurmak zorundadır","Sürücü, Hawaii'de CDL bulundurmaktan kalıcı olarak diskalifiye edilir","Sürücünün bir tıbbi muayene uzmanından değil, herhangi bir eczacıdan bir not alması yeterlidir","Sertifikalı bir tıbbi muayene uzmanı MEC'yi verebilir; ayrı bir MVSO eyalet içi ITDM muafiyeti başvurusu artık gerekli değildir"],"explanation":"Hawaii MVSO tarafından benimsenen 49 CFR 391.46 uyarınca, sertifikalı bir tıbbi muayene uzmanı, istikrarlı ve düzgün şekilde kontrol altına alınmış bir ITDM sürücüsü için (MCSA-5870 değerlendirmesini kullanarak) MEC verebilir; ayrı bir MVSO eyalet içi ITDM muafiyeti başvurusu artık gerekli değildir. Kaynak: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)."}},"es":{"0":{"q":"Según la ley de Hawái, ¿cuál es el ANCHO total máximo (incluyendo la carga) de un vehículo que puede circular por una carretera pública sin un permiso de sobredimensión?","options":["8 pies","8 pies 6 pulgadas","9 pies","10 pies"],"explanation":"El HRS §291-34 prohíbe operar un vehículo de motor cuyo ancho total, incluyendo la carga, supere los nueve pies en cualquier camino, calle o carretera pública del Estado sin un permiso. (Hawaii Revised Statutes §291-34; Hawaii CDL Manual.)"},"1":{"q":"¿Cuál es la ALTURA total máxima (incluyendo la carga) permitida para un vehículo en las carreteras de Hawái sin un permiso?","options":["13 pies","13 pies 6 pulgadas","14 pies","15 pies"],"explanation":"El HRS §291-34 establece la altura máxima del vehículo, incluyendo la carga, en catorce pies. Incluso dentro de ese límite, un vehículo no puede pasar por debajo de un puente o estructura si supera la altura libre indicada para esa estructura. (Hawaii Revised Statutes §291-34.)"},"2":{"q":"En las carreteras de Hawái, ¿cuál es el LARGO total máximo de un solo vehículo de motor (una unidad no combinada), incluyendo la carga, sin un permiso?","options":["40 pies","45 pies","53 pies","60 pies"],"explanation":"El HRS §291-34 limita un solo vehículo de motor (no una combinación) a cuarenta y cinco pies de largo total, incluyendo la carga. (Hawaii Revised Statutes §291-34.)"},"3":{"q":"Según el HRS §291-34, ¿cuál es el largo total máximo de una COMBINACIÓN de tractocamión y semirremolque, incluyendo la carga, permitida sin un permiso en Hawái?","options":["60 pies","65 pies","70 pies","75 pies"],"explanation":"El HRS §291-34 limita una combinación de tractocamión y semirremolque a sesenta y cinco pies de largo total, incluyendo la carga. (Hawaii Revised Statutes §291-34.)"},"4":{"q":"En Hawái, el peso bruto máximo impuesto sobre la carretera por un solo EJE SIMPLE no puede superar:","options":["18,000 libras","20,000 libras","22,500 libras","34,000 libras"],"explanation":"El HRS §291-35 limita el peso bruto sobre cualquier eje simple a veinte mil libras. (Hawaii Revised Statutes §291-35.)"},"5":{"q":"Un 'eje tándem' en Hawái (dos ejes consecutivos separados por más de 40 pulgadas pero no más de 96 pulgadas) puede soportar un peso bruto máximo de:","options":["32,000 libras","34,000 libras","36,000 libras","40,000 libras"],"explanation":"El HRS §291-35 limita un eje tándem (ejes separados por más de 40 pulgadas pero no más de 96 pulgadas) a treinta y cuatro mil libras. (Hawaii Revised Statutes §291-35.)"},"6":{"q":"Según la ley de pesos de Hawái, el peso bruto impuesto sobre la carretera por una sola RUEDA, ya sea de montaje simple o doble, no puede superar:","options":["8,000 libras","10,000 libras","12,000 libras","13,500 libras"],"explanation":"El HRS §291-35 limita el peso bruto sobre cualquier rueda (de montaje simple o doble) a diez mil libras. (Hawaii Revised Statutes §291-35.)"},"7":{"q":"¿Cuál es el PESO BRUTO total máximo permitido para un vehículo o combinación en las carreteras de Hawái sin un permiso de sobrepeso?","options":["73,280 libras","80,000 libras","88,000 libras","105,500 libras"],"explanation":"El HRS §291-35 limita el peso bruto vehicular total a ochenta mil libras, en concordancia con el límite federal. (Hawaii Revised Statutes §291-35.)"},"8":{"q":"Dos conjuntos consecutivos de ejes tándem pueden soportar cada uno 34,000 libras en Hawái solo si la distancia entre el primer y el último eje de los dos conjuntos tándem es de al menos:","options":["28 pies","32 pies","36 pies","40 pies"],"explanation":"El HRS §291-35 permite que dos conjuntos consecutivos de ejes tándem soporten 34,000 libras cada uno solo cuando la distancia total entre el primer y el último eje es de treinta y seis pies o más, y el peso bruto total se mantiene en 80,000 libras o menos. (Hawaii Revised Statutes §291-35.)"},"9":{"q":"La fórmula del HRS §291-35 que vincula el peso bruto permitido de un grupo de ejes con la separación y el número de ejes se basa en ¿cuál estándar federal?","options":["La Fórmula Federal de Puentes (Bridge Gross Weight Formula)","La regla de separación de ejes de CARB","El índice de carga de pavimento de AASHTO","La tabla de horas de servicio de FMCSA"],"explanation":"Las disposiciones de Hawái sobre el peso de grupos de ejes en el HRS §291-35 incorporan la Fórmula Federal de Puentes, que relaciona el peso permitido con el número de ejes y la distancia entre los ejes extremos de un grupo. (Hawaii Revised Statutes §291-35; 23 U.S.C. §127, aplicada como la regla de Hawái.)"},"10":{"q":"¿Quién tiene la autoridad para emitir un permiso por escrito que autorice el movimiento de cargas sobredimensionadas o de sobrepeso en una carretera ESTATAL de Hawái?","options":["El jefe de policía del condado","El Director de Transporte","La Comisión de Servicios Públicos","El Capitán de Puerto de Honolulu"],"explanation":"Según el HRS §291-36, el Director de Transporte emite los permisos de sobredimensión/sobrepeso para las carreteras estatales, mientras que el ingeniero del condado los emite para los caminos y calles del condado. (Hawaii Revised Statutes §291-36; HIDOT Highways Division.)"},"11":{"q":"Para los movimientos en caminos y calles del CONDADO en Hawái, ¿quién emite el permiso de sobredimensión/sobrepeso?","options":["El Director de Transporte","El ingeniero del condado","La oficina del alcalde","El Departamento de Seguridad Pública del estado"],"explanation":"El HRS §291-36 asigna la autoridad para emitir permisos en los caminos y calles del condado al ingeniero del condado (el Director de Transporte se encarga de las carreteras estatales). (Hawaii Revised Statutes §291-36.)"},"12":{"q":"¿Cómo se debe presentar una solicitud de permiso de sobredimensión/sobrepeso de Hawái?","options":["Oralmente por teléfono a la oficina del distrito","Por escrito en los formularios proporcionados por la Highways Division","Solo a través de un agente aduanal con licencia","Colocando un aviso en la estación de pesaje"],"explanation":"El HRS §291-36 exige una solicitud por escrito, y la HIDOT Highways Division requiere que se haga en los formularios que proporciona, incluyendo bocetos de la disposición de las ruedas, las dimensiones y la distribución de la carga. (Hawaii Revised Statutes §291-36; procedimientos de permisos de sobredimensión/sobrepeso de HIDOT.)"},"13":{"q":"Además de la solicitud, ¿qué exige la Highways Division de Hawái que el solicitante de un permiso de sobredimensión/sobrepeso tenga registrado?","options":["Un certificado de seguro","Una licencia de pesca comercial","Una fianza portuaria notariada","Una tarjeta de cabina IRP federal"],"explanation":"La HIDOT Highways Division exige tener registrado un certificado de seguro antes de emitir un permiso de sobredimensión/sobrepeso. (Procedimientos de permisos de Vehículos de Sobredimensión/Sobrepeso en Carreteras Estatales de HIDOT.)"},"14":{"q":"Según el calendario de tarifas de permisos de Hawái, la tarifa de un permiso de UN SOLO VIAJE para una carga de menos de 1.35 veces el peso permitido o de menos de 14 pies de ancho es:","options":["$5","$10","$25","$50"],"explanation":"Según el HRS §291-36, un permiso de un solo viaje para una carga de menos de 1.35 veces la carga permitida o de menos de 14 pies de ancho cuesta $5 (un permiso de viaje continuo en ese rango cuesta $10). (Hawaii Revised Statutes §291-36; HIDOT.)"},"15":{"q":"Según el calendario de tarifas de permisos de Hawái, la tarifa de un permiso de SOBREPESO para una carga que EXCEDE 1.35 veces la carga permitida es:","options":["$5","$10","$25","$100"],"explanation":"El HRS §291-36 establece una tarifa de $25 para un permiso de sobrepeso cuando la carga excede 1.35 veces la carga permitida; los mismos $25 se aplican a un permiso de sobredimensión que excede 14 pies de ancho. (Hawaii Revised Statutes §291-36; HIDOT.)"},"16":{"q":"En Hawái se requiere un permiso de sobredimensión de ANCHO (y conlleva la tarifa más alta de $25) una vez que el ancho de una carga excede:","options":["9 pies","10 pies","12 pies","14 pies"],"explanation":"Si bien cualquier ancho superior a 9 pies requiere un permiso, el calendario de tarifas del HRS §291-36 considera que una carga que excede 14 pies de ancho requiere la categoría de permiso de sobredimensión de $25. (Hawaii Revised Statutes §291-36; calendario de tarifas de permisos de HIDOT.)"},"17":{"q":"Según las disposiciones agrícolas de Hawái, ¿cuándo puede el Director de Transporte emitir un permiso que autorice pesos que superen los límites del HRS §291-35?","options":["Solo para vehículos propiedad del Estado","Al transportar productos cosechados desde donde se cosechan o almacenan hasta donde se procesan o utilizan","Solo entre la medianoche y las 5 a.m.","Nunca; no se permiten permisos de sobrepeso para fines agrícolas"],"explanation":"El HRS §291-36 autoriza un permiso para superar los límites de peso del §291-35 al transportar productos desde donde se cosechan o almacenan hasta donde se procesan o utilizan. (Hawaii Revised Statutes §291-36.)"},"18":{"q":"¿Qué movimiento agrícola en Hawái NO requiere ningún permiso según el HRS §291-36?","options":["Cualquier vehículo agrícola que viaje 10 millas o menos en una carretera estatal","Un vehículo utilizado en operaciones agrícolas que únicamente CRUZA un camino público en un lugar aprobado por el Director de Transporte o el ingeniero del condado","Cualquier vehículo que transporte piña sin importar el peso","Una combinación de menos de 80,000 libras que transporta café"],"explanation":"El HRS §291-36 establece que no se requiere permiso para un vehículo utilizado en operaciones agrícolas que únicamente cruza un camino, calle o carretera pública en un lugar aprobado por el Director de Transporte (carreteras estatales) o el ingeniero del condado (caminos del condado). (Hawaii Revised Statutes §291-36.)"},"19":{"q":"Si un análisis de ingeniería muestra que un puente de Hawái puede soportar de forma segura menos del peso bruto máximo establecido por ley, ¿qué puede hacer la autoridad responsable?","options":["Cerrar el puente permanentemente a todos los camiones","Colocar y mantener señales que limiten el peso bruto de los vehículos que cruzan ese puente","Aumentar el límite de peso bruto estatal para compensar","Exigir una mejora de la CDL para esa ruta"],"explanation":"El HRS §291-35 permite que el Director de Transporte (o el ingeniero del condado) coloque y mantenga señales que limiten el peso bruto sobre un puente o estructura específica cuando el análisis de ingeniería muestre que su capacidad es menor que el máximo establecido por ley; los conductores deben obedecer el límite indicado. (Hawaii Revised Statutes §291-35.)"},"20":{"q":"En Hawái, ¿qué clase de CDL se requiere para conducir cualquier combinación de vehículos con una clasificación de peso bruto combinado (GCWR) de 26,001 libras o más, cuando el o los vehículos remolcados tienen un GVWR superior a 10,000 libras?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"Hawái define una CDL de Clase A como cualquier combinación de vehículos con un GCWR de 26,001 lbs o más, siempre que el GVWR de la unidad remolcada exceda las 10,000 lbs. Fuente: HRS Sec. 286-239 y la Honolulu Commercial Driver Licensing Office. No existe una CDL 'Clase D' federal ni de Hawái."},"21":{"q":"Según la ley de Hawái, un solo vehículo con una clasificación de peso bruto vehicular (GVWR) de 26,001 libras o más (o ese mismo vehículo remolcando una unidad de no más de 10,000 libras) requiere ¿qué clase de CDL?","options":["Clase A","Clase B","Clase C","Clase M"],"explanation":"Hawái clasifica un solo vehículo con un GVWR de 26,001 lbs o más como un vehículo motorizado comercial de Clase B. Fuente: HRS Sec. 286-239; Honolulu CDL Office. La 'Clase M' es una categoría de motocicleta, no una CDL."},"22":{"q":"Un conductor de Hawái opera un vehículo de menos de 26,001 lbs de GVWR que está diseñado para transportar 16 o más pasajeros (incluido el conductor) o que lleva carteles (placards) de materiales peligrosos. ¿Qué clase de CDL aplica?","options":["Clase A","Clase B","Clase C","No se necesita CDL"],"explanation":"Una CDL de Clase C cubre los vehículos que no cumplen los requisitos de Clase A ni B, pero que están diseñados para transportar 16 o más pasajeros (incluido el conductor) o que llevan carteles (placards) de materiales peligrosos. Fuente: HRS Sec. 286-239; Honolulu CDL Office."},"23":{"q":"¿Qué código de endoso en una CDL de Hawái autoriza conducir un vehículo que transporta materiales peligrosos que requieren carteles (placards)?","options":["Endoso N","Endoso T","Endoso H","Endoso P"],"explanation":"El endoso H (HazMat) autoriza operar un vehículo que transporta materiales peligrosos con carteles (placards). Fuente: Hawaii CDL Manual / Honolulu CDL Office; 49 CFR Part 383 (adoptado por Hawái)."},"24":{"q":"En una CDL de Hawái, ¿qué endoso se requiere para conducir remolques dobles y triples?","options":["Endoso T","Endoso N","Endoso S","Endoso H"],"explanation":"El endoso T autoriza operar remolques dobles y triples. Fuente: Hawaii CDL Manual / Honolulu CDL Office; 49 CFR 383.93."},"25":{"q":"¿Qué endoso exige Hawái para conducir un vehículo cisterna (tanque), generalmente uno diseñado para transportar líquidos o gases en un tanque montado de forma permanente con una capacidad nominal superior a 1,000 galones?","options":["Endoso P","Endoso N","Endoso T","Endoso X"],"explanation":"El endoso N (Tanker / Cisterna) se requiere para los vehículos cisterna; Hawái hace referencia a tanques que exceden los 1,000 galones. Fuente: Honolulu CDL Office; 49 CFR 383.93. El código X denota una combinación de cisterna + HazMat, no solo cisterna."},"26":{"q":"¿Qué endoso debe obtener el titular de una CDL de Hawái para conducir un vehículo diseñado para transportar 16 o más pasajeros (incluido el conductor)?","options":["Endoso S","Endoso N","Endoso P","Endoso T"],"explanation":"El endoso P (Passenger / Pasajeros) se requiere para transportar 16 o más pasajeros, incluido el conductor. Fuente: Honolulu CDL Office; 49 CFR 383.93. El endoso S es específicamente para autobuses escolares."},"27":{"q":"Para conducir un autobús escolar en Hawái, el titular de una CDL debe tener el endoso S. ¿Qué endoso adicional relacionado con pasajeros también se requiere?","options":["Endoso N","Endoso T","Endoso H","Endoso P"],"explanation":"Un conductor de autobús escolar debe tener tanto el endoso S (School Bus / Autobús Escolar) como el endoso P (Passenger / Pasajeros). Fuente: Hawaii CDL Manual; 49 CFR 383.93, adoptado por Hawái."},"28":{"q":"¿Cuál es la edad mínima requerida para obtener una CDL de Hawái que autorice la conducción comercial interestatal (cruzando líneas estatales)?","options":["18 años","19 años","20 años","21 años"],"explanation":"La conducción comercial interestatal requiere una edad mínima de 21 años. La operación solo intraestatal puede permitirse a los 18 años. Fuente: Honolulu CDL Office; 49 CFR 391.11(b)."},"29":{"q":"Antes de solicitar una CDL de Hawái, un conductor primero debe obtener ¿qué credencial al aprobar el o los exámenes de conocimientos requeridos?","options":["Permiso de Aprendiz Comercial (CLP)","CDL provisional","Tarjeta temporal de HazMat","Permiso de instrucción de Clase C"],"explanation":"Los solicitantes primero deben obtener un Permiso de Aprendiz Comercial (CLP) al aprobar el o los exámenes de conocimientos antes de presentar el examen de destrezas de la CDL. Fuente: Honolulu CDL Office; 49 CFR 383.25."},"30":{"q":"Según las reglas federales adoptadas por Hawái, ¿durante cuánto tiempo debe un conductor tener un Permiso de Aprendiz Comercial antes de ser elegible para presentar el examen de destrezas de la CDL?","options":["Al menos 7 días","Al menos 14 días","Al menos 30 días","Al menos 60 días"],"explanation":"Un conductor debe tener el CLP durante al menos 14 días antes de presentar el examen de destrezas; Hawái programa el examen de destrezas no antes de 14 días después de que se emite el permiso. Fuente: Honolulu CDL Office; 49 CFR 383.25(e)."},"31":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Hawái antes de que deba renovarse?","options":["90 días","180 días","1 año","2 años"],"explanation":"Un CLP de Hawái es válido por 180 días. Fuente: Hawaii CDL Manual / guía del DMV; 49 CFR 383.25(c)."},"32":{"q":"Mientras conduce con un Permiso de Aprendiz Comercial de Hawái, el titular del permiso debe:","options":["Conducir solo durante las horas de luz del día únicamente","Ir acompañado de un titular de CDL sentado a su lado","Tener un endoso de pasajeros antes de cualquier práctica","Conducir solo en propiedad privada"],"explanation":"El titular de un CLP debe ir acompañado en todo momento por una persona que tenga una CDL válida (para la clase/endosos que se están practicando) sentada en el asiento delantero. Fuente: Hawaii CDL Manual; 49 CFR 383.25(a)."},"33":{"q":"¿Qué documento acepta la oficina emisora de CDL de Hawái como prueba de identidad y presencia legal para un solicitante ciudadano estadounidense?","options":["Una credencial de biblioteca","Un acta de nacimiento estadounidense certificada","Un registro vehicular","Únicamente un recibo de servicios públicos"],"explanation":"Hawái exige un acta de nacimiento estadounidense certificada (u otra prueba aprobada) para establecer la identidad y la presencia legal. Fuente: lista de documentos de la Honolulu CDL Office."},"34":{"q":"¿Cuántos documentos de comprobante de domicilio exige la oficina de CDL de Hawái que presente un solicitante?","options":["Ninguno","Uno","Dos","Cuatro"],"explanation":"Hawái exige dos documentos de comprobante de domicilio para establecer la residencia en Hawái para una CDL. Fuente: lista de verificación de documentos de la Honolulu CDL Office."},"35":{"q":"¿Qué documento médico debe presentar un solicitante de CDL de Hawái para certificar su aptitud física para conducir?","options":["Un Certificado de Examinador Médico del DOT vigente (MCSA-5876)","Un formulario de aprobación dental","Una declaración jurada de salud notariada","Una receta de atención primaria"],"explanation":"Los solicitantes deben presentar un examen físico del DOT / Certificado de Examinador Médico vigente (Formulario MCSA-5876). Fuente: Honolulu CDL Office; 49 CFR 391.43."},"36":{"q":"¿Qué categoría de autocertificación médica aplica a un conductor de CDL de Hawái que opera cruzando líneas estatales y está sujeto a y cumple con el requisito federal de certificado médico?","options":["Interestatal Exceptuado (Excepted Interstate)","Interestatal No Exceptuado (Non-Excepted Interstate)","Intraestatal Exceptuado (Excepted Intrastate)","Intraestatal No Exceptuado (Non-Excepted Intrastate)"],"explanation":"Un conductor en comercio interestatal que debe cumplir con el requisito federal de certificado médico de la Parte 391 se autocertifica como Non-Excepted Interstate (Interestatal No Exceptuado). Fuente: 49 CFR 383.71(b), adoptado por Hawái."},"37":{"q":"Desde el 7 de febrero de 2022, antes de presentar el examen de destrezas para una primera CDL de Clase A o B de Hawái (o un primer endoso P, S o H), un solicitante debe completar ¿qué requisito?","options":["Un historial de manejo limpio de 5 años","Capacitación de Conductor Principiante (ELDT) de FMCSA de un proveedor registrado","Un curso de manejo defensivo en cualquier escuela","Un aprendizaje de dos años"],"explanation":"El ELDT se requiere para las primeras CDL de Clase A/B y los primeros endosos P, S o H; la capacitación debe provenir de un proveedor que esté en el FMCSA Training Provider Registry. Fuente: 49 CFR Part 380 (vigente desde el 7 de febrero de 2022); Honolulu CDL Office."},"38":{"q":"Además de aprobar el examen de conocimientos de HazMat, ¿qué debe completar un solicitante de Hawái antes de que se emita el endoso H (HazMat)?","options":["Una evaluación de amenazas de seguridad de la TSA (verificación de antecedentes)","Un examen práctico en un vehículo cisterna","Una inspección de emisiones","Un curso de seguridad náutica"],"explanation":"La ley federal exige que todo solicitante del endoso HazMat apruebe una evaluación de amenazas de seguridad de la TSA (verificación de antecedentes con toma de huellas digitales) antes de la emisión, además del examen de conocimientos y el ELDT. Fuente: 49 CFR 1572 (TSA); 49 CFR 383.141; Hawaii CDL Office."},"39":{"q":"En Hawái, una persona comete una infracción mayor que conlleva descalificación al operar un vehículo motorizado comercial (CMV) con una concentración de alcohol en la sangre (BAC) de al menos ¿qué nivel?","options":["0.02","0.04","0.08","0.10"],"explanation":"Hawái establece el límite de alcohol para CMV en 0.04 de BAC, la mitad del límite de 0.08 para conductores comunes. Operar un CMV con 0.04 o más es una infracción mayor. Fuente: Hawaii CDL Manual (Hawaii DOT) y HRS 286-240; 49 CFR 383.51."},"40":{"q":"Según la ley de consentimiento implícito de Hawái, al conducir por las carreteras del estado se considera que un conductor comercial ha dado su consentimiento ¿para qué?","options":["Una inspección del vehículo en cualquier estación de pesaje","Una prueba de aliento, sangre u orina para detectar alcohol o drogas si es arrestado","Un registro de la cabina sin orden judicial","Un examen de recertificación médica cada año"],"explanation":"La ley de consentimiento implícito de Hawái considera que todo conductor ha consentido a una prueba de aliento, sangre u orina para determinar la concentración de alcohol o el contenido de drogas cuando es arrestado legalmente. Fuente: HRS 291E-11 (consentimiento implícito); Hawaii CDL Manual."},"41":{"q":"Un titular de CDL de Hawái es condenado por una primera infracción mayor (como conducir bajo los efectos del alcohol en un CMV) cuando NO transporta materiales peligrosos con carteles (placards). El período mínimo de descalificación es:","options":["60 días","120 días","1 año","3 años"],"explanation":"Una primera infracción mayor conlleva una descalificación mínima de 1 año de la CDL en Hawái. Fuente: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 1."},"42":{"q":"Si la primera infracción mayor ocurre mientras el conductor opera un CMV que transporta materiales peligrosos que requieren carteles (placards), el período de descalificación aumenta a:","options":["1 año","18 meses","3 años","5 años"],"explanation":"Una primera infracción mayor cometida mientras se transportan materiales peligrosos con carteles (placards) eleva la descalificación de 1 año a 3 años. Fuente: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51 Table 1."},"43":{"q":"¿Cuál es el período de descalificación en Hawái para una SEGUNDA infracción mayor (cometida en un CMV) durante la vida del conductor?","options":["3 años","5 años","10 años","De por vida (life)"],"explanation":"Una segunda infracción mayor resulta en una descalificación de por vida de la CDL en Hawái. Fuente: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 1."},"44":{"q":"Un conductor comercial de Hawái que SE NIEGA a someterse a la prueba requerida de alcohol/drogas queda descalificado para operar un CMV por un mínimo de:","options":["30 días","60 días","1 año","90 días"],"explanation":"Negarse a la prueba requerida bajo la ley de consentimiento implícito se trata como una infracción mayor, conllevando la misma descalificación mínima de 1 año de la CDL que un primer DUI (3 años si transporta HazMat con carteles/placards). Fuente: HRS 286-240 y HRS 291E-11; Hawaii CDL Manual."},"45":{"q":"¿Cuál de las siguientes es una infracción MAYOR (no simplemente una infracción de tránsito grave) para un titular de CDL de Hawái?","options":["Seguir a otro vehículo demasiado de cerca","Exceder el límite de velocidad por 15 mph o más","Usar un CMV para cometer un delito grave (felony)","Un cambio de carril indebido o errático"],"explanation":"Usar un CMV en la comisión de un delito grave (felony) es una infracción mayor. Seguir demasiado de cerca, el exceso de velocidad y los cambios de carril indebidos son infracciones de tránsito graves, no infracciones mayores. Fuente: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51."},"46":{"q":"La condena por DOS infracciones de tránsito graves en un CMV, derivadas de incidentes separados dentro de un período de 3 años, descalifica a un titular de CDL de Hawái por:","options":["30 días","60 días","120 días","1 año"],"explanation":"Dos infracciones de tránsito graves dentro de 3 años resultan en una descalificación de 60 días. Fuente: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 2."},"47":{"q":"La condena por TRES infracciones de tránsito graves en un CMV dentro de un período de 3 años descalifica a un titular de CDL de Hawái por:","options":["60 días","90 días","120 días","180 días"],"explanation":"Tres infracciones de tránsito graves dentro de 3 años resultan en una descalificación de 120 días, que se cumple además del período de 60 días por las dos anteriores. Fuente: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51 Table 2."},"48":{"q":"¿Por cuánto debe un conductor de CMV exceder el límite de velocidad indicado en Hawái para que la infracción cuente como una 'infracción de tránsito grave'?","options":["10 mph o más","15 mph o más","20 mph o más","25 mph o más"],"explanation":"El exceso de velocidad de 15 mph o más sobre el límite indicado es una infracción de tránsito grave. Fuente: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 2."},"49":{"q":"¿Cuál de estas se clasifica como una infracción de tránsito GRAVE para un titular de CDL de Hawái?","options":["Tener un BAC de 0.04 en un CMV","Conducción imprudente (reckless driving)","Negarse a una prueba química","Abandonar la escena de un accidente"],"explanation":"La conducción imprudente (reckless driving) es una infracción de tránsito grave. Las otras tres son infracciones mayores. Fuente: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51 Tables 1 and 2."},"50":{"q":"Conducir un CMV sin la clase adecuada de CDL o sin la CDL en posesión del conductor se trata en Hawái como una:","options":["Infracción mayor","Infracción de tránsito grave","Violación de una orden de fuera de servicio (out-of-service)","Violación de cruce ferroviario"],"explanation":"Conducir un CMV sin la clase adecuada de licencia/endoso, o sin la CDL en posesión, es una infracción de tránsito grave. Fuente: Hawaii CDL Manual (Hawaii DOT); HRS 286-240; 49 CFR 383.51 Table 2."},"51":{"q":"Según las reglas que aplican a los conductores de CMV de Hawái, enviar mensajes de texto mientras se conduce y usar un teléfono móvil de mano se categorizan como:","options":["Infracciones mayores","Infracciones de tránsito graves","Infracciones de equipo sin descalificación","Violaciones de fuera de servicio (out-of-service)"],"explanation":"Enviar mensajes de texto y usar un teléfono de mano mientras se conduce un CMV son infracciones de tránsito graves; dos en 3 años conllevan una descalificación de 60 días y tres conllevan 120 días. Fuente: Hawaii CDL Manual; 49 CFR 383.51 y 392.80/392.82 (FMCSA)."},"52":{"q":"Para un conductor de CMV de Hawái, la sanción civil federal máxima para un conductor individual que envía mensajes de texto o usa un teléfono de mano mientras conduce es aproximadamente:","options":["$500","$1,000","$2,750","$11,000"],"explanation":"Un conductor puede ser multado con hasta $2,750 (ajustado por inflación) por enviar mensajes de texto o usar un teléfono de mano en un CMV; los empleadores que lo permiten enfrentan hasta $11,000. Fuente: FMCSA 49 CFR 392.80/392.82 y 383.51, aplicable en Hawái."},"53":{"q":"La PRIMERA condena de un titular de CDL de Hawái por no obedecer una ley de cruce ferroviario a nivel (railroad-highway grade crossing) en un CMV resulta en una descalificación de:","options":["60 días","120 días","1 año","30 días"],"explanation":"Una primera infracción de cruce ferroviario a nivel conlleva una descalificación mínima de 60 días. Fuente: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 3."},"54":{"q":"Una SEGUNDA infracción de cruce ferroviario a nivel (railroad-highway grade crossing) dentro de un período de 3 años descalifica a un titular de CDL de Hawái por al menos:","options":["60 días","120 días","1 año","180 días"],"explanation":"Una segunda infracción de cruce a nivel dentro de 3 años conlleva una descalificación mínima de 120 días. Fuente: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51 Table 3."},"55":{"q":"Una TERCERA infracción de cruce ferroviario a nivel (railroad-highway grade crossing) dentro de un período de 3 años resulta en una descalificación de al menos:","options":["120 días","180 días","1 año","3 años"],"explanation":"Una tercera infracción de cruce a nivel dentro de 3 años conlleva una descalificación mínima de 1 año. Fuente: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 3."},"56":{"q":"La PRIMERA condena de un titular de CDL de Hawái por violar una orden de fuera de servicio (OOS) de conductor o de vehículo resulta en una descalificación de:","options":["Al menos 30 días","Al menos 90 días","Al menos 180 días (hasta 1 año)","Al menos 2 años"],"explanation":"Una primera violación de una orden de fuera de servicio conlleva una descalificación de 180 días hasta 1 año (de 180 días a 2 años si se transporta HazMat o pasajeros). Fuente: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51 Table 4."},"57":{"q":"Una SEGUNDA violación de una orden de fuera de servicio (out-of-service) en un CMV dentro de un período de 10 años descalifica a un titular de CDL de Hawái por:","options":["180 días a 1 año","2 a 5 años","1 a 3 años","De por vida"],"explanation":"Una segunda violación de orden OOS dentro de 10 años conlleva una descalificación de 2 a 5 años (de 3 a 5 años para HazMat/pasajeros). Fuente: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 4."},"58":{"q":"Cuando se impone un período de descalificación en Hawái además de un período impuesto previamente (por ejemplo, una tercera infracción grave que sigue a las dos anteriores), el nuevo período se:","options":["Cumple de forma concurrente con el período anterior","Reduce a la mitad","Suma (se cumple de forma consecutiva) al período anterior","Anula si se solicita una audiencia"],"explanation":"Los períodos de descalificación de Hawái se cumplen de forma consecutiva: un período recién impuesto se suma a cualquier período de descalificación impuesto previamente. Fuente: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51."},"59":{"q":"Según la ley de \"Cambia de carril\" (Move Over) de Hawái, cuando un conductor comercial se aproxima a un vehículo de emergencia detenido que muestra luces intermitentes en una carretera de varios carriles, ¿qué le exige hacer la ley?","options":["Reducir a una velocidad razonable y prudente y, cuando sea seguro, cambiarse a un carril no adyacente, alejándose del vehículo de emergencia","Mantener la velocidad indicada pero tocar la bocina dos veces al pasar","Detenerse por completo en el acotamiento hasta que se apaguen las luces del vehículo de emergencia","Reducir la velocidad exactamente 10 mph por debajo del límite indicado y permanecer en el carril derecho"],"explanation":"La ley de \"Cambia de carril\" de Hawái (HRS 291C-27) exige que el conductor que se aproxima reduzca a una velocidad razonable y prudente para las condiciones y, si es seguro, se cambie al carril adyacente alejándose del vehículo de emergencia (o dos carriles más allá, dejando un carril de por medio). Fuente: HRS 291C-27."},"60":{"q":"La ley de \"Cambia de carril\" de Hawái protege a los vehículos detenidos con luces intermitentes. ¿Cuál de los siguientes se menciona específicamente como un \"vehículo de emergencia\" protegido en el estatuto de Hawái?","options":["Un taxi esperando un pasajero","Una grúa de remolque","Una camioneta de reparto con las luces de emergencia encendidas","Un automóvil de pasajeros cambiando una llanta ponchada"],"explanation":"El HRS 291C-27 incluye a las grúas de remolque entre los vehículos de emergencia protegidos, junto con vehículos de policía, bomberos, servicios médicos de emergencia (EMS), seguridad oceánica, patrulla de servicio de autopistas, alguacil (sheriff), defensa civil, división de puertos y de aplicación de la ley del DLNR. Fuente: HRS 291C-27."},"61":{"q":"Cuando un vehículo con placardas de materiales peligrosos o un autobús que transporta pasajeros debe detenerse en un cruce de ferrocarril en Hawái, ¿dónde debe detenerse con respecto al riel más cercano?","options":["A no menos de 5 pies pero no más de 25 pies del riel más cercano","A no menos de 25 pies pero no más de 75 pies del riel más cercano","A no menos de 15 pies pero no más de 50 pies del riel más cercano","Exactamente a 30 pies del riel más cercano"],"explanation":"La ley de Hawái (HRS 291C-93), reflejada en el Manual de CDL de Hawái, exige que el vehículo se detenga dentro de 50 pies pero no menos de 15 pies del riel más cercano, y luego escuche y mire en ambas direcciones. Fuente: HRS 291C-93; Manual de CDL de Hawái."},"62":{"q":"De acuerdo con la ley de Hawái y el Manual de CDL de Hawái, ¿qué vehículo está obligado a detenerse en cada cruce a nivel de ferrocarril incluso cuando no hay ningún tren a la vista?","options":["Un camión recto de plataforma vacío","Cualquier tractocamión con remolque de más de 40 pies de largo","Una camioneta pickup que remolca un tráiler de servicio","Un vehículo que transporta sustancias explosivas o líquidos inflamables como carga"],"explanation":"El HRS 291C-93 exige que los vehículos que transportan pasajeros por contratación, los autobuses escolares que transportan niños y los vehículos que transportan sustancias explosivas o líquidos inflamables como carga se detengan. Un camión vacío o de carga general no está obligado a detenerse a menos que lleve placardas. Fuente: HRS 291C-93; Manual de CDL de Hawái."},"63":{"q":"Cuando un conductor con CDL de Hawái debe detenerse en un cruce de ferrocarril y luego cruzar las vías, ¿qué exige la ley con respecto a los cambios de marcha?","options":["Reducir a la marcha más baja una vez que las ruedas delanteras estén sobre el primer riel","Cruzar en una marcha que no requiera cambiar de velocidad, y no cambiar de marcha mientras se está sobre las vías","Poner el cambio en neutral y cruzar las vías por inercia","Usar la marcha más alta posible para despejar las vías rápidamente"],"explanation":"El HRS 291C-93 exige que el conductor cruce en una marcha que no requiera cambiar de velocidad, y el conductor no debe cambiar de marcha mientras cruza las vías. Fuente: HRS 291C-93; Manual de CDL de Hawái."},"64":{"q":"Según la ley de Hawái, un autobús o vehículo con placardas que normalmente debe detenerse en un cruce de ferrocarril NO está obligado a detenerse en cuál de las siguientes situaciones?","options":["Cuando el cruce tiene solo dos vías","Cuando el conductor puede ver al menos 400 pies a lo largo de la vía","Cuando un oficial de policía o una señal de control de tránsito indica al tráfico que continúe","Cuando el vehículo está retrasado con respecto a su horario"],"explanation":"El HRS 291C-93 exime de la parada obligatoria cuando un oficial de policía o una señal de control de tránsito en funcionamiento indica al tráfico que continúe; tampoco se aplica en los cruces a nivel de tranvía dentro de un distrito comercial o residencial. Fuente: HRS 291C-93."},"65":{"q":"La ley de Hawái sobre rebasar autobuses escolares se aplica cuando un autobús detenido tiene sus señales visuales activadas, ¿en qué entorno?","options":["Solo en una zona escolar señalizada","Solo en carreteras con límite de 25 mph o menos","En cualquier lugar donde un autobús se detenga, incluidas las autopistas de acceso limitado","En una zona residencial"],"explanation":"El HRS 291C-95 vincula el requisito de detenerse a un autobús escolar detenido en una carretera o camino en una zona residencial con sus señales visuales activadas. Fuente: HRS 291C-95."},"66":{"q":"Cuando la ley de autobuses escolares de Hawái te exige detenerte ante un autobús que sube o baja niños, ¿a qué distancia del autobús debes detenerte?","options":["A no menos de 20 pies del autobús escolar","A no menos de 10 pies del autobús escolar","A no menos de 30 pies del autobús escolar","A no menos de 50 pies del autobús escolar"],"explanation":"El HRS 291C-95 exige que los conductores en el carril del autobús y en los carriles adyacentes se detengan a no menos de 20 pies del autobús escolar y permanezcan detenidos hasta que el autobús reanude la marcha y las señales se apaguen. Muchos estados simplemente dicen \"detenerse\"; Hawái especifica 20 pies. Fuente: HRS 291C-95."},"67":{"q":"En un camino residencial de dos carriles sin división en Hawái, un autobús escolar se detiene con las luces rojas intermitentes y el brazo de alto extendido. ¿Quién debe detenerse?","options":["Solo el tráfico detrás del autobús debe detenerse","Solo el tráfico en el mismo carril que el autobús debe detenerse","El tráfico en ambas direcciones debe detenerse","Nadie debe detenerse porque no hay camellón"],"explanation":"En una carretera sin división, el HRS 291C-95 se aplica a los vehículos en el carril del autobús y en todos los carriles adyacentes sin importar la dirección, de modo que tanto el tráfico que viene atrás como el que viene de frente deben detenerse a por lo menos 20 pies. Fuente: HRS 291C-95."},"68":{"q":"Según la ley de autobuses escolares de Hawái, ¿cuándo permite la excepción de carretera dividida que el tráfico en sentido contrario continúe SIN detenerse ante un autobús detenido?","options":["Siempre que la carretera tenga dos o más carriles en cada dirección","Siempre que la carretera tenga una línea central pintada","Solo cuando un guardia de cruce indica al tráfico que pase","Cuando el autobús y el vehículo están en calzadas diferentes separadas por un espacio intermedio, una barrera física o una sección divisoria claramente indicada"],"explanation":"El HRS 291C-95 establece que el requisito de detenerse no se aplica cuando el autobús y el vehículo están en calzadas diferentes; cuando un camino residencial está dividido por un espacio intermedio, una barrera física o una sección divisoria claramente indicada, solo los conductores del mismo lado que el autobús deben detenerse. Fuente: HRS 291C-95."},"69":{"q":"Un autobús escolar en Hawái señala una parada con sus luces rojas intermitentes alternas. ¿A qué distancia deben ser claramente visibles esas luces de señalización según la ley?","options":["200 pies bajo luz solar normal","500 pies bajo luz solar normal","1,000 pies bajo luz solar normal","300 pies bajo luz solar normal"],"explanation":"El HRS 291C-95 describe las cuatro luces de señalización rojas del autobús como intermitentes alternas y claramente visibles a una distancia de 500 pies bajo luz solar normal. Fuente: HRS 291C-95."},"70":{"q":"La restricción del carril izquierdo de 2024 de Hawái para vehículos comerciales pesados se aplica, ¿a partir de qué peso del vehículo?","options":["10,000 libras o más","5,000 libras o más","26,001 libras o más","80,000 libras o más"],"explanation":"El HRS 291C-55 (vigente desde el 1 de enero de 2024) prohíbe que un vehículo comercial que pesa 10,000 libras o más use el carril del extremo izquierdo donde hay tres o más carriles en la misma dirección, salvo para mantener el ritmo del tráfico, rebasar o girar/salir a la izquierda. Fuente: HRS 291C-55."},"71":{"q":"La prohibición de Hawái sobre el carril izquierdo para vehículos pesados (vigente en 2024) se aplica en calzadas con cuántos carriles en la misma dirección?","options":["Dos o más carriles en la misma dirección","Cuatro o más carriles en la misma dirección","Cualquier carretera de varios carriles, sin importar la cantidad de carriles","Tres o más carriles en la misma dirección"],"explanation":"El HRS 291C-55 se aplica solo cuando una calzada tiene tres o más carriles para el tráfico que circula en la misma dirección; allí, un vehículo comercial de 10,000 lbs o más no puede usar el carril del extremo izquierdo salvo para mantener el ritmo del tráfico, rebasar o girar/salir a la izquierda. Fuente: HRS 291C-55."},"72":{"q":"Según la ley del carril izquierdo de Hawái para vehículos comerciales pesados, ¿qué uso del carril del extremo izquierdo todavía está permitido?","options":["Circular por el carril izquierdo para mantener una velocidad constante en una pendiente larga de bajada","Alcanzar y rebasar a otro vehículo que circula en la misma dirección","Permanecer a la izquierda para evitar el tráfico que se incorpora frecuentemente por la derecha","Usar el carril izquierdo en cualquier momento en que haya poco tráfico"],"explanation":"El HRS 291C-55 permite que un vehículo comercial pesado esté en el carril del extremo izquierdo solo cuando mantiene el ritmo del flujo de tráfico existente, alcanza y rebasa, o se prepara para girar a la izquierda o salir. Fuente: HRS 291C-55."},"73":{"q":"En una carretera de varios carriles de Hawái, un vehículo comercial que circula más lento que la velocidad normal del tráfico generalmente debe transitar, ¿en qué carril?","options":["El carril central para equilibrar el flujo de tráfico","El carril del extremo izquierdo para mantenerse fuera del tráfico que se incorpora","El carril de la derecha disponible, o lo más cerca posible del borde derecho de la calzada","Cualquier carril, siempre que se usen las direccionales"],"explanation":"El HRS 291C-41 exige que un vehículo que circula más lento que la velocidad normal del tráfico se mantenga a la derecha —en el carril de la derecha o lo más cerca posible del borde derecho— salvo cuando rebasa o se prepara para girar a la izquierda. Fuente: HRS 291C-41."},"74":{"q":"¿Cómo se establece legalmente el límite máximo de velocidad para un tramo de carretera de Hawái?","options":["Por ordenanza del condado o por señales oficiales colocadas por el director de transporte","Por un único máximo fijo estatal de 70 mph para todas las carreteras","Por el gobierno federal, solo para todas las rutas interestatales","Por la discreción de cada distrito policial individual"],"explanation":"Hawái no tiene un único máximo estatal establecido por ley; según el HRS 291C-102, el límite máximo (y mínimo) de velocidad se establece por ordenanza del condado o por señales oficiales colocadas por el director de transporte, y los conductores deben obedecer el límite indicado. Fuente: HRS 291C-102."},"75":{"q":"¿Cuál es la regla básica de velocidad que un conductor con CDL de Hawái debe seguir, sin importar el límite indicado?","options":["Conducir siempre al menos al límite indicado para mantener el tráfico en movimiento","Igualar en todo momento la velocidad del vehículo más lento en la carretera","Conducir 5 mph por debajo del límite indicado siempre que se transporte carga","Nunca conducir más rápido de lo razonable y prudente para las condiciones reales y potenciales"],"explanation":"El HRS 291C-101 (la regla básica) prohíbe conducir más rápido de lo razonable y prudente dados los peligros y condiciones reales y potenciales; un CMV puede necesitar ir por debajo del límite indicado en lluvia, niebla o tráfico denso. Fuente: HRS 291C-101."},"76":{"q":"Después de que un conductor con CDL de Hawái detiene un camión en un camino de dos carriles y doble sentido, ¿dónde deben colocarse los tres triángulos reflectantes de advertencia?","options":["Los tres colocados en fila a 50 pies detrás del vehículo","Dentro de los 10 pies de la parte trasera, a 200 pies detrás y a 200 pies delante del vehículo","Dentro de los 10 pies de la parte trasera, a unos 100 pies detrás y a unos 100 pies delante del vehículo","Uno en la defensa delantera y dos en el acotamiento junto a la cabina"],"explanation":"El Manual de CDL de Hawái (que sigue el 49 CFR 392.22) indica que, en un camino de doble sentido, se coloque un triángulo dentro de los 10 pies de la parte trasera del lado del tráfico, uno a unos 100 pies hacia atrás y uno a unos 100 pies hacia adelante. Fuente: Manual de CDL de Hawái."},"77":{"q":"Cuando un conductor con CDL de Hawái se detiene en una carretera de sentido único o dividida, ¿dónde deben colocarse los triángulos de advertencia?","options":["Espaciados de manera uniforme a 50, 100 y 150 pies delante del vehículo","A unos 10 pies, 100 pies y 200 pies hacia el tráfico que se aproxima por detrás del vehículo","Uno a 10 pies detrás y dos a 500 pies detrás en el acotamiento","Los tres dentro de los 25 pies de la parte trasera del vehículo"],"explanation":"El Manual de CDL de Hawái indica que en una carretera de sentido único o dividida los triángulos van hacia el tráfico que se aproxima, a unos 10 pies, 100 pies y 200 pies del vehículo. Fuente: Manual de CDL de Hawái."},"78":{"q":"Un conductor con CDL de Hawái se detiene en un camino de dos carriles justo después de la cima de una colina que bloquea la visibilidad del tráfico que se aproxima. ¿Qué debe hacer el conductor con el triángulo de advertencia trasero?","options":["Dejarlo a los 100 pies estándar porque las distancias nunca cambian","Colocarlo directamente sobre la línea central solo a 10 pies detrás del camión","Omitir el triángulo trasero ya que la colina de por sí oculta el camión","Mover el triángulo trasero hacia el otro lado de la colina, hasta 500 pies del camión, para advertir a los conductores antes de la obstrucción"],"explanation":"El Manual de CDL de Hawái establece que si una colina, una curva u otra obstrucción impide que los conductores vean el camión dentro de 500 pies, el dispositivo de advertencia trasero debe moverse hacia atrás por el camino —hasta 500 pies— para que los conductores que se aproximan reciban una advertencia adecuada. Fuente: Manual de CDL de Hawái."},"79":{"q":"En Hawái, ¿a dónde acude realmente un solicitante de CDL para solicitar y obtener una licencia de conducir comercial?","options":["A una oficina regional de la FMCSA","A una de las oficinas de licencias de conducir del condado (p. ej., Honolulu Customer Services, Maui/Kauai Finance, Hawaii County VRLD)","Enviando por correo la solicitud a la sede del Hawaii DOT en Honolulu","En cualquier sucursal del Servicio Postal de EE. UU. en todo el estado"],"explanation":"Las CDL de Hawái se emiten a través de las cuatro oficinas de licencias de conducir del condado, que operan bajo la supervisión de la State of Hawaii DOT Motor Vehicle Safety Office (MVSO). Fuente: aviso \"How to Apply for a CDL\" del Hawaii DOT MVSO y páginas de CDL de los condados (Honolulu CSD, Maui/Kauai Finance, Hawaii County VRLD)."},"80":{"q":"¿Entre cuántas categorías distintas de autocertificación de operación comercial debe elegir un solicitante de CDL de Hawái al autocertificar su tipo de conducción?","options":["Dos","Cuatro","Tres","Seis"],"explanation":"Los solicitantes de Hawái se autocertifican en una de cuatro categorías: interestatal no exceptuada (Non-excepted interstate), interestatal exceptuada (Excepted interstate), intraestatal no exceptuada (Non-excepted intrastate) o intraestatal exceptuada (Excepted intrastate). Fuente: Hawaii DOT MVSO CDL Medical Certification Requirements FAQ (Rev. 5/19/2025)."},"81":{"q":"¿Cuál de las cuatro categorías de autocertificación de Hawái NO requiere presentar un Certificado del Examinador Médico (Formulario MCSA-5876)?","options":["Interestatal exceptuada (Excepted interstate)","Interestatal no exceptuada (Non-excepted interstate)","Intraestatal no exceptuada (Non-excepted intrastate)","Las cuatro categorías requieren el MEC"],"explanation":"Según las preguntas frecuentes (FAQ) del Hawaii MVSO, los conductores que se autocertifican como \"Excepted interstate\" (o intraestatal exceptuada) no están obligados a presentar un MEC; solo los conductores Non-excepted interstate y Non-excepted intrastate deben hacerlo. Fuente: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)."},"82":{"q":"A partir del 19 de mayo de 2025, ¿cómo debe presentarse el Certificado del Examinador Médico (MCSA-5876) de un conductor con CDL no exceptuado de Hawái?","options":["Como copia física en papel entregada en la oficina de CDL del condado","Subido por el conductor al portal del sitio web del Hawaii DOT MVSO","Enviado por correo por el empleador del conductor a la FMCSA","Directamente a la base de datos del FMCSA National Registry a través del examinador médico certificado"],"explanation":"A partir del 19 de mayo de 2025, el HDOT y las oficinas de CDL del condado ya no aceptan copias físicas del MEC; el examinador médico certificado presenta el MEC directamente al FMCSA National Registry, que transmite los datos al sistema de licencias de conducir de Hawái. Fuente: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)."},"83":{"q":"¿Cuáles son las tres partes que componen la prueba de habilidades de la CDL de Hawái, todas las cuales deben aprobarse en la misma cita?","options":["Frenos de aire, examen escrito de hazmat y conducción en carretera","Inspección previa al viaje, examen de la vista y examen de conocimientos generales","Inspección previa al viaje, control básico del vehículo y conducción en carretera","Reversa, acople/desacople y un examen escrito de endoso"],"explanation":"La prueba de habilidades de la CDL de Hawái tiene tres partes: inspección previa al viaje, control básico del vehículo y la prueba de conducción en carretera, todas aprobadas en una sola cita. Fuente: aviso \"How to Apply for a CDL\" del Hawaii DOT MVSO y página de la oficina de CDL de Honolulu CSD."},"84":{"q":"¿Por cuánto tiempo es válido un permiso de instrucción (de aprendiz comercial) de CDL de Hawái?","options":["Seis meses","Un año","Dos años","180 días"],"explanation":"El permiso de instrucción de CDL de Hawái es válido por un año y permite al titular practicar la conducción bajo supervisión. Fuente: aviso \"How to Apply for a CDL\" del Hawaii DOT MVSO."},"85":{"q":"Después de que se emite un CLP de Hawái, ¿cuánto tiempo debe esperar el titular antes de poder presentar la prueba de habilidades de la CDL?","options":["30 días","7 días","10 días","14 días"],"explanation":"La regla federal aplicada en Hawái exige tener el CLP durante al menos 14 días antes de la prueba de habilidades; Honolulu CSD señala que las citas para la prueba de habilidades pueden hacerse 14 días después de emitido el permiso. Fuente: página de la oficina de CDL de Honolulu CSD; 49 CFR 383.25."},"86":{"q":"¿Qué capacitación debe completar un solicitante de CDL Clase A/B de Hawái ANTES de presentar la prueba de habilidades de la CDL (vigente desde el 7 de febrero de 2022)?","options":["Un curso de manejo defensivo administrado por el estado","Un seminario de seguridad en aula de 40 horas del Hawaii DOT","Un aprendizaje en el trabajo exclusivo del empleador","Capacitación de Conductor de Nivel Inicial (ELDT) registrada ante la FMCSA"],"explanation":"Desde el 7 de febrero de 2022, los solicitantes de una CDL Clase A/B inicial (y ciertos endosos) deben completar la Entry-Level Driver Training (ELDT) de la FMCSA con un proveedor que esté en el FMCSA Training Provider Registry antes de hacer la prueba. Fuente: regla ELDT de la FMCSA según la aplica la página de la oficina de CDL de Honolulu CSD."},"87":{"q":"¿Cuál es la edad mínima para obtener una CDL de Hawái completa (sin restricciones)?","options":["18","19","25","21"],"explanation":"Hawái exige que el solicitante tenga 21 años para una CDL completa (se puede obtener un permiso de CDL a los 18). Fuente: aviso \"How to Apply for a CDL\" del Hawaii DOT MVSO y página de la oficina de CDL de Honolulu CSD."},"88":{"q":"¿Cuál es el estándar mínimo de visión que un solicitante de CDL de Hawái debe cumplir en el examen de la vista?","options":["20/40 en cada ojo (se acepta corregida)","20/20 en cada ojo, solo sin corrección","20/50 en el ojo con mejor visión","20/30 combinada con ambos ojos"],"explanation":"Hawái exige un mínimo de 20/40 en cada ojo, con lentes correctivos permitidos, para el examen de la vista de la CDL. Fuente: página de la oficina de CDL de Honolulu CSD; Hawaii DOT MVSO."},"89":{"q":"¿Cuál de estos forma parte de la documentación requerida al solicitar una CDL de Hawái?","options":["Una carta notariada de un empleador actual de transporte de carga","Una licencia de conducir básica (no comercial) de Hawái válida, además de comprobante de identidad, número de Seguro Social y residencia","Un pasaporte que es el único comprobante de identidad aceptable","Tres años de declaraciones de impuestos certificadas"],"explanation":"Los solicitantes de CDL de Hawái deben presentar una licencia de conducir de Hawái válida y comprobar identidad/edad (p. ej., acta de nacimiento), número de Seguro Social y residencia. Fuente: aviso \"How to Apply for a CDL\" del Hawaii DOT MVSO y página de la oficina de CDL de Honolulu CSD."},"90":{"q":"Si un conductor de Hawái opera TANTO en comercio interestatal exceptuado como no exceptuado, ¿con qué estatus debe autocertificarse?","options":["Interestatal no exceptuada (Non-excepted interstate)","Interestatal exceptuada (Excepted interstate)","Intraestatal exceptuada (Excepted intrastate)","Cualquiera de las dos, el conductor puede elegir libremente"],"explanation":"El Hawaii MVSO exige que un conductor que opera en ambos tipos elija \"Non-excepted interstate\" para que siga estando habilitado para ambos, lo cual también requiere presentar un MEC. Fuente: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)."},"91":{"q":"Durante la transición a la presentación electrónica del MEC, ¿por cuánto tiempo recomienda el Hawaii MVSO que un conductor de CDL lleve consigo una copia de su Certificado del Examinador Médico después de presentarlo al examinador médico?","options":["No más de 30 días desde la presentación","No más de 60 días desde la presentación","No más de 15 días desde la presentación","Exactamente un año"],"explanation":"El Hawaii MVSO recomienda llevar consigo la copia del MEC por no más de 15 días desde que se presentó al examinador médico, para cubrir posibles retrasos en la actualización electrónica. Fuente: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)."},"92":{"q":"El certificado médico de un titular de CDL de Hawái vence y este NO presenta uno nuevo. ¿En qué día se retiran todos los privilegios de la CDL, lo que requiere acudir en persona a una oficina de CDL?","options":["Día 54","Día 30","Día 90","Día 15"],"explanation":"Según el Hawaii MVSO, si el MEC se actualiza dentro de los 53 días no se necesita comparecer en persona ni pagar una tarifa de reinstauración; en el día 54 se retiran todos los privilegios de la CDL y el conductor debe acudir a una oficina de CDL para reinstaurarlos. Fuente: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)."},"93":{"q":"¿Qué ocurre con la elegibilidad de un conductor de Hawái en el momento en que vence su certificado médico del DOT?","options":["De inmediato deja de ser elegible para conducir un vehículo motorizado comercial","Conserva todos los privilegios de la CDL durante un período de gracia automático de 90 días","Nada cambia hasta la siguiente fecha de renovación de la CDL","Puede seguir conduciendo solo de manera intraestatal sin ninguna tarjeta médica"],"explanation":"El Hawaii MVSO indica que en el momento en que vence el certificado médico, el conductor deja de ser elegible para operar un CMV; el MVSO luego envía por correo un aviso de que el conductor ya no está físicamente habilitado. Fuente: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)."},"94":{"q":"En Hawái, ¿con cuánta anticipación al vencimiento puede normalmente un titular de CDL renovar su licencia de conducir comercial?","options":["Solo en la fecha exacta de vencimiento o después de ella","Hasta 30 días antes de la fecha de vencimiento","Hasta 6 meses antes de la fecha de vencimiento","Hasta 2 años antes de la fecha de vencimiento"],"explanation":"Las oficinas de los condados de Hawái (p. ej., Maui) permiten la renovación de la CDL dentro de los seis (6) meses previos a la fecha de vencimiento. Fuente: página \"Renewal of Commercial Drivers License\" del condado de Maui."},"95":{"q":"¿Con qué frecuencia debe un titular de CDL de Hawái renovar un endoso de Materiales Peligrosos (HazMat), independientemente del ciclo de la licencia base?","options":["Cada 8 años sin verificación de antecedentes","Cada 2 años con un nuevo examen de manejo","Cada 5 años, incluida una evaluación de amenazas de seguridad de la TSA","Solo una vez, nunca vence después de la primera emisión"],"explanation":"Un endoso de HazMat debe renovarse cada 5 años y requiere aprobar el examen de conocimientos de HazMat más una evaluación de amenazas de seguridad de la TSA (verificación de antecedentes basada en huellas dactilares). Fuente: página de renovación de CDL del condado de Maui; programa HazMat Endorsement de la TSA; 49 CFR Part 1572."},"96":{"q":"Los conductores de Hawái que tienen una licencia de conducir Clase 3 o Clase 4 y operan un CMV, ¿qué obligación tienen respecto al certificado médico?","options":["Deben presentar el MEC al FMCSA National Registry, igual que los titulares de Clase A","No presentan el MEC a un examinador médico, pero deben llevar consigo una copia cuando operan un CMV","Están totalmente exentos y no necesitan ningún certificado médico","Deben enviar por correo un MEC en papel al MVSO cada año"],"explanation":"El Hawaii MVSO indica que los titulares de licencia Clase 3/4 que operan un CMV no presentan el MEC a su examinador médico, pero aún así están obligados a llevar consigo una copia del MEC cuando operan un CMV. Fuente: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)."},"97":{"q":"¿Qué agencia de Hawái es responsable de la supervisión del proceso de certificación médica de la CDL y a la cual se dirige una autocertificación?","options":["El Hawaii State Department of Health","La División de Tránsito del Honolulu Police Department","El Hawaii DOT Motor Vehicle Safety Office (MVSO)","El U.S. Department of Labor"],"explanation":"El Hawaii DOT Motor Vehicle Safety Office (MVSO) administra la certificación médica y la autocertificación de la CDL, trabajando con las oficinas de CDL del condado y la FMCSA. Fuente: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)."},"98":{"q":"Según las reglas actualizadas de Hawái conforme al 49 CFR 391.46, ¿qué es ahora cierto para un conductor con diabetes mellitus tratada con insulina (ITDM) correctamente controlada que busca la certificación médica?","options":["El conductor todavía debe solicitar al MVSO una exención intraestatal de ITDM por separado antes de cualquier certificación","El conductor queda permanentemente descalificado para tener una CDL en Hawái","El conductor solo necesita una nota de cualquier farmacéutico, no de un examinador médico","Un examinador médico certificado puede emitir el MEC; ya no se requiere una solicitud de exención intraestatal de ITDM del MVSO por separado"],"explanation":"Según el 49 CFR 391.46 adoptado por el Hawaii MVSO, un examinador médico certificado puede emitir el MEC para un conductor con ITDM estable y correctamente controlada (usando la evaluación MCSA-5870); ya no se requiere una solicitud de exención intraestatal de ITDM del MVSO por separado. Fuente: Hawaii DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)."}},"hi":{"0":{"q":"हवाई कानून के तहत, किसी वाहन की अधिकतम कुल चौड़ाई (लोड सहित) कितनी हो सकती है जिसे ओवरसाइज़ परमिट के बिना सार्वजनिक राजमार्ग पर चलाया जा सके?","options":["8 फीट","8 फीट 6 इंच","9 फीट","10 फीट"],"explanation":"HRS §291-34 ऐसे किसी मोटर वाहन को चलाने पर रोक लगाता है जिसकी कुल चौड़ाई, लोड सहित, राज्य की किसी भी सार्वजनिक सड़क, गली या राजमार्ग पर परमिट के बिना नौ फीट से अधिक हो। (Hawaii Revised Statutes §291-34; Hawaii CDL Manual.)"},"1":{"q":"बिना परमिट के हवाई राजमार्गों पर किसी वाहन के लिए अनुमत अधिकतम कुल ऊँचाई (लोड सहित) कितनी है?","options":["13 फीट","13 फीट 6 इंच","14 फीट","15 फीट"],"explanation":"HRS §291-34 अधिकतम वाहन ऊँचाई, लोड सहित, चौदह फीट निर्धारित करता है। इस सीमा के भीतर रहते हुए भी, कोई वाहन किसी पुल या संरचना के नीचे से नहीं गुजर सकता यदि वह उस संरचना के लिए दर्शाई गई क्लीयरेंस से अधिक हो। (Hawaii Revised Statutes §291-34.)"},"2":{"q":"हवाई राजमार्गों पर, बिना परमिट के किसी एकल मोटर वाहन (गैर-संयोजन इकाई) की अधिकतम कुल लंबाई, लोड सहित, कितनी है?","options":["40 फीट","45 फीट","53 फीट","60 फीट"],"explanation":"HRS §291-34 किसी एकल मोटर वाहन (संयोजन नहीं) की कुल लंबाई, लोड सहित, पैंतालीस फीट तक सीमित करता है। (Hawaii Revised Statutes §291-34.)"},"3":{"q":"HRS §291-34 के तहत, हवाई में बिना परमिट के अनुमत किसी ट्रक-ट्रैक्टर और सेमीट्रेलर संयोजन की अधिकतम कुल लंबाई, लोड सहित, कितनी है?","options":["60 फीट","65 फीट","70 फीट","75 फीट"],"explanation":"HRS §291-34 किसी ट्रक-ट्रैक्टर और सेमीट्रेलर संयोजन को कुल लंबाई, लोड सहित, पैंसठ फीट तक सीमित करता है। (Hawaii Revised Statutes §291-34.)"},"4":{"q":"हवाई में, किसी एक एकल धुरी (single axle) द्वारा राजमार्ग पर डाला गया अधिकतम सकल भार इससे अधिक नहीं हो सकता:","options":["18,000 पाउंड","20,000 पाउंड","22,500 पाउंड","34,000 पाउंड"],"explanation":"HRS §291-35 किसी भी एकल धुरी पर सकल भार को बीस हज़ार पाउंड तक सीमित करता है। (Hawaii Revised Statutes §291-35.)"},"5":{"q":"हवाई में एक 'टैंडम धुरी' (दो लगातार धुरियाँ जो 40 इंच से अधिक लेकिन 96 इंच से अधिक नहीं की दूरी पर हों) अधिकतम कितना सकल भार ले जा सकती है:","options":["32,000 पाउंड","34,000 पाउंड","36,000 पाउंड","40,000 पाउंड"],"explanation":"HRS §291-35 किसी टैंडम धुरी (40 इंच से अधिक लेकिन 96 इंच से अधिक नहीं की दूरी पर रखी धुरियाँ) को चौंतीस हज़ार पाउंड तक सीमित करता है। (Hawaii Revised Statutes §291-35.)"},"6":{"q":"हवाई के भार कानून के तहत, किसी एक पहिये द्वारा राजमार्ग पर डाला गया सकल भार, चाहे एकल हो या दोहरी माउंटिंग, इससे अधिक नहीं हो सकता:","options":["8,000 पाउंड","10,000 पाउंड","12,000 पाउंड","13,500 पाउंड"],"explanation":"HRS §291-35 किसी एक पहिये पर सकल भार (एकल या दोहरी माउंटिंग) को दस हज़ार पाउंड तक सीमित करता है। (Hawaii Revised Statutes §291-35.)"},"7":{"q":"बिना ओवरवेट परमिट के हवाई राजमार्गों पर किसी वाहन या संयोजन के लिए अनुमत अधिकतम कुल सकल भार कितना है?","options":["73,280 पाउंड","80,000 पाउंड","88,000 पाउंड","105,500 पाउंड"],"explanation":"HRS §291-35 कुल वाहन सकल भार को अस्सी हज़ार पाउंड तक सीमित करता है, जो संघीय सीमा के अनुरूप है। (Hawaii Revised Statutes §291-35.)"},"8":{"q":"हवाई में दो लगातार टैंडम-धुरी सेट प्रत्येक 34,000 पाउंड तभी ले जा सकते हैं जब दोनों टैंडम सेटों की पहली और अंतिम धुरियों के बीच की दूरी कम से कम हो:","options":["28 फीट","32 फीट","36 फीट","40 फीट"],"explanation":"HRS §291-35 दो लगातार टैंडम-धुरी सेटों को प्रत्येक 34,000 पाउंड ले जाने की अनुमति केवल तभी देता है जब पहली और अंतिम धुरियों के बीच की कुल दूरी छत्तीस फीट या अधिक हो, और कुल सकल भार 80,000 पाउंड या उससे कम बना रहे। (Hawaii Revised Statutes §291-35.)"},"9":{"q":"HRS §291-35 में दिया गया सूत्र, जो धुरियों के किसी समूह के अनुमेय सकल भार को धुरियों की दूरी और संख्या से जोड़ता है, किस संघीय मानक पर आधारित है?","options":["संघीय ब्रिज फॉर्मूला (Bridge Gross Weight Formula)","CARB धुरी-दूरी नियम","AASHTO फुटपाथ लोडिंग सूचकांक","FMCSA सेवा-घंटे (hours-of-service) तालिका"],"explanation":"HRS §291-35 में हवाई के धुरी-समूह भार प्रावधान संघीय ब्रिज फॉर्मूला को शामिल करते हैं, जो अनुमेय भार को धुरियों की संख्या और किसी समूह की चरम धुरियों के बीच की दूरी से जोड़ता है। (Hawaii Revised Statutes §291-35; 23 U.S.C. §127, हवाई नियम के रूप में लागू।)"},"10":{"q":"हवाई में किसी राज्य राजमार्ग पर ओवरसाइज़ या ओवरवेट मूवमेंट की अनुमति देने वाला लिखित परमिट जारी करने का अधिकार किसके पास है?","options":["काउंटी पुलिस प्रमुख","परिवहन निदेशक (Director of Transportation)","लोक उपयोगिता आयोग (Public Utilities Commission)","होनोलूलू हार्बर मास्टर"],"explanation":"HRS §291-36 के तहत, परिवहन निदेशक राज्य राजमार्गों के लिए ओवरसाइज़/ओवरवेट परमिट जारी करते हैं, जबकि काउंटी इंजीनियर उन्हें काउंटी सड़कों और गलियों के लिए जारी करते हैं। (Hawaii Revised Statutes §291-36; HIDOT Highways Division.)"},"11":{"q":"हवाई में काउंटी सड़कों और गलियों पर मूवमेंट के लिए, ओवरसाइज़/ओवरवेट परमिट कौन जारी करता है?","options":["परिवहन निदेशक (Director of Transportation)","काउंटी इंजीनियर","मेयर का कार्यालय","राज्य लोक सुरक्षा विभाग"],"explanation":"HRS §291-36 काउंटी सड़कों और गलियों के लिए परमिट का अधिकार काउंटी इंजीनियर को सौंपता है (परिवहन निदेशक राज्य राजमार्गों को संभालते हैं)। (Hawaii Revised Statutes §291-36.)"},"12":{"q":"हवाई ओवरसाइज़/ओवरवेट परमिट के लिए आवेदन कैसे जमा करना चाहिए?","options":["जिला कार्यालय को टेलीफोन द्वारा मौखिक रूप से","Highways Division द्वारा प्रदान किए गए फॉर्म पर लिखित रूप में","केवल किसी लाइसेंसशुदा कस्टम ब्रोकर के माध्यम से","वजन-स्टेशन (weigh station) पर एक सूचना लगाकर"],"explanation":"HRS §291-36 लिखित आवेदन की आवश्यकता रखता है, और HIDOT Highways Division इसे अपने प्रदान किए गए फॉर्म पर अनिवार्य करता है, जिसमें पहिया व्यवस्था, आयाम और भार वितरण के रेखाचित्र शामिल हों। (Hawaii Revised Statutes §291-36; HIDOT Oversize/Overweight परमिट प्रक्रियाएँ।)"},"13":{"q":"आवेदन के अलावा, हवाई Highways Division किसी ओवरसाइज़/ओवरवेट परमिट आवेदक के पास फाइल में क्या रखना आवश्यक करता है?","options":["बीमा प्रमाणपत्र (certificate of insurance)","वाणिज्यिक मछली पकड़ने का लाइसेंस","नोटरीकृत हार्बर बॉन्ड","संघीय IRP कैब कार्ड"],"explanation":"HIDOT Highways Division किसी ओवरसाइज़/ओवरवेट परमिट जारी करने से पहले फाइल में बीमा प्रमाणपत्र रखना आवश्यक करता है। (HIDOT Oversize/Overweight Vehicles on State Highways परमिट प्रक्रियाएँ।)"},"14":{"q":"हवाई की परमिट शुल्क अनुसूची के अनुसार, अनुमेय भार के 1.35 गुना से कम या 14 फीट से कम चौड़ाई वाले लोड के लिए एकल-यात्रा (single-trip) परमिट का शुल्क है:","options":["$5","$10","$25","$50"],"explanation":"HRS §291-36 के तहत, अनुमेय भार के 1.35 गुना से कम या 14 फीट से कम चौड़ाई वाले लोड के लिए एकल-यात्रा परमिट का शुल्क $5 है (उस सीमा में निरंतर-यात्रा परमिट $10 है)। (Hawaii Revised Statutes §291-36; HIDOT.)"},"15":{"q":"हवाई की परमिट शुल्क अनुसूची के तहत, अनुमेय भार के 1.35 गुना से अधिक के लोड के लिए ओवरवेट परमिट का शुल्क है:","options":["$5","$10","$25","$100"],"explanation":"HRS §291-36 ओवरवेट परमिट के लिए $25 शुल्क निर्धारित करता है जब लोड अनुमेय भार के 1.35 गुना से अधिक हो; वही $25 शुल्क 14 फीट से अधिक चौड़ाई वाले ओवरसाइज़ परमिट पर भी लागू होता है। (Hawaii Revised Statutes §291-36; HIDOT.)"},"16":{"q":"हवाई में किसी लोड की चौड़ाई इससे अधिक हो जाने पर ओवरसाइज़ चौड़ाई (WIDTH) परमिट आवश्यक होता है (और उच्चतर $25 शुल्क लगता है):","options":["9 फीट","10 फीट","12 फीट","14 फीट"],"explanation":"हालाँकि 9 फीट से अधिक किसी भी चौड़ाई के लिए परमिट आवश्यक है, HRS §291-36 की शुल्क अनुसूची 14 फीट से अधिक चौड़ाई वाले लोड को $25 ओवरसाइज़ परमिट श्रेणी में आवश्यक मानती है। (Hawaii Revised Statutes §291-36; HIDOT परमिट शुल्क अनुसूची।)"},"17":{"q":"हवाई के कृषि प्रावधानों के तहत, परिवहन निदेशक कब HRS §291-35 की सीमाओं से अधिक भार की अनुमति देने वाला परमिट जारी कर सकते हैं?","options":["केवल राज्य के स्वामित्व वाले वाहनों के लिए","जब कटाई किए गए उत्पादों को उस स्थान से जहाँ उनकी कटाई या भंडारण होता है, उस स्थान तक ले जाया जा रहा हो जहाँ उनका प्रसंस्करण या उपयोग होता है","केवल आधी रात से सुबह 5 बजे के बीच","कभी नहीं — कोई ओवरवेट कृषि परमिट अनुमत नहीं है"],"explanation":"HRS §291-36 §291-35 की भार सीमाओं से अधिक होने का परमिट तब अधिकृत करता है जब उत्पादों को उस स्थान से जहाँ उनकी कटाई या भंडारण होता है, उस स्थान तक ले जाया जा रहा हो जहाँ उनका प्रसंस्करण या उपयोग होता है। (Hawaii Revised Statutes §291-36.)"},"18":{"q":"HRS §291-36 के तहत हवाई में किस कृषि मूवमेंट के लिए कोई परमिट बिल्कुल आवश्यक नहीं है?","options":["कोई भी फार्म वाहन जो राज्य राजमार्ग पर 10 मील या उससे कम यात्रा करता हो","कृषि कार्यों में प्रयुक्त कोई वाहन जो परिवहन निदेशक या काउंटी इंजीनियर द्वारा अनुमोदित किसी स्थान पर केवल किसी सार्वजनिक सड़क को पार करता हो","कोई भी वाहन जो भार की परवाह किए बिना अनानास ढो रहा हो","80,000 पाउंड से कम का कोई संयोजन जो कॉफ़ी ले जा रहा हो"],"explanation":"HRS §291-36 प्रावधान करता है कि कृषि कार्यों में प्रयुक्त किसी ऐसे वाहन के लिए कोई परमिट आवश्यक नहीं है जो परिवहन निदेशक (राज्य राजमार्ग) या काउंटी इंजीनियर (काउंटी सड़कें) द्वारा अनुमोदित किसी स्थान पर केवल किसी सार्वजनिक सड़क, गली या राजमार्ग को पार करता हो। (Hawaii Revised Statutes §291-36.)"},"19":{"q":"यदि कोई इंजीनियरिंग विश्लेषण यह दर्शाता है कि कोई हवाई पुल वैधानिक अधिकतम सकल भार से कम सुरक्षित रूप से वहन कर सकता है, तो जिम्मेदार प्राधिकरण क्या कर सकता है?","options":["पुल को सभी ट्रकों के लिए स्थायी रूप से बंद कर दे","उस पुल को पार करने वाले वाहनों के सकल भार को सीमित करने वाले संकेत लगाए और बनाए रखे","क्षतिपूर्ति के लिए राज्यव्यापी सकल भार सीमा बढ़ा दे","उस मार्ग के लिए CDL अपग्रेड आवश्यक करे"],"explanation":"HRS §291-35 परिवहन निदेशक (या काउंटी इंजीनियर) को किसी विशिष्ट पुल या संरचना पर सकल भार सीमित करने वाले संकेत लगाने और बनाए रखने की अनुमति देता है जब इंजीनियरिंग विश्लेषण यह दर्शाए कि उसकी क्षमता वैधानिक अधिकतम से कम है; चालकों को दर्शाई गई सीमा का पालन करना चाहिए। (Hawaii Revised Statutes §291-35.)"},"20":{"q":"हवाई में, 26,001 पाउंड या अधिक के सकल संयोजन भार रेटिंग (GCWR) वाले वाहनों के किसी भी संयोजन को चलाने के लिए कौन-सा CDL वर्ग आवश्यक है, जब खींचे जा रहे वाहन(नों) का GVWR 10,000 पाउंड से अधिक हो?","options":["Class A","Class B","Class C","Class D"],"explanation":"हवाई Class A CDL को वाहनों के ऐसे किसी संयोजन के रूप में परिभाषित करता है जिसका GCWR 26,001 lbs या अधिक हो, बशर्ते खींची गई इकाई का GVWR 10,000 lbs से अधिक हो। स्रोत: HRS Sec. 286-239 और Honolulu Commercial Driver Licensing Office. कोई संघीय/हवाई 'Class D' CDL नहीं है।"},"21":{"q":"हवाई कानून के तहत, 26,001 पाउंड या अधिक के सकल वाहन भार रेटिंग (GVWR) वाले किसी एकल वाहन (या ऐसे वाहन के साथ जो 10,000 पाउंड से अधिक की इकाई नहीं खींच रहा हो) के लिए कौन-सा CDL वर्ग आवश्यक है?","options":["Class A","Class B","Class C","Class M"],"explanation":"हवाई 26,001 lbs या अधिक के GVWR वाले किसी एकल वाहन को Class B वाणिज्यिक मोटर वाहन के रूप में वर्गीकृत करता है। स्रोत: HRS Sec. 286-239; Honolulu CDL Office. 'Class M' एक मोटरसाइकिल श्रेणी है, CDL नहीं।"},"22":{"q":"एक हवाई चालक 26,001 lbs GVWR से कम का ऐसा वाहन चलाता है जो 16 या अधिक यात्रियों (चालक सहित) को ले जाने के लिए डिज़ाइन किया गया है या खतरनाक सामग्री के लिए प्लैकार्ड लगा है। कौन-सा CDL वर्ग लागू होता है?","options":["Class A","Class B","Class C","किसी CDL की आवश्यकता नहीं"],"explanation":"Class C CDL ऐसे वाहनों को कवर करता है जो न तो Class A और न ही Class B के मानदंड पूरे करते हैं लेकिन 16+ यात्रियों (चालक सहित) को ले जाने के लिए डिज़ाइन किए गए हैं या प्लैकार्ड लगी हैज़मैट ले जाते हैं। स्रोत: HRS Sec. 286-239; Honolulu CDL Office."},"23":{"q":"हवाई CDL पर कौन-सा एंडोर्समेंट कोड ऐसे वाहन को चलाने का अधिकार देता है जो प्लैकार्ड की आवश्यकता वाली खतरनाक सामग्री ले जाता है?","options":["Endorsement N","Endorsement T","Endorsement H","Endorsement P"],"explanation":"H (HazMat) एंडोर्समेंट प्लैकार्ड लगी खतरनाक सामग्री ले जाने वाले वाहन को चलाने का अधिकार देता है। स्रोत: Hawaii CDL Manual / Honolulu CDL Office; 49 CFR Part 383 (हवाई द्वारा अपनाया गया)।"},"24":{"q":"हवाई CDL पर, डबल और ट्रिपल ट्रेलर चलाने के लिए कौन-सा एंडोर्समेंट आवश्यक है?","options":["Endorsement T","Endorsement N","Endorsement S","Endorsement H"],"explanation":"T एंडोर्समेंट डबल और ट्रिपल ट्रेलर चलाने का अधिकार देता है। स्रोत: Hawaii CDL Manual / Honolulu CDL Office; 49 CFR 383.93."},"25":{"q":"हवाई किसी टैंक वाहन को चलाने के लिए कौन-सा एंडोर्समेंट आवश्यक करता है, जो आम तौर पर ऐसा वाहन होता है जिसे 1,000 गैलन से अधिक रेटेड क्षमता वाले स्थायी रूप से माउंट किए गए टैंक में तरल या गैस ढोने के लिए डिज़ाइन किया गया हो?","options":["Endorsement P","Endorsement N","Endorsement T","Endorsement X"],"explanation":"N (Tanker) एंडोर्समेंट टैंक वाहनों के लिए आवश्यक है; हवाई 1,000 गैलन से अधिक के टैंकों का संदर्भ देता है। स्रोत: Honolulu CDL Office; 49 CFR 383.93. X कोड संयुक्त टैंक + हैज़मैट को दर्शाता है, अकेले टैंकर को नहीं।"},"26":{"q":"16 या अधिक यात्रियों (चालक सहित) को ले जाने के लिए डिज़ाइन किए गए वाहन को चलाने के लिए हवाई CDL धारक को कौन-सा एंडोर्समेंट प्राप्त करना चाहिए?","options":["Endorsement S","Endorsement N","Endorsement P","Endorsement T"],"explanation":"P (Passenger) एंडोर्समेंट 16 या अधिक यात्रियों, चालक सहित, को ले जाने के लिए आवश्यक है। स्रोत: Honolulu CDL Office; 49 CFR 383.93. S एंडोर्समेंट विशेष रूप से स्कूल बसों के लिए है।"},"27":{"q":"हवाई में स्कूल बस चलाने के लिए, किसी CDL धारक को S एंडोर्समेंट होना चाहिए। इसके साथ कौन-सा अतिरिक्त यात्री-संबंधी एंडोर्समेंट भी आवश्यक है?","options":["Endorsement N","Endorsement T","Endorsement H","Endorsement P"],"explanation":"किसी स्कूल बस चालक के पास S (School Bus) और P (Passenger) दोनों एंडोर्समेंट होने चाहिए। स्रोत: Hawaii CDL Manual; 49 CFR 383.93, हवाई द्वारा अपनाया गया।"},"28":{"q":"इंटरस्टेट (राज्य सीमाओं के पार) वाणिज्यिक ड्राइविंग को अधिकृत करने वाला हवाई CDL प्राप्त करने के लिए आवश्यक न्यूनतम आयु क्या है?","options":["18 वर्ष","19 वर्ष","20 वर्ष","21 वर्ष"],"explanation":"इंटरस्टेट वाणिज्यिक ड्राइविंग के लिए न्यूनतम आयु 21 आवश्यक है। केवल-इंट्रास्टेट संचालन की अनुमति 18 वर्ष में दी जा सकती है। स्रोत: Honolulu CDL Office; 49 CFR 391.11(b)."},"29":{"q":"हवाई CDL के लिए आवेदन करने से पहले, चालक को आवश्यक ज्ञान परीक्षा(ओं) को पास करके कौन-सा क्रेडेंशियल पहले प्राप्त करना चाहिए?","options":["Commercial Learner Permit (CLP)","Provisional CDL","Temporary HazMat कार्ड","Class C निर्देश परमिट"],"explanation":"आवेदकों को CDL कौशल परीक्षा देने से पहले ज्ञान परीक्षा(ओं) को पास करके पहले Commercial Learner Permit (CLP) प्राप्त करना चाहिए। स्रोत: Honolulu CDL Office; 49 CFR 383.25."},"30":{"q":"हवाई द्वारा अपनाए गए संघीय नियमों के तहत, CDL कौशल परीक्षा देने के पात्र होने से पहले किसी चालक को Commercial Learner Permit कितने समय तक रखना चाहिए?","options":["कम से कम 7 दिन","कम से कम 14 दिन","कम से कम 30 दिन","कम से कम 60 दिन"],"explanation":"किसी चालक को कौशल परीक्षा देने से पहले CLP को कम से कम 14 दिन रखना चाहिए; हवाई परमिट जारी होने के 14 दिन से पहले कौशल परीक्षा निर्धारित नहीं करता। स्रोत: Honolulu CDL Office; 49 CFR 383.25(e)."},"31":{"q":"हवाई Commercial Learner Permit (CLP) के नवीनीकरण से पहले यह कितने समय के लिए वैध रहता है?","options":["90 दिन","180 दिन","1 वर्ष","2 वर्ष"],"explanation":"हवाई CLP 180 दिनों के लिए वैध है। स्रोत: Hawaii CDL Manual / DMV मार्गदर्शन; 49 CFR 383.25(c)."},"32":{"q":"हवाई Commercial Learner Permit पर ड्राइविंग करते समय, परमिट धारक को:","options":["केवल दिन के उजाले के घंटों में अकेले ड्राइव करना चाहिए","उनके बगल में बैठे किसी CDL धारक के साथ होना चाहिए","किसी भी अभ्यास से पहले एक यात्री एंडोर्समेंट होना चाहिए","केवल निजी संपत्ति पर ड्राइव करना चाहिए"],"explanation":"किसी CLP धारक के साथ हर समय कोई ऐसा व्यक्ति होना चाहिए जिसके पास वैध CDL हो (जिस वर्ग/एंडोर्समेंट का अभ्यास किया जा रहा हो उसके लिए) और जो अगली सीट पर बैठा हो। स्रोत: Hawaii CDL Manual; 49 CFR 383.25(a)."},"33":{"q":"हवाई का CDL जारी करने वाला कार्यालय किसी अमेरिकी नागरिक आवेदक के लिए पहचान और वैध उपस्थिति के प्रमाण के रूप में कौन-सा दस्तावेज़ स्वीकार करता है?","options":["एक लाइब्रेरी कार्ड","एक प्रमाणित अमेरिकी जन्म प्रमाणपत्र","एक वाहन पंजीकरण","केवल एक उपयोगिता बिल"],"explanation":"हवाई पहचान और वैध उपस्थिति स्थापित करने के लिए एक प्रमाणित अमेरिकी जन्म प्रमाणपत्र (या अन्य अनुमोदित प्रमाण) आवश्यक करता है। स्रोत: Honolulu CDL Office दस्तावेज़ सूची।"},"34":{"q":"हवाई का CDL कार्यालय किसी आवेदक से कितने निवास-प्रमाण दस्तावेज़ प्रस्तुत करने की आवश्यकता रखता है?","options":["कोई नहीं","एक","दो","चार"],"explanation":"हवाई CDL के लिए हवाई निवास स्थापित करने हेतु दो निवास-प्रमाण दस्तावेज़ आवश्यक करता है। स्रोत: Honolulu CDL Office दस्तावेज़ चेकलिस्ट।"},"35":{"q":"हवाई CDL आवेदक को ड्राइव करने की अपनी शारीरिक योग्यता प्रमाणित करने के लिए कौन-सा चिकित्सा दस्तावेज़ जमा करना चाहिए?","options":["एक वर्तमान DOT Medical Examiner's Certificate (MCSA-5876)","एक दंत मंजूरी फॉर्म","एक नोटरीकृत स्वास्थ्य शपथपत्र","एक प्राथमिक-देखभाल प्रिस्क्रिप्शन"],"explanation":"आवेदकों को एक वर्तमान DOT physical / Medical Examiner's Certificate (Form MCSA-5876) जमा करना चाहिए। स्रोत: Honolulu CDL Office; 49 CFR 391.43."},"36":{"q":"किसी ऐसे हवाई CDL चालक पर कौन-सी चिकित्सा स्व-प्रमाणन श्रेणी लागू होती है जो राज्य सीमाओं के पार संचालन करता है और संघीय चिकित्सा-प्रमाणपत्र आवश्यकता के अधीन है तथा उसे पूरा करता है?","options":["Excepted Interstate","Non-Excepted Interstate","Excepted Intrastate","Non-Excepted Intrastate"],"explanation":"अंतरराज्यीय वाणिज्य में कोई चालक जिसे संघीय Part 391 चिकित्सा-प्रमाणपत्र आवश्यकता पूरी करनी होती है, वह Non-Excepted Interstate के रूप में स्व-प्रमाणित करता है। स्रोत: 49 CFR 383.71(b), हवाई द्वारा अपनाया गया।"},"37":{"q":"7 फरवरी 2022 से, पहली हवाई Class A या B CDL (या पहले P, S, या H एंडोर्समेंट) के लिए कौशल परीक्षा देने से पहले, किसी आवेदक को कौन-सी आवश्यकता पूरी करनी चाहिए?","options":["5-वर्ष का स्वच्छ ड्राइविंग रिकॉर्ड","किसी पंजीकृत प्रदाता से FMCSA Entry-Level Driver Training (ELDT)","किसी भी स्कूल में एक रक्षात्मक-ड्राइविंग पाठ्यक्रम","एक दो-वर्षीय अप्रेंटिसशिप"],"explanation":"ELDT पहली बार Class A/B CDL और पहली बार P, S, या H एंडोर्समेंट के लिए आवश्यक है; प्रशिक्षण FMCSA Training Provider Registry में शामिल किसी प्रदाता से होना चाहिए। स्रोत: 49 CFR Part 380 (7 फरवरी 2022 से प्रभावी); Honolulu CDL Office."},"38":{"q":"HazMat ज्ञान परीक्षा पास करने के अलावा, H (HazMat) एंडोर्समेंट जारी होने से पहले किसी हवाई आवेदक को क्या पूरा करना चाहिए?","options":["एक TSA सुरक्षा खतरा आकलन (पृष्ठभूमि जाँच)","किसी टैंक वाहन में एक रोड टेस्ट","एक उत्सर्जन निरीक्षण","एक नौका सुरक्षा पाठ्यक्रम"],"explanation":"संघीय कानून हर HazMat-एंडोर्समेंट आवेदक को जारी करने से पहले एक TSA सुरक्षा खतरा आकलन (फिंगरप्रिंटिंग सहित पृष्ठभूमि जाँच) पास करना आवश्यक करता है, जो ज्ञान परीक्षा और ELDT के अतिरिक्त है। स्रोत: 49 CFR 1572 (TSA); 49 CFR 383.141; Hawaii CDL Office."},"39":{"q":"हवाई में, कोई व्यक्ति किसी वाणिज्यिक मोटर वाहन (CMV) को कम से कम किस स्तर के रक्त अल्कोहल सांद्रता (BAC) के साथ चलाकर एक प्रमुख अयोग्यता अपराध करता है?","options":["0.02","0.04","0.08","0.10"],"explanation":"हवाई CMV अल्कोहल सीमा 0.04 BAC निर्धारित करता है, जो सामान्य चालकों के लिए 0.08 सीमा की आधी है। CMV को 0.04 या अधिक पर चलाना एक प्रमुख अपराध है। स्रोत: Hawaii CDL Manual (Hawaii DOT) और HRS 286-240; 49 CFR 383.51."},"40":{"q":"हवाई के निहित-सहमति (implied-consent) कानून के तहत, राज्य के राजमार्गों पर ड्राइविंग करके एक वाणिज्यिक चालक को किसके लिए सहमति दे चुका माना जाता है?","options":["किसी भी वजन-स्टेशन पर वाहन निरीक्षण","गिरफ़्तार होने पर अल्कोहल या ड्रग सामग्री के लिए सांस, रक्त, या मूत्र की जाँच","बिना वारंट के कैब की तलाशी","हर साल एक चिकित्सा पुनर्प्रमाणन परीक्षा"],"explanation":"हवाई का निहित-सहमति कानून किसी भी चालक को वैध रूप से गिरफ़्तार किए जाने पर अल्कोहल सांद्रता या ड्रग सामग्री निर्धारित करने के लिए सांस, रक्त, या मूत्र की जाँच के लिए सहमति दे चुका मानता है। स्रोत: HRS 291E-11 (implied consent); Hawaii CDL Manual."},"41":{"q":"एक हवाई CDL धारक को प्लैकार्ड लगी खतरनाक सामग्री का परिवहन न करते हुए पहले प्रमुख अपराध (जैसे CMV में DUI) के लिए दोषी ठहराया जाता है। न्यूनतम अयोग्यता अवधि है:","options":["60 दिन","120 दिन","1 वर्ष","3 वर्ष"],"explanation":"हवाई में पहला प्रमुख अपराध न्यूनतम 1-वर्ष की CDL अयोग्यता लाता है। स्रोत: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 1."},"42":{"q":"यदि पहला प्रमुख अपराध तब होता है जब चालक प्लैकार्ड की आवश्यकता वाली खतरनाक सामग्री का परिवहन करने वाला CMV चला रहा हो, तो अयोग्यता अवधि बढ़कर हो जाती है:","options":["1 वर्ष","18 महीने","3 वर्ष","5 वर्ष"],"explanation":"प्लैकार्ड लगी खतरनाक सामग्री का परिवहन करते समय किया गया पहला प्रमुख अपराध अयोग्यता को 1 वर्ष से बढ़ाकर 3 वर्ष कर देता है। स्रोत: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51 Table 1."},"43":{"q":"चालक के जीवनकाल के भीतर (CMV में किए गए) दूसरे प्रमुख अपराध के लिए हवाई में अयोग्यता अवधि क्या है?","options":["3 वर्ष","5 वर्ष","10 वर्ष","आजीवन (life)"],"explanation":"दूसरे प्रमुख अपराध के परिणामस्वरूप हवाई में आजीवन CDL अयोग्यता होती है। स्रोत: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 1."},"44":{"q":"एक हवाई वाणिज्यिक चालक जो आवश्यक अल्कोहल/ड्रग जाँच के लिए सहमत होने से इनकार करता है, उसे CMV संचालन से न्यूनतम कितने समय के लिए अयोग्य घोषित किया जाता है:","options":["30 दिन","60 दिन","1 वर्ष","90 दिन"],"explanation":"निहित-सहमति कानून के तहत आवश्यक जाँच से इनकार करना एक प्रमुख अपराध माना जाता है, जो पहले DUI के समान ही न्यूनतम 1-वर्ष की CDL अयोग्यता लाता है (प्लैकार्ड HazMat होने पर 3 वर्ष)। स्रोत: HRS 286-240 और HRS 291E-11; Hawaii CDL Manual."},"45":{"q":"हवाई CDL धारक के लिए निम्नलिखित में से कौन-सा एक प्रमुख अपराध है (केवल एक गंभीर यातायात उल्लंघन नहीं)?","options":["किसी अन्य वाहन का बहुत करीब से पीछा करना","सीमा से 15 mph या अधिक तेज़ गति से चलना","किसी अपराध (felony) को करने के लिए CMV का उपयोग करना","अनुचित या अनियमित लेन परिवर्तन"],"explanation":"किसी अपराध (felony) को करने में CMV का उपयोग करना एक प्रमुख अपराध है। बहुत करीब से पीछा करना, अत्यधिक गति, और अनुचित लेन परिवर्तन गंभीर यातायात उल्लंघन हैं, प्रमुख अपराध नहीं। स्रोत: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51."},"46":{"q":"3-वर्ष की अवधि के भीतर अलग-अलग घटनाओं से उत्पन्न CMV में दो गंभीर यातायात उल्लंघनों के लिए दोषसिद्धि हवाई CDL धारक को कितने समय के लिए अयोग्य घोषित करती है:","options":["30 दिन","60 दिन","120 दिन","1 वर्ष"],"explanation":"3 वर्ष के भीतर दो गंभीर यातायात उल्लंघनों के परिणामस्वरूप 60-दिन की अयोग्यता होती है। स्रोत: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 2."},"47":{"q":"3-वर्ष की अवधि के भीतर CMV में तीन गंभीर यातायात उल्लंघनों के लिए दोषसिद्धि हवाई CDL धारक को कितने समय के लिए अयोग्य घोषित करती है:","options":["60 दिन","90 दिन","120 दिन","180 दिन"],"explanation":"3 वर्ष के भीतर तीन गंभीर यातायात उल्लंघनों के परिणामस्वरूप 120-दिन की अयोग्यता होती है, जो पिछले दो के लिए 60-दिन की अवधि के अतिरिक्त सेवित की जाती है। स्रोत: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51 Table 2."},"48":{"q":"हवाई में किसी CMV चालक को 'गंभीर यातायात उल्लंघन' के रूप में गिने जाने के लिए दर्शाई गई गति सीमा से कितना अधिक चालान किया जाना चाहिए?","options":["10 mph या अधिक","15 mph या अधिक","20 mph या अधिक","25 mph या अधिक"],"explanation":"दर्शाई गई सीमा से 15 mph या अधिक की अत्यधिक गति एक गंभीर यातायात उल्लंघन है। स्रोत: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 2."},"49":{"q":"इनमें से किसे हवाई CDL धारक के लिए एक गंभीर यातायात उल्लंघन के रूप में वर्गीकृत किया गया है?","options":["CMV में 0.04 का BAC होना","लापरवाही से ड्राइविंग (Reckless driving)","रासायनिक जाँच से इनकार करना","दुर्घटना स्थल छोड़कर जाना"],"explanation":"लापरवाही से ड्राइविंग एक गंभीर यातायात उल्लंघन है। अन्य तीन प्रमुख अपराध हैं। स्रोत: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51 Tables 1 and 2."},"50":{"q":"उचित वर्ग के CDL के बिना या चालक के पास CDL न होने पर CMV चलाना हवाई में किस रूप में माना जाता है:","options":["प्रमुख अपराध","गंभीर यातायात उल्लंघन","सेवा-से-बाहर (out-of-service) आदेश उल्लंघन","रेलमार्ग-क्रॉसिंग उल्लंघन"],"explanation":"उचित वर्ग के लाइसेंस/एंडोर्समेंट के बिना, या CDL पास में न होने पर CMV चलाना एक गंभीर यातायात उल्लंघन है। स्रोत: Hawaii CDL Manual (Hawaii DOT); HRS 286-240; 49 CFR 383.51 Table 2."},"51":{"q":"हवाई CMV चालकों पर लागू नियमों के तहत, ड्राइविंग करते समय टेक्स्टिंग करना और हाथ में पकड़ा हुआ मोबाइल फ़ोन उपयोग करना किस रूप में वर्गीकृत हैं:","options":["प्रमुख अपराध","गंभीर यातायात उल्लंघन","बिना अयोग्यता के उपकरण उल्लंघन","सेवा-से-बाहर उल्लंघन"],"explanation":"CMV चलाते समय टेक्स्टिंग और हाथ में पकड़े फ़ोन का उपयोग गंभीर यातायात उल्लंघन हैं; 3 वर्ष में दो 60-दिन की अयोग्यता लाते हैं और तीन 120 दिन लाते हैं। स्रोत: Hawaii CDL Manual; 49 CFR 383.51 and 392.80/392.82 (FMCSA)."},"52":{"q":"हवाई CMV चालक के लिए, ड्राइविंग करते समय टेक्स्टिंग करने या हाथ में पकड़े फ़ोन का उपयोग करने वाले किसी व्यक्तिगत चालक के लिए अधिकतम संघीय नागरिक दंड लगभग है:","options":["$500","$1,000","$2,750","$11,000"],"explanation":"CMV में टेक्स्टिंग या हाथ में पकड़े फ़ोन के उपयोग के लिए किसी चालक पर $2,750 तक (मुद्रास्फीति-समायोजित) जुर्माना लगाया जा सकता है; इसकी अनुमति देने वाले नियोक्ताओं को $11,000 तक का सामना करना पड़ता है। स्रोत: FMCSA 49 CFR 392.80/392.82 and 383.51, हवाई में लागू।"},"53":{"q":"किसी हवाई CDL धारक की CMV में रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग कानून का पालन करने में विफलता के लिए पहली दोषसिद्धि के परिणामस्वरूप कितने समय की अयोग्यता होती है:","options":["60 दिन","120 दिन","1 वर्ष","30 दिन"],"explanation":"पहला रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन न्यूनतम 60-दिन की अयोग्यता लाता है। स्रोत: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 3."},"54":{"q":"3-वर्ष की अवधि के भीतर दूसरा रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन हवाई CDL धारक को कम से कम कितने समय के लिए अयोग्य घोषित करता है:","options":["60 दिन","120 दिन","1 वर्ष","180 दिन"],"explanation":"3 वर्ष के भीतर दूसरा ग्रेड-क्रॉसिंग उल्लंघन न्यूनतम 120-दिन की अयोग्यता लाता है। स्रोत: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51 Table 3."},"55":{"q":"3-वर्ष की अवधि के भीतर तीसरा रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन कम से कम कितने समय की अयोग्यता में परिणत होता है:","options":["120 दिन","180 दिन","1 वर्ष","3 वर्ष"],"explanation":"3 वर्ष के भीतर तीसरा ग्रेड-क्रॉसिंग उल्लंघन न्यूनतम 1-वर्ष की अयोग्यता लाता है। स्रोत: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 3."},"56":{"q":"किसी हवाई CDL धारक की किसी चालक या वाहन सेवा-से-बाहर (OOS) आदेश के उल्लंघन के लिए पहली दोषसिद्धि के परिणामस्वरूप कितने समय की अयोग्यता होती है:","options":["कम से कम 30 दिन","कम से कम 90 दिन","कम से कम 180 दिन (1 वर्ष तक)","कम से कम 2 वर्ष"],"explanation":"पहला सेवा-से-बाहर आदेश उल्लंघन 180 दिन से 1 वर्ष तक की अयोग्यता लाता है (HazMat या यात्रियों का परिवहन करते समय 180 दिन से 2 वर्ष)। स्रोत: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51 Table 4."},"57":{"q":"10-वर्ष की अवधि के भीतर CMV में दूसरा सेवा-से-बाहर आदेश उल्लंघन हवाई CDL धारक को कितने समय के लिए अयोग्य घोषित करता है:","options":["180 दिन से 1 वर्ष","2 से 5 वर्ष","1 से 3 वर्ष","आजीवन"],"explanation":"10 वर्ष के भीतर दूसरा OOS-आदेश उल्लंघन 2-से-5-वर्ष की अयोग्यता लाता है (HazMat/यात्री के लिए 3 से 5 वर्ष)। स्रोत: HRS 286-240; Hawaii CDL Manual (Hawaii DOT); 49 CFR 383.51 Table 4."},"58":{"q":"जब किसी पहले लगाई गई अवधि के ऊपर एक हवाई अयोग्यता अवधि लगाई जाती है (उदाहरण के लिए, पिछले दो के बाद तीसरा गंभीर उल्लंघन), तो नई अवधि:","options":["पिछली अवधि के साथ समवर्ती रूप से (concurrently) सेवित की जाती है","आधी कर दी जाती है","पिछली अवधि में जोड़ी जाती है (क्रमिक रूप से/consecutively सेवित की जाती है)","सुनवाई का अनुरोध करने पर माफ़ कर दी जाती है"],"explanation":"हवाई अयोग्यता अवधियाँ क्रमिक रूप से (consecutively) चलती हैं: एक नई लगाई गई अवधि किसी भी पहले लगाई गई अयोग्यता अवधि के अतिरिक्त होती है। स्रोत: HRS 286-240; Hawaii CDL Manual; 49 CFR 383.51."},"59":{"q":"हवाई के मूव ओवर कानून के तहत, जब कोई वाणिज्यिक चालक बहु-लेन सड़क पर चमकती रोशनी दिखाते हुए रुके हुए आपातकालीन वाहन के पास पहुंचता है, तो कानून चालक से निम्नलिखित में से क्या करने की अपेक्षा करता है?","options":["उचित और विवेकपूर्ण गति तक धीमा करे और, जब सुरक्षित हो, आपातकालीन वाहन से दूर किसी गैर-आसन्न लेन में चला जाए","निर्धारित गति बनाए रखे लेकिन गुजरते समय दो बार हॉर्न बजाए","आपातकालीन वाहन की रोशनी बंद होने तक शोल्डर पर पूरी तरह रुक जाए","गति को निर्धारित सीमा से ठीक 10 mph कम करे और दाहिनी लेन में बना रहे"],"explanation":"हवाई का मूव ओवर कानून (HRS 291C-27) निकट आ रहे चालक से यह अपेक्षा करता है कि वह परिस्थितियों के अनुसार उचित और विवेकपूर्ण गति तक धीमा हो जाए और, यदि सुरक्षित हो, तो आपातकालीन वाहन से दूर आसन्न लेन में बदल जाए (या दो लेन हटकर, बीच में एक लेन छोड़ते हुए)। स्रोत: HRS 291C-27।"},"60":{"q":"हवाई का मूव ओवर कानून चमकती रोशनी के साथ रुके हुए वाहनों की रक्षा करता है। हवाई के क़ानून के तहत निम्नलिखित में से किसे विशेष रूप से एक संरक्षित 'आपातकालीन वाहन' के रूप में नामित किया गया है?","options":["सवारी की प्रतीक्षा कर रही एक टैक्सीकैब","एक टो ट्रक","हैज़र्ड लाइट चालू वाली एक डिलीवरी वैन","पंक्चर टायर बदल रही एक यात्री कार"],"explanation":"HRS 291C-27 संरक्षित आपातकालीन वाहनों में टो ट्रकों को सूचीबद्ध करता है, साथ ही पुलिस, फायर, EMS, महासागर सुरक्षा, फ्रीवे सेवा गश्ती, शेरिफ, नागरिक सुरक्षा, हार्बर्स डिवीजन और DLNR प्रवर्तन वाहनों को भी। स्रोत: HRS 291C-27।"},"61":{"q":"जब किसी प्लेकार्ड लगे खतरनाक-सामग्री वाले वाहन या यात्रियों को ले जा रही बस को हवाई में रेलरोड क्रॉसिंग पर रुकना होता है, तो उसे निकटतम रेल के सापेक्ष कहां रुकना चाहिए?","options":["निकटतम रेल से 5 फीट से कम नहीं लेकिन 25 फीट से अधिक नहीं","निकटतम रेल से 25 फीट से कम नहीं लेकिन 75 फीट से अधिक नहीं","निकटतम रेल से 15 फीट से कम नहीं लेकिन 50 फीट से अधिक नहीं","निकटतम रेल से ठीक 30 फीट"],"explanation":"हवाई कानून (HRS 291C-93), जो हवाई CDL मैनुअल में भी दर्शाया गया है, वाहन से यह अपेक्षा करता है कि वह निकटतम रेल से 50 फीट के भीतर लेकिन 15 फीट से कम नहीं रुके, फिर सुने और दोनों ओर देखे। स्रोत: HRS 291C-93; हवाई CDL मैनुअल।"},"62":{"q":"हवाई कानून और हवाई CDL मैनुअल के अनुसार, किस वाहन को हर रेलरोड ग्रेड क्रॉसिंग पर रुकना आवश्यक है, भले ही कोई ट्रेन दिखाई न दे?","options":["एक खाली फ्लैटबेड सीधा ट्रक","40 फीट से अधिक लंबा कोई भी ट्रैक्टर-ट्रेलर","एक यूटिलिटी ट्रेलर खींच रहा पिकअप ट्रक","विस्फोटक पदार्थ या ज्वलनशील तरल पदार्थ को कार्गो के रूप में ले जा रहा वाहन"],"explanation":"HRS 291C-93 किराए पर यात्रियों को ले जा रहे वाहनों, बच्चों को ले जा रही स्कूल बसों, और विस्फोटक पदार्थ या ज्वलनशील तरल पदार्थ को कार्गो के रूप में ले जा रहे वाहनों से रुकने की अपेक्षा करता है। एक खाली या सामान्य-माल वाले ट्रक को रुकना आवश्यक नहीं है जब तक कि उस पर प्लेकार्ड न लगा हो। स्रोत: HRS 291C-93; हवाई CDL मैनुअल।"},"63":{"q":"जब किसी हवाई CDL चालक को रेलरोड क्रॉसिंग पर रुकना होता है और फिर पटरियों के पार जाना होता है, तो गियर के संबंध में कानून क्या अपेक्षा करता है?","options":["जैसे ही आगे के पहिये पहली रेल पर हों, सबसे निचले गियर में डाउनशिफ्ट करें","ऐसे गियर में पार करें जिसमें गियर बदलने की जरूरत न हो, और पटरियों पर रहते हुए गियर न बदलें","न्यूट्रल में शिफ्ट करें और पटरियों के पार कोस्ट करें","पटरियों को जल्दी पार करने के लिए संभव उच्चतम गियर का उपयोग करें"],"explanation":"HRS 291C-93 चालक से यह अपेक्षा करता है कि वह ऐसे गियर में पार करे जिसमें गियर बदलने की आवश्यकता न हो, और चालक को पटरियों को पार करते समय गियर नहीं बदलना चाहिए। स्रोत: HRS 291C-93; हवाई CDL मैनुअल।"},"64":{"q":"हवाई कानून के तहत, एक बस या प्लेकार्ड लगे वाहन को जिसे सामान्यतः रेलरोड क्रॉसिंग पर रुकना आवश्यक है, किस स्थिति में रुकना आवश्यक नहीं है?","options":["जब क्रॉसिंग पर केवल दो पटरियां हों","जब चालक पटरी पर कम से कम 400 फीट नीचे तक देख सके","जब कोई पुलिस अधिकारी या ट्रैफिक-नियंत्रण सिग्नल यातायात को आगे बढ़ने का निर्देश दे","जब वाहन निर्धारित समय से पीछे चल रहा हो"],"explanation":"HRS 291C-93 अनिवार्य रुकाव से छूट देता है जहां कोई पुलिस अधिकारी या कार्यरत ट्रैफिक-नियंत्रण सिग्नल यातायात को आगे बढ़ने का निर्देश देता है; यह व्यवसाय या आवासीय जिले के भीतर स्ट्रीट-रेलवे ग्रेड क्रॉसिंग पर भी लागू नहीं होता। स्रोत: HRS 291C-93।"},"65":{"q":"हवाई का स्कूल-बस पासिंग कानून तब लागू होता है जब एक रुकी हुई बस के दृश्य सिग्नल किस सेटिंग में सक्रिय हों?","options":["केवल चिह्नित स्कूल ज़ोन में","केवल 25 mph या उससे कम पर निर्धारित सड़कों पर","जहां भी बस रुके, सीमित-पहुंच वाले फ्रीवे सहित","एक आवासीय क्षेत्र में"],"explanation":"HRS 291C-95 रुकने की आवश्यकता को एक आवासीय क्षेत्र में राजमार्ग या सड़क पर रुकी हुई और अपने दृश्य सिग्नल सक्रिय किए हुए स्कूल बस से जोड़ता है। स्रोत: HRS 291C-95।"},"66":{"q":"जब हवाई का स्कूल-बस कानून आपको बच्चों को चढ़ाने या उतारने वाली बस के लिए रुकने की अपेक्षा करता है, तो आपको बस से कितनी दूरी पर रुकना चाहिए?","options":["स्कूल बस से 20 फीट से कम नहीं","स्कूल बस से 10 फीट से कम नहीं","स्कूल बस से 30 फीट से कम नहीं","स्कूल बस से 50 फीट से कम नहीं"],"explanation":"HRS 291C-95 बस की लेन और आसन्न लेन में चालकों से स्कूल बस से 20 फीट से कम नहीं रुकने और तब तक रुके रहने की अपेक्षा करता है जब तक कि वह गति फिर से शुरू न कर ले और सिग्नल बंद न हो जाएं। कई राज्य केवल 'रुकें' कहते हैं; हवाई 20 फीट निर्दिष्ट करता है। स्रोत: HRS 291C-95।"},"67":{"q":"हवाई में एक अविभाजित दो-लेन वाली आवासीय सड़क पर, एक स्कूल बस लाल रोशनी चमकाते हुए और अपनी स्टॉप आर्म बाहर निकालकर रुकती है। किसे रुकना चाहिए?","options":["केवल बस के पीछे का यातायात रुकना चाहिए","केवल बस की समान लेन में यातायात रुकना चाहिए","दोनों दिशाओं में यातायात रुकना चाहिए","किसी को रुकने की आवश्यकता नहीं क्योंकि कोई मीडियन नहीं है"],"explanation":"एक अविभाजित मार्ग पर, HRS 291C-95 बस की लेन और सभी आसन्न लेन में वाहनों पर लागू होता है, चाहे दिशा कोई भी हो, इसलिए पीछे और सामने से आ रहे दोनों यातायात को कम से कम 20 फीट दूर रुकना चाहिए। स्रोत: HRS 291C-95।"},"68":{"q":"हवाई के स्कूल-बस कानून के तहत, विभाजित-मार्ग अपवाद कब सामने से आ रहे यातायात को रुकी हुई बस के लिए रुके बिना आगे बढ़ने देता है?","options":["जब भी सड़क पर प्रत्येक दिशा में दो या अधिक लेन हों","जब भी सड़क पर एक रंगी हुई केंद्र रेखा हो","केवल जब एक क्रॉसिंग गार्ड यातायात को आगे बढ़ने का इशारा करे","जब बस और वाहन एक हस्तक्षेपकारी स्थान, भौतिक अवरोध, या स्पष्ट रूप से इंगित विभाजन खंड से अलग किए गए विभिन्न मार्गों पर हों"],"explanation":"HRS 291C-95 कहता है कि रुकने की आवश्यकता तब लागू नहीं होती जब बस और वाहन विभिन्न मार्गों पर हों; जहां एक आवासीय सड़क एक हस्तक्षेपकारी स्थान, भौतिक अवरोध, या स्पष्ट रूप से इंगित विभाजन खंड से विभाजित होती है, वहां केवल बस के समान ओर के चालकों को रुकना चाहिए। स्रोत: HRS 291C-95।"},"69":{"q":"हवाई में एक स्कूल बस अपने वैकल्पिक रूप से चमकते लाल लैंप से रुकने का संकेत देती है। कानून के तहत वे सिग्नल लैंप कितनी दूरी से स्पष्ट रूप से दिखाई देने चाहिए?","options":["सामान्य धूप में 200 फीट","सामान्य धूप में 500 फीट","सामान्य धूप में 1,000 फीट","सामान्य धूप में 300 फीट"],"explanation":"HRS 291C-95 बस के चार लाल सिग्नल लैंप को वैकल्पिक रूप से चमकते हुए और सामान्य धूप में 500 फीट की दूरी पर स्पष्ट रूप से दिखाई देने वाले के रूप में वर्णित करता है। स्रोत: HRS 291C-95।"},"70":{"q":"भारी वाणिज्यिक वाहनों के लिए हवाई का 2024 का बाईं-लेन प्रतिबंध किस वाहन वजन पर लागू होता है?","options":["10,000 पाउंड या अधिक","5,000 पाउंड या अधिक","26,001 पाउंड या अधिक","80,000 पाउंड या अधिक"],"explanation":"HRS 291C-55 (1 जनवरी, 2024 से प्रभावी) 10,000 पाउंड या अधिक वजन वाले वाणिज्यिक वाहन को सबसे बाईं लेन से रोकता है जहां एक ही दिशा में तीन या अधिक लेन हों, जब तक कि वह गति बनाए न रखे, ओवरटेक न करे, या बाईं ओर मुड़कर/निकलकर न जाए। स्रोत: HRS 291C-55।"},"71":{"q":"हवाई का भारी-वाहन बाईं-लेन निषेध (2024 से प्रभावी) एक ही दिशा में कितनी लेन वाले मार्गों पर लागू होता है?","options":["एक ही दिशा में दो या अधिक लेन","एक ही दिशा में चार या अधिक लेन","लेन संख्या की परवाह किए बिना कोई भी बहु-लेन सड़क","एक ही दिशा में तीन या अधिक लेन"],"explanation":"HRS 291C-55 केवल वहां लागू होता है जहां एक मार्ग पर एक ही दिशा में चल रहे यातायात के लिए तीन या अधिक लेन हों; वहां, 10,000 lbs या अधिक का वाणिज्यिक वाहन सबसे बाईं लेन का उपयोग नहीं कर सकता सिवाय गति बनाए रखने, ओवरटेक करने, या बाईं ओर मुड़ने/निकलने के। स्रोत: HRS 291C-55।"},"72":{"q":"भारी वाणिज्यिक वाहनों के लिए हवाई के बाईं-लेन कानून के तहत, सबसे बाईं लेन का कौन सा उपयोग अभी भी अनुमत है?","options":["लंबी ढलान पर स्थिर गति बनाए रखने के लिए बाईं लेन में चलना","एक ही दिशा में जा रहे दूसरे वाहन को ओवरटेक करना और पास करना","दाईं ओर बार-बार मर्ज होने वाले यातायात से बचने के लिए बाईं ओर बने रहना","जब भी यातायात कम हो, बाईं लेन का उपयोग करना"],"explanation":"HRS 291C-55 एक भारी वाणिज्यिक वाहन को सबसे बाईं लेन में केवल तभी अनुमति देता है जब वह मौजूदा यातायात प्रवाह के साथ गति बनाए रख रहा हो, ओवरटेक और पास कर रहा हो, या बाईं ओर मुड़ने या निकलने की तैयारी कर रहा हो। स्रोत: HRS 291C-55।"},"73":{"q":"हवाई के बहु-लेन राजमार्ग पर, एक वाणिज्यिक वाहन जो यातायात की सामान्य गति से धीमा चल रहा है, उसे आम तौर पर किस लेन में चलना चाहिए?","options":["यातायात प्रवाह को संतुलित करने के लिए केंद्र लेन","मर्ज होने वाले यातायात से बाहर रहने के लिए सबसे बाईं लेन","उपलब्ध दाहिनी-ओर की लेन, या मार्ग के दाहिने किनारे के यथासंभव निकट","कोई भी लेन, जब तक टर्न सिग्नल का उपयोग किया जाए"],"explanation":"HRS 291C-41 सामान्य यातायात गति से धीमा चल रहे वाहन से दाईं ओर रहने की अपेक्षा करता है—दाहिनी-ओर की लेन में या दाहिने किनारे के यथासंभव निकट—सिवाय ओवरटेक करने या बाईं ओर मुड़ने की तैयारी के समय। स्रोत: HRS 291C-41।"},"74":{"q":"हवाई राजमार्ग के एक खंड के लिए अधिकतम गति सीमा कानूनी रूप से कैसे स्थापित की जाती है?","options":["काउंटी अध्यादेश द्वारा या परिवहन निदेशक द्वारा लगाए गए आधिकारिक संकेतों द्वारा","सभी राजमार्गों के लिए 70 mph की एकल निश्चित राज्यव्यापी अधिकतम द्वारा","केवल सभी अंतरराज्यीय मार्गों के लिए संघीय सरकार द्वारा","प्रत्येक व्यक्तिगत पुलिस जिले के विवेक द्वारा"],"explanation":"हवाई में कोई एकल वैधानिक राज्यव्यापी अधिकतम नहीं है; HRS 291C-102 के तहत अधिकतम (और न्यूनतम) गति सीमा काउंटी अध्यादेश द्वारा या परिवहन निदेशक द्वारा लगाए गए आधिकारिक संकेतों द्वारा निर्धारित की जाती है, और चालकों को निर्धारित सीमा का पालन करना चाहिए। स्रोत: HRS 291C-102।"},"75":{"q":"निर्धारित सीमा की परवाह किए बिना एक हवाई CDL चालक को कौन सा बुनियादी गति नियम पालन करना चाहिए?","options":["यातायात को चलते रखने के लिए हमेशा कम से कम निर्धारित सीमा पर गाड़ी चलाएं","हर समय सड़क पर सबसे धीमे वाहन की गति से मिलान करें","कार्गो ले जाते समय जब भी निर्धारित सीमा से 5 mph कम गाड़ी चलाएं","जो वास्तविक और संभावित परिस्थितियों के लिए उचित और विवेकपूर्ण है उससे कभी तेज गाड़ी न चलाएं"],"explanation":"HRS 291C-101 (बुनियादी नियम) वास्तविक और संभावित खतरों एवं परिस्थितियों को देखते हुए उचित और विवेकपूर्ण से तेज गाड़ी चलाने पर रोक लगाता है; बारिश, कोहरे, या भारी यातायात में एक CMV को निर्धारित सीमा से कम पर जाने की आवश्यकता हो सकती है। स्रोत: HRS 291C-101।"},"76":{"q":"जब एक हवाई CDL चालक दो-लेन, दो-तरफा सड़क पर एक ट्रक रोकता है, तो तीन परावर्तक चेतावनी त्रिकोण कहां रखे जाने चाहिए?","options":["तीनों को वाहन के पीछे 50 फीट पर एक पंक्ति में रखा जाए","पीछे से 10 फीट के भीतर, वाहन के 200 फीट पीछे, और 200 फीट आगे","पीछे से 10 फीट के भीतर, लगभग 100 फीट पीछे, और वाहन के लगभग 100 फीट आगे","एक फ्रंट बम्पर पर और दो कैब के बगल में शोल्डर पर"],"explanation":"हवाई CDL मैनुअल (49 CFR 392.22 का अनुसरण करते हुए) निर्देश देता है कि दो-तरफा सड़क पर, एक त्रिकोण पीछे से 10 फीट के भीतर यातायात की ओर वाली ओर रखें, एक लगभग 100 फीट पीछे, और एक लगभग 100 फीट आगे। स्रोत: हवाई CDL मैनुअल।"},"77":{"q":"जब एक हवाई CDL चालक एक-तरफा या विभाजित राजमार्ग पर रुकता है, तो चेतावनी त्रिकोण कहां रखे जाने चाहिए?","options":["वाहन के आगे 50, 100, और 150 फीट पर समान रूप से दूरी पर","वाहन के पीछे निकट आ रहे यातायात की ओर लगभग 10 फीट, 100 फीट, और 200 फीट पर","एक 10 फीट पीछे और दो शोल्डर पर 500 फीट पीछे","तीनों वाहन के पीछे 25 फीट के भीतर"],"explanation":"हवाई CDL मैनुअल निर्देश देता है कि एक-तरफा या विभाजित राजमार्ग पर त्रिकोण निकट आ रहे यातायात की ओर वाहन से लगभग 10 फीट, 100 फीट, और 200 फीट पर रखे जाएं। स्रोत: हवाई CDL मैनुअल।"},"78":{"q":"एक हवाई CDL चालक दो-लेन वाली सड़क पर एक पहाड़ी की चोटी के ठीक आगे रुकता है जो निकट आ रहे यातायात का दृश्य अवरुद्ध करती है। चालक को पीछे के चेतावनी त्रिकोण के साथ क्या करना चाहिए?","options":["इसे मानक 100 फीट पर छोड़ दें क्योंकि दूरियां कभी नहीं बदलतीं","इसे केवल ट्रक के 10 फीट पीछे सीधे केंद्र रेखा पर रखें","पीछे का त्रिकोण छोड़ दें क्योंकि पहाड़ी पहले से ही ट्रक को छिपा देती है","पीछे के त्रिकोण को पहाड़ी के दूर वाली ओर तक, ट्रक से 500 फीट तक पीछे ले जाएं, ताकि चालकों को अवरोध से पहले चेतावनी मिले"],"explanation":"हवाई CDL मैनुअल बताता है कि यदि कोई पहाड़ी, मोड़, या अन्य अवरोध चालकों को 500 फीट के भीतर ट्रक देखने से रोकता है, तो पीछे के चेतावनी उपकरण को सड़क पर पीछे की ओर—500 फीट तक—ले जाना चाहिए ताकि निकट आ रहे चालकों को पर्याप्त चेतावनी मिले। स्रोत: हवाई CDL मैनुअल।"},"79":{"q":"हवाई में, एक CDL आवेदक वाणिज्यिक चालक लाइसेंस के लिए आवेदन करने और प्राप्त करने के लिए वास्तव में कहां जाता है?","options":["एक क्षेत्रीय FMCSA फील्ड कार्यालय में","काउंटी चालक लाइसेंसिंग कार्यालयों में से एक में (जैसे, Honolulu Customer Services, Maui/Kauai Finance, Hawaii County VRLD)","Honolulu में हवाई DOT मुख्यालय को आवेदन डाक से भेजकर","राज्यव्यापी किसी भी U.S. Postal Service स्थान पर"],"explanation":"हवाई CDL चार काउंटी चालक लाइसेंसिंग कार्यालयों के माध्यम से जारी किए जाते हैं, जो State of Hawaii DOT Motor Vehicle Safety Office (MVSO) की देखरेख में संचालित होते हैं। स्रोत: हवाई DOT MVSO 'How to Apply for a CDL' नोटिस और काउंटी CDL पेज (Honolulu CSD, Maui/Kauai Finance, Hawaii County VRLD)।"},"80":{"q":"एक हवाई CDL आवेदक को अपने ड्राइविंग के प्रकार को स्वयं-प्रमाणित करते समय वाणिज्यिक संचालन की कितनी अलग-अलग स्वयं-प्रमाणन श्रेणियों में से चुनना होता है?","options":["दो","चार","तीन","छह"],"explanation":"हवाई आवेदक चार श्रेणियों में से एक के लिए स्वयं-प्रमाणन करते हैं: Non-excepted interstate, Excepted interstate, Non-excepted intrastate, या Excepted intrastate। स्रोत: हवाई DOT MVSO CDL Medical Certification Requirements FAQ (Rev. 5/19/2025)।"},"81":{"q":"चार हवाई स्वयं-प्रमाणन श्रेणियों में से किसके लिए Medical Examiner's Certificate (Form MCSA-5876) जमा करना आवश्यक नहीं है?","options":["Excepted interstate","Non-excepted interstate","Non-excepted intrastate","चारों श्रेणियों के लिए MEC आवश्यक है"],"explanation":"हवाई MVSO FAQ के अनुसार, 'Excepted interstate' (या excepted intrastate) के रूप में स्वयं-प्रमाणन करने वाले चालकों को MEC जमा करना आवश्यक नहीं है; केवल Non-excepted interstate और Non-excepted intrastate चालकों को ही करना होगा। स्रोत: हवाई DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)।"},"82":{"q":"19 मई, 2025 से शुरू होकर, एक हवाई Non-excepted CDL चालक का Medical Examiner's Certificate (MCSA-5876) कैसे जमा किया जाना चाहिए?","options":["काउंटी CDL कार्यालय में जमा की गई एक भौतिक कागजी प्रति के रूप में","चालक द्वारा हवाई DOT MVSO वेबसाइट पोर्टल पर अपलोड किया गया","चालक के नियोक्ता द्वारा FMCSA को डाक से भेजा गया","प्रमाणित चिकित्सा परीक्षक के माध्यम से सीधे FMCSA National Registry डेटाबेस को"],"explanation":"19 मई, 2025 से, HDOT और काउंटी CDL कार्यालय अब भौतिक MEC प्रतियां स्वीकार नहीं करते; प्रमाणित चिकित्सा परीक्षक MEC को सीधे FMCSA National Registry को जमा करता है, जो डेटा को हवाई की चालक लाइसेंस प्रणाली को प्रेषित करता है। स्रोत: हवाई DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)।"},"83":{"q":"कौन से तीन भाग हवाई CDL कौशल परीक्षण को बनाते हैं, जिन सभी को एक ही अपॉइंटमेंट पर पास करना होगा?","options":["Air brakes, लिखित hazmat, और ऑन-रोड ड्राइविंग","Pre-trip निरीक्षण, दृष्टि स्क्रीनिंग, और सामान्य ज्ञान परीक्षण","Pre-trip निरीक्षण, बुनियादी वाहन नियंत्रण, और ऑन-रोड ड्राइविंग","Backing, coupling/uncoupling, और एक लिखित एंडोर्समेंट परीक्षा"],"explanation":"हवाई CDL कौशल परीक्षण के तीन भाग हैं: pre-trip निरीक्षण, बुनियादी वाहन नियंत्रण, और ऑन-रोड ड्राइविंग परीक्षण, जो सभी एक ही अपॉइंटमेंट पर पास किए जाते हैं। स्रोत: हवाई DOT MVSO 'How to Apply for a CDL' नोटिस और Honolulu CSD CDL कार्यालय पेज।"},"84":{"q":"एक हवाई CDL निर्देश (वाणिज्यिक लर्नर) परमिट कितने समय तक वैध रहता है?","options":["छह महीने","एक वर्ष","दो वर्ष","180 दिन"],"explanation":"हवाई का CDL निर्देश परमिट एक वर्ष के लिए वैध होता है और धारक को पर्यवेक्षण के तहत ड्राइविंग का अभ्यास करने देता है। स्रोत: हवाई DOT MVSO 'How to Apply for a CDL' नोटिस।"},"85":{"q":"एक हवाई CLP जारी होने के बाद, धारक को CDL कौशल परीक्षण देने से पहले कितने समय तक प्रतीक्षा करनी चाहिए?","options":["30 दिन","7 दिन","10 दिन","14 दिन"],"explanation":"हवाई में लागू संघीय नियम कौशल परीक्षण से पहले कम से कम 14 दिन CLP धारण करने की अपेक्षा करता है; Honolulu CSD नोट करता है कि कौशल-परीक्षण अपॉइंटमेंट परमिट जारी होने के 14 दिन बाद बनाए जा सकते हैं। स्रोत: Honolulu CSD CDL कार्यालय पेज; 49 CFR 383.25।"},"86":{"q":"एक हवाई Class A/B CDL आवेदक को CDL कौशल परीक्षण देने से पहले कौन सा प्रशिक्षण पूरा करना चाहिए (7 फरवरी, 2022 से प्रभावी)?","options":["एक राज्य-संचालित रक्षात्मक ड्राइविंग पाठ्यक्रम","एक 40-घंटे का हवाई DOT कक्षा सुरक्षा सेमिनार","केवल-नियोक्ता ऑन-द-जॉब अप्रेंटिसशिप","FMCSA-पंजीकृत Entry-Level Driver Training (ELDT)"],"explanation":"7 फरवरी, 2022 से, एक प्रारंभिक Class A/B CDL (और कुछ एंडोर्समेंट) के आवेदकों को परीक्षण से पहले FMCSA Training Provider Registry पर एक प्रदाता के साथ FMCSA Entry-Level Driver Training पूरा करना होगा। स्रोत: FMCSA ELDT नियम जैसा कि Honolulu CSD CDL कार्यालय पेज द्वारा लागू किया गया।"},"87":{"q":"एक पूर्ण (अप्रतिबंधित) हवाई CDL प्राप्त करने के लिए न्यूनतम आयु क्या है?","options":["18","19","25","21"],"explanation":"हवाई एक पूर्ण CDL के लिए आवेदक की आयु 21 वर्ष होने की अपेक्षा करता है (एक CDL परमिट 18 वर्ष की आयु में प्राप्त किया जा सकता है)। स्रोत: हवाई DOT MVSO 'How to Apply for a CDL' नोटिस और Honolulu CSD CDL कार्यालय पेज।"},"88":{"q":"एक हवाई CDL आवेदक को दृष्टि परीक्षण पर कौन सा न्यूनतम दृष्टि मानक पूरा करना चाहिए?","options":["प्रत्येक आंख में 20/40 (corrected स्वीकार्य)","प्रत्येक आंख में 20/20, केवल uncorrected","बेहतर आंख में 20/50","दोनों आंखों से संयुक्त रूप से 20/30"],"explanation":"हवाई CDL दृष्टि परीक्षण के लिए प्रत्येक आंख में न्यूनतम 20/40 की अपेक्षा करता है, जिसमें corrective lenses की अनुमति है। स्रोत: Honolulu CSD CDL कार्यालय पेज; हवाई DOT MVSO।"},"89":{"q":"हवाई CDL के लिए आवेदन करते समय इनमें से कौन सा आवश्यक दस्तावेज़ीकरण का हिस्सा है?","options":["एक वर्तमान ट्रकिंग नियोक्ता से एक नोटरीकृत पत्र","एक वैध बुनियादी (गैर-वाणिज्यिक) हवाई चालक लाइसेंस साथ ही पहचान, SSN, और निवास का प्रमाण","एक पासपोर्ट जो पहचान का एकमात्र स्वीकार्य प्रमाण है","तीन वर्षों के प्रमाणित कर रिटर्न"],"explanation":"हवाई CDL आवेदकों को एक वैध हवाई चालक लाइसेंस प्रस्तुत करना होगा और पहचान/आयु (जैसे, जन्म प्रमाणपत्र), Social Security number, और निवास सिद्ध करना होगा। स्रोत: हवाई DOT MVSO 'How to Apply for a CDL' नोटिस और Honolulu CSD CDL कार्यालय पेज।"},"90":{"q":"यदि एक हवाई चालक excepted और non-excepted अंतरराज्यीय वाणिज्य दोनों में संचालन करता है, तो उसे किस स्थिति के रूप में स्वयं-प्रमाणन करना चाहिए?","options":["Non-excepted interstate","Excepted interstate","Excepted intrastate","कोई भी एक, चालक स्वतंत्र रूप से चुन सकता है"],"explanation":"हवाई MVSO दोनों प्रकारों में संचालन करने वाले चालक से 'Non-excepted interstate' चुनने की अपेक्षा करता है ताकि वे दोनों के लिए योग्य बने रहें, जिसके लिए MEC जमा करना भी आवश्यक है। स्रोत: हवाई DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)।"},"91":{"q":"इलेक्ट्रॉनिक MEC जमा करने के संक्रमण के दौरान, चिकित्सा परीक्षक को जमा किए जाने के बाद हवाई MVSO एक CDL चालक को अपने Medical Examiner's Certificate की एक प्रति कितने समय तक साथ रखने की सिफारिश करता है?","options":["जमा करने से 30 दिन से अधिक नहीं","जमा करने से 60 दिन से अधिक नहीं","जमा करने से 15 दिन से अधिक नहीं","ठीक एक वर्ष"],"explanation":"हवाई MVSO संभावित इलेक्ट्रॉनिक-अपडेट विलंब को कवर करने के लिए, जब इसे चिकित्सा परीक्षक को जमा किया गया था उससे 15 दिन से अधिक नहीं तक MEC प्रति साथ रखने की सिफारिश करता है। स्रोत: हवाई DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)।"},"92":{"q":"एक हवाई CDL धारक का चिकित्सा प्रमाणपत्र समाप्त हो जाता है और वे एक नया जमा नहीं करते। किस दिन सभी CDL विशेषाधिकार हटा दिए जाते हैं, जिसके लिए CDL कार्यालय की व्यक्तिगत यात्रा आवश्यक होती है?","options":["दिन 54","दिन 30","दिन 90","दिन 15"],"explanation":"हवाई MVSO के अनुसार, यदि MEC 53 दिनों के भीतर अपडेट हो जाता है तो किसी व्यक्तिगत उपस्थिति या पुनर्स्थापना शुल्क की आवश्यकता नहीं है; दिन 54 पर सभी CDL विशेषाधिकार हटा दिए जाते हैं और चालक को पुनर्स्थापित करने के लिए एक CDL कार्यालय जाना होगा। स्रोत: हवाई DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)।"},"93":{"q":"जिस क्षण एक हवाई चालक का DOT चिकित्सा प्रमाणपत्र समाप्त होता है, उनकी पात्रता का क्या होता है?","options":["वे तुरंत एक वाणिज्यिक मोटर वाहन चलाने के लिए अपात्र हो जाते हैं","वे 90-दिन की स्वचालित ग्रेस अवधि के लिए पूर्ण CDL विशेषाधिकार बनाए रखते हैं","अगली CDL नवीनीकरण तिथि तक कुछ नहीं बदलता","वे बिना किसी चिकित्सा कार्ड के केवल अंतरराज्यीय (intrastate) गाड़ी चलाना जारी रख सकते हैं"],"explanation":"हवाई MVSO बताता है कि जिस क्षण चिकित्सा प्रमाणपत्र समाप्त होता है, चालक एक CMV संचालित करने के लिए अपात्र हो जाता है; MVSO फिर सूचना भेजता है कि चालक अब शारीरिक रूप से योग्य नहीं है। स्रोत: हवाई DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)।"},"94":{"q":"हवाई में, एक CDL धारक आम तौर पर समाप्ति से कितनी पहले अपने वाणिज्यिक चालक लाइसेंस का नवीनीकरण कर सकता है?","options":["केवल सटीक समाप्ति तिथि पर या उसके बाद","समाप्ति तिथि से 30 दिन पहले तक","समाप्ति तिथि से 6 महीने पहले तक","समाप्ति तिथि से 2 वर्ष पहले तक"],"explanation":"हवाई काउंटी कार्यालय (जैसे, Maui) समाप्ति तिथि से पहले छह (6) महीनों के भीतर CDL नवीनीकरण की अनुमति देते हैं। स्रोत: Maui County 'Renewal of Commercial Drivers License' पेज।"},"95":{"q":"आधार लाइसेंस चक्र की परवाह किए बिना, एक हवाई CDL धारक को Hazardous Materials (HazMat) एंडोर्समेंट का कितनी बार नवीनीकरण करना चाहिए?","options":["बिना किसी पृष्ठभूमि जांच के हर 8 वर्ष में","एक नए रोड टेस्ट के साथ हर 2 वर्ष में","हर 5 वर्ष में, एक TSA सुरक्षा खतरा आकलन सहित","केवल एक बार, पहली बार जारी होने के बाद यह कभी समाप्त नहीं होता"],"explanation":"एक HazMat एंडोर्समेंट का हर 5 वर्ष में नवीनीकरण किया जाना चाहिए और इसके लिए HazMat ज्ञान परीक्षण पास करने के साथ-साथ एक TSA सुरक्षा खतरा आकलन (फिंगरप्रिंट-आधारित पृष्ठभूमि जांच) की आवश्यकता होती है। स्रोत: Maui County CDL नवीनीकरण पेज; TSA HazMat Endorsement कार्यक्रम; 49 CFR Part 1572।"},"96":{"q":"जो हवाई चालक Class 3 या Class 4 चालक लाइसेंस रखते हैं और एक CMV संचालित करते हैं, उनकी चिकित्सा-प्रमाणपत्र संबंधी क्या बाध्यता है?","options":["उन्हें Class A धारकों की तरह MEC को FMCSA National Registry को जमा करना होगा","वे MEC को चिकित्सा परीक्षक को जमा नहीं करते लेकिन CMV संचालित करते समय एक प्रति साथ रखनी होगी","वे पूरी तरह छूट प्राप्त हैं और उन्हें किसी चिकित्सा प्रमाणपत्र की बिल्कुल आवश्यकता नहीं है","उन्हें हर वर्ष MVSO को एक कागजी MEC डाक से भेजनी होगी"],"explanation":"हवाई MVSO बताता है कि CMV संचालित करने वाले Class 3/4 लाइसेंस धारक MEC को अपने चिकित्सा परीक्षक को जमा नहीं करते लेकिन उन्हें CMV संचालित करते समय MEC की एक प्रति साथ रखना अभी भी आवश्यक है। स्रोत: हवाई DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)।"},"97":{"q":"कौन सी हवाई एजेंसी CDL चिकित्सा-प्रमाणन प्रक्रिया की देखरेख के लिए जिम्मेदार है और जिसकी ओर एक स्वयं-प्रमाणन निर्देशित किया जाता है?","options":["The Hawaii State Department of Health","The Honolulu Police Department Traffic Division","The Hawaii DOT Motor Vehicle Safety Office (MVSO)","The U.S. Department of Labor"],"explanation":"Hawaii DOT Motor Vehicle Safety Office (MVSO) CDL चिकित्सा प्रमाणन और स्वयं-प्रमाणन का प्रशासन करता है, काउंटी CDL कार्यालयों और FMCSA के साथ काम करता है। स्रोत: हवाई DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)।"},"98":{"q":"49 CFR 391.46 के अनुसरण में हवाई के अद्यतन नियमों के तहत, चिकित्सा प्रमाणन चाहने वाले एक उचित रूप से नियंत्रित इंसुलिन-उपचारित मधुमेह (ITDM) वाले चालक के लिए अब क्या सच है?","options":["चालक को किसी भी प्रमाणन से पहले एक अलग intrastate ITDM छूट के लिए अभी भी MVSO में आवेदन करना होगा","चालक को हवाई में CDL रखने से स्थायी रूप से अयोग्य ठहरा दिया जाता है","चालक को केवल किसी भी फार्मासिस्ट से एक नोट की आवश्यकता है, चिकित्सा परीक्षक की नहीं","एक प्रमाणित चिकित्सा परीक्षक MEC जारी कर सकता है; एक अलग MVSO intrastate ITDM छूट आवेदन की अब आवश्यकता नहीं है"],"explanation":"हवाई MVSO द्वारा अपनाए गए 49 CFR 391.46 के अनुसार, एक प्रमाणित चिकित्सा परीक्षक एक स्थिर, उचित रूप से नियंत्रित ITDM चालक के लिए MEC जारी कर सकता है (MCSA-5870 आकलन का उपयोग करते हुए); एक अलग MVSO intrastate ITDM छूट आवेदन की अब आवश्यकता नहीं है। स्रोत: हवाई DOT MVSO Medical Certification Requirements FAQ (Rev. 5/19/2025)।"}},"ar":{"0":{"q":"بموجب قانون هاواي، ما هو الحد الأقصى للعرض الإجمالي (بما في ذلك الحمولة) للمركبة التي يجوز تشغيلها على طريق عام دون تصريح للحجم الزائد؟","options":["8 أقدام","8 أقدام و6 بوصات","9 أقدام","10 أقدام"],"explanation":"تحظر المادة HRS §291-34 تشغيل مركبة آلية يتجاوز عرضها الإجمالي، بما في ذلك الحمولة، تسعة أقدام على أي طريق أو شارع أو طريق سريع عام في الولاية دون تصريح. (قوانين هاواي المنقحة HRS §291-34؛ دليل CDL في هاواي.)"},"1":{"q":"ما هو الحد الأقصى للارتفاع الإجمالي (بما في ذلك الحمولة) المسموح به للمركبة على طرق هاواي السريعة دون تصريح؟","options":["13 قدمًا","13 قدمًا و6 بوصات","14 قدمًا","15 قدمًا"],"explanation":"تحدد المادة HRS §291-34 الحد الأقصى لارتفاع المركبة، بما في ذلك الحمولة، بأربعة عشر قدمًا. وحتى ضمن هذا الحد، لا يجوز للمركبة المرور تحت جسر أو منشأة إذا تجاوزت الخلوص المعلن لتلك المنشأة. (قوانين هاواي المنقحة HRS §291-34.)"},"2":{"q":"على طرق هاواي السريعة، ما هو الحد الأقصى للطول الإجمالي لمركبة آلية واحدة (وحدة غير مركّبة)، بما في ذلك الحمولة، دون تصريح؟","options":["40 قدمًا","45 قدمًا","53 قدمًا","60 قدمًا"],"explanation":"تحدّ المادة HRS §291-34 المركبة الآلية الواحدة (غير المركّبة) بخمسة وأربعين قدمًا في الطول الإجمالي، بما في ذلك الحمولة. (قوانين هاواي المنقحة HRS §291-34.)"},"3":{"q":"بموجب المادة HRS §291-34، ما هو الحد الأقصى للطول الإجمالي لتركيبة جرار شاحنة ونصف مقطورة، بما في ذلك الحمولة، المسموح به دون تصريح في هاواي؟","options":["60 قدمًا","65 قدمًا","70 قدمًا","75 قدمًا"],"explanation":"تحدّ المادة HRS §291-34 تركيبة جرار الشاحنة ونصف المقطورة بخمسة وستين قدمًا في الطول الإجمالي الكلي، بما في ذلك الحمولة. (قوانين هاواي المنقحة HRS §291-34.)"},"4":{"q":"في هاواي، لا يجوز أن يتجاوز الوزن الإجمالي المفروض على الطريق السريع من قبل أي محور مفرد واحد:","options":["18,000 رطل","20,000 رطل","22,500 رطل","34,000 رطل"],"explanation":"تحدّ المادة HRS §291-35 الوزن الإجمالي على أي محور مفرد بعشرين ألف رطل. (قوانين هاواي المنقحة HRS §291-35.)"},"5":{"q":"يجوز لـ'المحور المزدوج' في هاواي (محوران متتاليان متباعدان أكثر من 40 بوصة ولكن ليس أكثر من 96 بوصة) أن يحمل وزنًا إجماليًا أقصاه:","options":["32,000 رطل","34,000 رطل","36,000 رطل","40,000 رطل"],"explanation":"تحدّ المادة HRS §291-35 المحور المزدوج (محاور متباعدة أكثر من 40 بوصة ولكن ليس أكثر من 96 بوصة) بأربعة وثلاثين ألف رطل. (قوانين هاواي المنقحة HRS §291-35.)"},"6":{"q":"بموجب قانون الوزن في هاواي، لا يجوز أن يتجاوز الوزن الإجمالي المفروض على الطريق السريع من قبل أي عجلة واحدة، سواء كانت مفردة أو مزدوجة التركيب:","options":["8,000 رطل","10,000 رطل","12,000 رطل","13,500 رطل"],"explanation":"تحدّ المادة HRS §291-35 الوزن الإجمالي على أي عجلة واحدة (مفردة أو مزدوجة التركيب) بعشرة آلاف رطل. (قوانين هاواي المنقحة HRS §291-35.)"},"7":{"q":"ما هو الحد الأقصى للوزن الإجمالي الكلي المسموح به لمركبة أو تركيبة على طرق هاواي السريعة دون تصريح للوزن الزائد؟","options":["73,280 رطل","80,000 رطل","88,000 رطل","105,500 رطل"],"explanation":"تحدّ المادة HRS §291-35 الوزن الإجمالي الكلي للمركبة بثمانين ألف رطل، بما يتوافق مع الحد الفيدرالي. (قوانين هاواي المنقحة HRS §291-35.)"},"8":{"q":"يجوز لمجموعتين متتاليتين من المحاور المزدوجة أن تحمل كل منهما 34,000 رطل في هاواي فقط إذا كانت المسافة بين المحور الأول والأخير لمجموعتي المحاور المزدوجة لا تقل عن:","options":["28 قدمًا","32 قدمًا","36 قدمًا","40 قدمًا"],"explanation":"تسمح المادة HRS §291-35 لمجموعتين متتاليتين من المحاور المزدوجة بأن تحمل كل منهما 34,000 رطل فقط عندما تكون المسافة الإجمالية بين المحور الأول والأخير ستة وثلاثين قدمًا أو أكثر، ويبقى الوزن الإجمالي الكلي عند 80,000 رطل أو أقل. (قوانين هاواي المنقحة HRS §291-35.)"},"9":{"q":"المعادلة الواردة في المادة HRS §291-35 التي تربط الوزن الإجمالي المسموح به لمجموعة محاور بتباعد المحاور وعددها تستند إلى أي معيار فيدرالي؟","options":["معادلة الجسر الفيدرالية (معادلة الوزن الإجمالي للجسر)","قاعدة تباعد المحاور CARB","مؤشر تحميل الرصف AASHTO","جدول ساعات الخدمة FMCSA"],"explanation":"تتضمن أحكام وزن مجموعة المحاور في هاواي في المادة HRS §291-35 معادلة الجسر الفيدرالية، التي تربط الوزن المسموح به بعدد المحاور والمسافة بين المحاور القصوى للمجموعة. (قوانين هاواي المنقحة HRS §291-35؛ 23 U.S.C. §127، مطبّقة كقاعدة هاواي.)"},"10":{"q":"من يملك صلاحية إصدار تصريح كتابي يسمح بحركة الحجم الزائد أو الوزن الزائد على طريق سريع تابع للولاية في هاواي؟","options":["رئيس شرطة المقاطعة","مدير النقل","لجنة المرافق العامة","مسؤول ميناء هونولولو"],"explanation":"بموجب المادة HRS §291-36، يصدر مدير النقل تصاريح الحجم الزائد/الوزن الزائد للطرق السريعة التابعة للولاية، بينما يصدرها مهندس المقاطعة للطرق والشوارع التابعة للمقاطعة. (قوانين هاواي المنقحة HRS §291-36؛ قسم الطرق السريعة في Hawaii DOT.)"},"11":{"q":"بالنسبة للحركة على الطرق والشوارع التابعة للمقاطعة في هاواي، من يصدر تصريح الحجم الزائد/الوزن الزائد؟","options":["مدير النقل","مهندس المقاطعة","مكتب رئيس البلدية","إدارة السلامة العامة في الولاية"],"explanation":"تسند المادة HRS §291-36 صلاحية إصدار التصاريح للطرق والشوارع التابعة للمقاطعة إلى مهندس المقاطعة (بينما يتولى مدير النقل الطرق السريعة التابعة للولاية). (قوانين هاواي المنقحة HRS §291-36.)"},"12":{"q":"كيف يجب تقديم طلب الحصول على تصريح الحجم الزائد/الوزن الزائد في هاواي؟","options":["شفهيًا عبر الهاتف إلى مكتب المنطقة","كتابيًا على نماذج يوفرها قسم الطرق السريعة","فقط من خلال وسيط جمركي مرخص","بنشر إشعار في محطة الوزن"],"explanation":"تتطلب المادة HRS §291-36 طلبًا كتابيًا، ويشترط قسم الطرق السريعة في Hawaii DOT تقديمه على نماذجه الموفّرة، بما في ذلك رسومات لترتيب العجلات والأبعاد وتوزيع الحمولة. (قوانين هاواي المنقحة HRS §291-36؛ إجراءات تصاريح الحجم الزائد/الوزن الزائد في Hawaii DOT.)"},"13":{"q":"بالإضافة إلى الطلب، ماذا يشترط قسم الطرق السريعة في هاواي أن يكون لدى مقدّم طلب تصريح الحجم الزائد/الوزن الزائد في الملف؟","options":["شهادة تأمين","رخصة صيد تجاري","سند ميناء موثّق","بطاقة كابينة IRP فيدرالية"],"explanation":"يشترط قسم الطرق السريعة في Hawaii DOT وجود شهادة تأمين في الملف قبل إصدار تصريح الحجم الزائد/الوزن الزائد. (إجراءات تصاريح المركبات ذات الحجم الزائد/الوزن الزائد على الطرق السريعة التابعة للولاية في Hawaii DOT.)"},"14":{"q":"وفقًا لجدول رسوم التصاريح في هاواي، فإن رسوم تصريح الرحلة الواحدة لحمولة تقل عن 1.35 ضعف الوزن المسموح به أو يقل عرضها عن 14 قدمًا هي:","options":["5 دولارات","10 دولارات","25 دولارًا","50 دولارًا"],"explanation":"بموجب المادة HRS §291-36، تكلّف رسوم تصريح الرحلة الواحدة لحمولة تقل عن 1.35 ضعف الحمولة المسموح بها أو يقل عرضها عن 14 قدمًا مبلغ 5 دولارات (وتكون رسوم تصريح الرحلة المستمرة في هذا النطاق 10 دولارات). (قوانين هاواي المنقحة HRS §291-36؛ Hawaii DOT.)"},"15":{"q":"وفقًا لجدول رسوم التصاريح في هاواي، فإن رسوم تصريح الوزن الزائد لحمولة تتجاوز 1.35 ضعف الحمولة المسموح بها هي:","options":["5 دولارات","10 دولارات","25 دولارًا","100 دولار"],"explanation":"تحدد المادة HRS §291-36 رسومًا قدرها 25 دولارًا لتصريح الوزن الزائد عندما تتجاوز الحمولة 1.35 ضعف الحمولة المسموح بها؛ وينطبق المبلغ نفسه (25 دولارًا) على تصريح الحجم الزائد الذي يتجاوز عرضه 14 قدمًا. (قوانين هاواي المنقحة HRS §291-36؛ Hawaii DOT.)"},"16":{"q":"يُطلب تصريح العرض الزائد في هاواي (وتترتب عليه الرسوم الأعلى البالغة 25 دولارًا) بمجرد أن يتجاوز عرض الحمولة:","options":["9 أقدام","10 أقدام","12 قدمًا","14 قدمًا"],"explanation":"في حين أن أي عرض يتجاوز 9 أقدام يتطلب تصريحًا، فإن جدول الرسوم في المادة HRS §291-36 يعامل الحمولة التي يتجاوز عرضها 14 قدمًا باعتبارها تتطلب فئة تصريح الحجم الزائد بقيمة 25 دولارًا. (قوانين هاواي المنقحة HRS §291-36؛ جدول رسوم التصاريح في Hawaii DOT.)"},"17":{"q":"بموجب الأحكام الزراعية في هاواي، متى يجوز لمدير النقل إصدار تصريح يسمح بأوزان تتجاوز حدود المادة HRS §291-35؟","options":["فقط للمركبات المملوكة للولاية","عند نقل المنتجات المحصودة من مكان حصادها أو تخزينها إلى مكان معالجتها أو استخدامها","فقط بين منتصف الليل والساعة 5 صباحًا","أبدًا — لا يُسمح بأي تصاريح وزن زائد للمزارع"],"explanation":"تجيز المادة HRS §291-36 إصدار تصريح لتجاوز حدود الوزن في المادة §291-35 عند نقل المنتجات من مكان حصادها أو تخزينها إلى مكان معالجتها أو استخدامها. (قوانين هاواي المنقحة HRS §291-36.)"},"18":{"q":"أي حركة زراعية في هاواي لا تتطلب أي تصريح على الإطلاق بموجب المادة HRS §291-36؟","options":["أي مركبة زراعية تسافر 10 أميال أو أقل على طريق سريع تابع للولاية","مركبة تُستخدم في العمليات الزراعية وتعبر فقط طريقًا عامًا في موقع معتمد من مدير النقل أو مهندس المقاطعة","أي مركبة تنقل الأناناس بغض النظر عن الوزن","تركيبة يقل وزنها عن 80,000 رطل تحمل القهوة"],"explanation":"تنص المادة HRS §291-36 على أنه لا يُطلب أي تصريح لمركبة تُستخدم في العمليات الزراعية وتعبر فقط طريقًا أو شارعًا أو طريقًا سريعًا عامًا في موقع معتمد من مدير النقل (الطرق السريعة التابعة للولاية) أو مهندس المقاطعة (الطرق التابعة للمقاطعة). (قوانين هاواي المنقحة HRS §291-36.)"},"19":{"q":"إذا أظهر التحليل الهندسي أن جسرًا في هاواي يمكنه أن يحمل بأمان أقل من الحد الأقصى القانوني للوزن الإجمالي، فماذا يجوز للسلطة المسؤولة أن تفعل؟","options":["إغلاق الجسر نهائيًا أمام جميع الشاحنات","وضع وصيانة لافتات تحدّ من الوزن الإجمالي للمركبات العابرة لذلك الجسر","رفع الحد الأقصى للوزن الإجمالي على مستوى الولاية للتعويض","اشتراط ترقية رخصة CDL لذلك المسار"],"explanation":"تسمح المادة HRS §291-35 لمدير النقل (أو مهندس المقاطعة) بوضع وصيانة لافتات تحدّ من الوزن الإجمالي على جسر أو منشأة معينة عندما يُظهر التحليل الهندسي أن قدرتها أقل من الحد الأقصى القانوني؛ ويجب على السائقين الالتزام بالحد المعلن. (قوانين هاواي المنقحة HRS §291-35.)"},"20":{"q":"في هاواي، أي فئة من رخص CDL مطلوبة لقيادة أي تركيبة من المركبات بتصنيف وزن إجمالي مركّب (GCWR) يبلغ 26,001 رطل أو أكثر، عندما يكون للمركبة (المركبات) المقطورة تصنيف وزن إجمالي (GVWR) يتجاوز 10,000 رطل؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"تعرّف هاواي رخصة CDL من الفئة A بأنها أي تركيبة من المركبات بتصنيف GCWR يبلغ 26,001 رطل أو أكثر، شريطة أن يتجاوز تصنيف GVWR للوحدة المقطورة 10,000 رطل. المصدر: المادة HRS Sec. 286-239 ومكتب ترخيص السائقين التجاريين في هونولولو. لا توجد رخصة CDL فيدرالية/في هاواي من 'الفئة D'."},"21":{"q":"بموجب قانون هاواي، تتطلب المركبة الواحدة بتصنيف وزن إجمالي (GVWR) يبلغ 26,001 رطل أو أكثر (أو مثل هذه المركبة وهي تقطر وحدة لا تتجاوز 10,000 رطل) أي فئة من رخص CDL؟","options":["الفئة A","الفئة B","الفئة C","الفئة M"],"explanation":"تصنّف هاواي المركبة الواحدة بتصنيف GVWR يبلغ 26,001 رطل أو أكثر باعتبارها مركبة تجارية آلية من الفئة B. المصدر: المادة HRS Sec. 286-239؛ مكتب CDL في هونولولو. 'الفئة M' هي فئة دراجات نارية، وليست رخصة CDL."},"22":{"q":"يقود سائق في هاواي مركبة يقل تصنيف GVWR لها عن 26,001 رطل وهي مصممة لنقل 16 راكبًا أو أكثر (بمن فيهم السائق) أو تحمل لافتات لمواد خطرة. أي فئة من رخص CDL تنطبق؟","options":["الفئة A","الفئة B","الفئة C","لا حاجة لرخصة CDL"],"explanation":"تغطي رخصة CDL من الفئة C المركبات التي لا تستوفي شروط الفئة A ولا الفئة B لكنها مصممة لنقل 16 راكبًا أو أكثر (بمن فيهم السائق) أو تحمل مواد خطرة موضوعة عليها لافتات. المصدر: المادة HRS Sec. 286-239؛ مكتب CDL في هونولولو."},"23":{"q":"أي رمز تظهير على رخصة CDL في هاواي يخوّل قيادة مركبة تنقل مواد خطرة تتطلب لافتات؟","options":["التظهير N","التظهير T","التظهير H","التظهير P"],"explanation":"يخوّل تظهير H (HazMat) تشغيل مركبة تحمل مواد خطرة موضوعة عليها لافتات. المصدر: دليل CDL في هاواي / مكتب CDL في هونولولو؛ 49 CFR Part 383 (المعتمد من هاواي)."},"24":{"q":"على رخصة CDL في هاواي، أي تظهير مطلوب لقيادة المقطورات المزدوجة والثلاثية؟","options":["التظهير T","التظهير N","التظهير S","التظهير H"],"explanation":"يخوّل تظهير T تشغيل المقطورات المزدوجة والثلاثية. المصدر: دليل CDL في هاواي / مكتب CDL في هونولولو؛ 49 CFR 383.93."},"25":{"q":"أي تظهير تشترطه هاواي لقيادة مركبة صهريج، وهي عمومًا مركبة مصممة لنقل السوائل أو الغازات في صهريج مثبّت بشكل دائم بسعة مقدّرة تتجاوز 1,000 غالون؟","options":["التظهير P","التظهير N","التظهير T","التظهير X"],"explanation":"يُطلب تظهير N (الصهريج) لمركبات الصهاريج؛ وتشير هاواي إلى الصهاريج التي تتجاوز 1,000 غالون. المصدر: مكتب CDL في هونولولو؛ 49 CFR 383.93. يشير الرمز X إلى صهريج + مواد خطرة معًا، وليس الصهريج وحده."},"26":{"q":"أي تظهير يجب أن يحصل عليه حامل رخصة CDL في هاواي لقيادة مركبة مصممة لنقل 16 راكبًا أو أكثر (بمن فيهم السائق)؟","options":["التظهير S","التظهير N","التظهير P","التظهير T"],"explanation":"يُطلب تظهير P (الركاب) لنقل 16 راكبًا أو أكثر، بمن فيهم السائق. المصدر: مكتب CDL في هونولولو؛ 49 CFR 383.93. ويخصّ تظهير S الحافلات المدرسية تحديدًا."},"27":{"q":"لقيادة حافلة مدرسية في هاواي، يجب أن يحمل حامل رخصة CDL تظهير S. أي تظهير إضافي متعلق بالركاب يُطلب أيضًا؟","options":["التظهير N","التظهير T","التظهير H","التظهير P"],"explanation":"يجب أن يحمل سائق الحافلة المدرسية كلا التظهيرين S (الحافلة المدرسية) وP (الركاب). المصدر: دليل CDL في هاواي؛ 49 CFR 383.93، المعتمد من هاواي."},"28":{"q":"ما هو الحد الأدنى للعمر المطلوب للحصول على رخصة CDL في هاواي تخوّل القيادة التجارية بين الولايات (عبر حدود الولايات)؟","options":["18 عامًا","19 عامًا","20 عامًا","21 عامًا"],"explanation":"تتطلب القيادة التجارية بين الولايات حدًا أدنى للعمر يبلغ 21. وقد يُسمح بالتشغيل داخل الولاية فقط عند سن 18. المصدر: مكتب CDL في هونولولو؛ 49 CFR 391.11(b)."},"29":{"q":"قبل التقدم للحصول على رخصة CDL في هاواي، يجب على السائق أولًا الحصول على أي وثيقة من خلال اجتياز اختبار (اختبارات) المعرفة المطلوبة؟","options":["تصريح متعلّم تجاري (CLP)","رخصة CDL مؤقتة احتمالية","بطاقة HazMat مؤقتة","تصريح تعليم الفئة C"],"explanation":"يجب على المتقدمين أولًا الحصول على تصريح متعلّم تجاري (CLP) من خلال اجتياز اختبار (اختبارات) المعرفة قبل إجراء اختبار مهارات CDL. المصدر: مكتب CDL في هونولولو؛ 49 CFR 383.25."},"30":{"q":"بموجب القواعد الفيدرالية المعتمدة من هاواي، إلى متى يجب على السائق أن يحمل تصريح المتعلّم التجاري قبل أن يصبح مؤهلًا لإجراء اختبار مهارات CDL؟","options":["7 أيام على الأقل","14 يومًا على الأقل","30 يومًا على الأقل","60 يومًا على الأقل"],"explanation":"يجب على السائق أن يحمل تصريح CLP لمدة 14 يومًا على الأقل قبل إجراء اختبار المهارات؛ وتجدول هاواي اختبار المهارات في موعد لا يسبق 14 يومًا بعد إصدار التصريح. المصدر: مكتب CDL في هونولولو؛ 49 CFR 383.25(e)."},"31":{"q":"إلى متى يكون تصريح المتعلّم التجاري (CLP) في هاواي صالحًا قبل أن يجب تجديده؟","options":["90 يومًا","180 يومًا","سنة واحدة","سنتان"],"explanation":"تصريح CLP في هاواي صالح لمدة 180 يومًا. المصدر: دليل CDL في هاواي / إرشادات DMV؛ 49 CFR 383.25(c)."},"32":{"q":"أثناء القيادة بموجب تصريح المتعلّم التجاري في هاواي، يجب على حامل التصريح أن:","options":["يقود وحده خلال ساعات النهار فقط","يكون مرافَقًا بحامل رخصة CDL يجلس بجواره","يحمل تظهير الركاب قبل أي تدريب","يقود فقط في ملكية خاصة"],"explanation":"يجب أن يكون حامل تصريح CLP مرافَقًا في جميع الأوقات بشخص يحمل رخصة CDL سارية (للفئة/التظهيرات التي يجري التدرب عليها) يجلس في المقعد الأمامي. المصدر: دليل CDL في هاواي؛ 49 CFR 383.25(a)."},"33":{"q":"أي وثيقة يقبلها مكتب إصدار رخص CDL في هاواي كإثبات للهوية والوجود القانوني لمتقدّم من مواطني الولايات المتحدة؟","options":["بطاقة مكتبة","شهادة ميلاد أمريكية مصدّقة","تسجيل مركبة","فاتورة خدمات فقط"],"explanation":"تشترط هاواي شهادة ميلاد أمريكية مصدّقة (أو إثباتًا معتمدًا آخر) لإثبات الهوية والوجود القانوني. المصدر: قائمة وثائق مكتب CDL في هونولولو."},"34":{"q":"كم عدد وثائق إثبات الإقامة التي يشترط مكتب CDL في هاواي على المتقدّم تقديمها؟","options":["لا شيء","واحدة","اثنتان","أربع"],"explanation":"تشترط هاواي وثيقتي إثبات إقامة لإثبات الإقامة في هاواي لرخصة CDL. المصدر: قائمة وثائق مكتب CDL في هونولولو."},"35":{"q":"أي وثيقة طبية يجب على متقدّم رخصة CDL في هاواي تقديمها لإثبات أهليته البدنية للقيادة؟","options":["شهادة فاحص طبي DOT سارية (MCSA-5876)","نموذج تصريح طب أسنان","إقرار صحي موثّق","وصفة طبية من طبيب الرعاية الأولية"],"explanation":"يجب على المتقدمين تقديم فحص DOT طبي ساري / شهادة فاحص طبي (النموذج MCSA-5876). المصدر: مكتب CDL في هونولولو؛ 49 CFR 391.43."},"36":{"q":"أي فئة من فئات التصديق الذاتي الطبي تنطبق على سائق رخصة CDL في هاواي يعمل عبر حدود الولايات ويخضع لمتطلب الشهادة الطبية الفيدرالي ويستوفيه؟","options":["معفى بين الولايات","غير معفى بين الولايات","معفى داخل الولاية","غير معفى داخل الولاية"],"explanation":"السائق في التجارة بين الولايات الذي يجب أن يستوفي متطلب الشهادة الطبية الفيدرالي في Part 391 يصدّق على نفسه ذاتيًا بأنه غير معفى بين الولايات. المصدر: 49 CFR 383.71(b)، المعتمد من هاواي."},"37":{"q":"منذ 7 فبراير 2022، قبل إجراء اختبار المهارات لأول رخصة CDL من الفئة A أو B في هاواي (أو أول تظهير P أو S أو H)، يجب على المتقدّم إكمال أي متطلب؟","options":["سجل قيادة نظيف لمدة 5 سنوات","تدريب السائقين المبتدئين (ELDT) من FMCSA من مقدّم مسجّل","دورة قيادة دفاعية في أي مدرسة","تدريب مهني لمدة سنتين"],"explanation":"يُطلب تدريب ELDT لأول رخص CDL من الفئة A/B ولأول تظهيرات P أو S أو H؛ ويجب أن يأتي التدريب من مقدّم مدرج في سجل مقدّمي التدريب لدى FMCSA. المصدر: 49 CFR Part 380 (ساري المفعول 7 فبراير 2022)؛ مكتب CDL في هونولولو."},"38":{"q":"بالإضافة إلى اجتياز اختبار معرفة HazMat، ماذا يجب على المتقدّم في هاواي إكماله قبل إصدار تظهير H (HazMat)؟","options":["تقييم تهديد أمني من TSA (فحص الخلفية)","اختبار طريق في مركبة صهريج","فحص انبعاثات","دورة سلامة بحرية"],"explanation":"يشترط القانون الفيدرالي على كل متقدّم لتظهير HazMat اجتياز تقييم تهديد أمني من TSA (فحص الخلفية مع أخذ البصمات) قبل الإصدار، بالإضافة إلى اختبار المعرفة وتدريب ELDT. المصدر: 49 CFR 1572 (TSA)؛ 49 CFR 383.141؛ مكتب CDL في هاواي."},"39":{"q":"في هاواي، يرتكب الشخص مخالفة كبرى تستوجب إسقاط الأهلية بتشغيل مركبة تجارية آلية (CMV) وهو يحمل تركيز كحول في الدم (BAC) لا يقل عن أي مستوى؟","options":["0.02","0.04","0.08","0.10"],"explanation":"تحدد هاواي حد الكحول للمركبات التجارية الآلية عند 0.04 BAC، أي نصف حد 0.08 للسائقين العاديين. ويُعد تشغيل مركبة تجارية آلية بمعدل 0.04 أو أكثر مخالفة كبرى. المصدر: دليل CDL في هاواي (Hawaii DOT) وHRS 286-240؛ 49 CFR 383.51."},"40":{"q":"بموجب قانون الموافقة الضمنية في هاواي، يُعد السائق التجاري، بقيادته على طرق الولاية السريعة، قد أعطى موافقته على ماذا؟","options":["فحص المركبة في أي محطة وزن","اختبار النفَس أو الدم أو البول لمحتوى الكحول أو المخدرات إذا تم اعتقاله","تفتيش الكابينة دون مذكرة","فحص إعادة الاعتماد الطبي كل سنة"],"explanation":"يَعتبر قانون الموافقة الضمنية في هاواي أن أي سائق قد وافق على اختبار النفَس أو الدم أو البول لتحديد تركيز الكحول أو محتوى المخدرات عند اعتقاله قانونيًا. المصدر: HRS 291E-11 (الموافقة الضمنية)؛ دليل CDL في هاواي."},"41":{"q":"أُدين حامل رخصة CDL في هاواي بأول مخالفة كبرى (مثل القيادة تحت تأثير الكحول في مركبة تجارية آلية) بينما لم يكن ينقل مواد خطرة موضوعة عليها لافتات. الحد الأدنى لمدة إسقاط الأهلية هو:","options":["60 يومًا","120 يومًا","سنة واحدة","3 سنوات"],"explanation":"تستوجب أول مخالفة كبرى إسقاط أهلية CDL لمدة سنة واحدة كحد أدنى في هاواي. المصدر: HRS 286-240؛ دليل CDL في هاواي (Hawaii DOT)؛ 49 CFR 383.51 Table 1."},"42":{"q":"إذا وقعت أول مخالفة كبرى بينما يقوم السائق بتشغيل مركبة تجارية آلية تنقل مواد خطرة تتطلب لافتات، تزداد مدة إسقاط الأهلية إلى:","options":["سنة واحدة","18 شهرًا","3 سنوات","5 سنوات"],"explanation":"ترفع أول مخالفة كبرى تُرتكب أثناء نقل مواد خطرة موضوعة عليها لافتات مدة إسقاط الأهلية من سنة واحدة إلى 3 سنوات. المصدر: HRS 286-240؛ دليل CDL في هاواي؛ 49 CFR 383.51 Table 1."},"43":{"q":"ما هي مدة إسقاط الأهلية في هاواي لثاني مخالفة كبرى (تُرتكب في مركبة تجارية آلية) خلال حياة السائق؟","options":["3 سنوات","5 سنوات","10 سنوات","مدى الحياة (الحياة كاملة)"],"explanation":"تؤدي ثاني مخالفة كبرى إلى إسقاط أهلية CDL مدى الحياة في هاواي. المصدر: HRS 286-240؛ دليل CDL في هاواي (Hawaii DOT)؛ 49 CFR 383.51 Table 1."},"44":{"q":"السائق التجاري في هاواي الذي يرفض الخضوع لاختبار الكحول/المخدرات المطلوب تُسقَط أهليته لتشغيل مركبة تجارية آلية لمدة لا تقل عن:","options":["30 يومًا","60 يومًا","سنة واحدة","90 يومًا"],"explanation":"يُعامل رفض الاختبار المطلوب بموجب قانون الموافقة الضمنية باعتباره مخالفة كبرى، ويستوجب نفس الحد الأدنى لإسقاط أهلية CDL البالغ سنة واحدة كأول قيادة تحت تأثير الكحول (3 سنوات إذا كانت المواد الخطرة موضوعة عليها لافتات). المصدر: HRS 286-240 وHRS 291E-11؛ دليل CDL في هاواي."},"45":{"q":"أي مما يلي يُعد مخالفة كبرى (وليس مجرد مخالفة مرورية خطيرة) لحامل رخصة CDL في هاواي؟","options":["اتباع مركبة أخرى عن قرب أكثر من اللازم","تجاوز السرعة بمقدار 15 mph أو أكثر فوق الحد","استخدام مركبة تجارية آلية لارتكاب جناية","تغيير المسار بشكل غير صحيح أو متقلب"],"explanation":"يُعد استخدام مركبة تجارية آلية في ارتكاب جناية مخالفة كبرى. أما الاتباع عن قرب أكثر من اللازم، والإفراط في السرعة، وتغيير المسار بشكل غير صحيح فهي مخالفات مرورية خطيرة، وليست مخالفات كبرى. المصدر: HRS 286-240؛ دليل CDL في هاواي؛ 49 CFR 383.51."},"46":{"q":"تؤدي الإدانة بمخالفتين مروريتين خطيرتين في مركبة تجارية آلية، ناجمتين عن حادثتين منفصلتين خلال فترة 3 سنوات، إلى إسقاط أهلية حامل رخصة CDL في هاواي لمدة:","options":["30 يومًا","60 يومًا","120 يومًا","سنة واحدة"],"explanation":"تؤدي مخالفتان مروريتان خطيرتان خلال 3 سنوات إلى إسقاط أهلية لمدة 60 يومًا. المصدر: HRS 286-240؛ دليل CDL في هاواي (Hawaii DOT)؛ 49 CFR 383.51 Table 2."},"47":{"q":"تؤدي الإدانة بثلاث مخالفات مرورية خطيرة في مركبة تجارية آلية خلال فترة 3 سنوات إلى إسقاط أهلية حامل رخصة CDL في هاواي لمدة:","options":["60 يومًا","90 يومًا","120 يومًا","180 يومًا"],"explanation":"تؤدي ثلاث مخالفات مرورية خطيرة خلال 3 سنوات إلى إسقاط أهلية لمدة 120 يومًا، تُنفَّذ بالإضافة إلى فترة الـ60 يومًا الخاصة بالمخالفتين السابقتين. المصدر: HRS 286-240؛ دليل CDL في هاواي؛ 49 CFR 383.51 Table 2."},"48":{"q":"بكم يجب أن يتجاوز سائق المركبة التجارية الآلية حد السرعة المعلن في هاواي لكي تُحتسب المخالفة 'مخالفة مرورية خطيرة'؟","options":["10 mph أو أكثر","15 mph أو أكثر","20 mph أو أكثر","25 mph أو أكثر"],"explanation":"يُعد الإفراط في السرعة بمقدار 15 mph أو أكثر فوق الحد المعلن مخالفة مرورية خطيرة. المصدر: HRS 286-240؛ دليل CDL في هاواي (Hawaii DOT)؛ 49 CFR 383.51 Table 2."},"49":{"q":"أي مما يلي يُصنّف على أنه مخالفة مرورية خطيرة لحامل رخصة CDL في هاواي؟","options":["وجود تركيز كحول في الدم 0.04 في مركبة تجارية آلية","القيادة المتهورة","رفض اختبار كيميائي","مغادرة موقع الحادث"],"explanation":"القيادة المتهورة مخالفة مرورية خطيرة. أما الثلاث الأخرى فهي مخالفات كبرى. المصدر: HRS 286-240؛ دليل CDL في هاواي؛ 49 CFR 383.51 Tables 1 and 2."},"50":{"q":"قيادة مركبة تجارية آلية دون الفئة الصحيحة من رخصة CDL أو دون وجود رخصة CDL بحوزة السائق تُعامَل في هاواي على أنها:","options":["مخالفة كبرى","مخالفة مرورية خطيرة","مخالفة أمر إخراج من الخدمة","مخالفة معبر سكة حديد"],"explanation":"قيادة مركبة تجارية آلية دون الفئة الصحيحة من الرخصة/التظهير، أو دون وجود رخصة CDL بالحوزة، مخالفة مرورية خطيرة. المصدر: دليل CDL في هاواي (Hawaii DOT)؛ HRS 286-240؛ 49 CFR 383.51 Table 2."},"51":{"q":"بموجب القواعد المنطبقة على سائقي المركبات التجارية الآلية في هاواي، تُصنّف الكتابة النصية أثناء القيادة واستخدام هاتف محمول يدوي على أنها:","options":["مخالفات كبرى","مخالفات مرورية خطيرة","مخالفات معدات دون إسقاط أهلية","مخالفات إخراج من الخدمة"],"explanation":"تُعد الكتابة النصية واستخدام الهاتف اليدوي أثناء قيادة مركبة تجارية آلية مخالفتين مروريتين خطيرتين؛ مخالفتان خلال 3 سنوات تؤديان إلى إسقاط أهلية 60 يومًا وثلاث تؤدي إلى 120 يومًا. المصدر: دليل CDL في هاواي؛ 49 CFR 383.51 و392.80/392.82 (FMCSA)."},"52":{"q":"بالنسبة لسائق مركبة تجارية آلية في هاواي، فإن الحد الأقصى للعقوبة المدنية الفيدرالية لسائق فرد يكتب نصيًا أو يستخدم هاتفًا يدويًا أثناء القيادة يبلغ تقريبًا:","options":["$500","$1,000","$2,750","$11,000"],"explanation":"قد يُغرَّم السائق حتى $2,750 (معدّلة وفق التضخم) للكتابة النصية أو استخدام الهاتف اليدوي في مركبة تجارية آلية؛ ويواجه أصحاب العمل الذين يسمحون بذلك غرامة حتى $11,000. المصدر: FMCSA 49 CFR 392.80/392.82 و383.51، المنطبقة في هاواي."},"53":{"q":"تؤدي أول إدانة لحامل رخصة CDL في هاواي بسبب عدم الالتزام بقانون معبر السكة الحديدية مع الطريق السريع في مركبة تجارية آلية إلى إسقاط أهلية لمدة:","options":["60 يومًا","120 يومًا","سنة واحدة","30 يومًا"],"explanation":"تستوجب أول مخالفة لمعبر السكة الحديدية مع الطريق السريع إسقاط أهلية لمدة 60 يومًا كحد أدنى. المصدر: HRS 286-240؛ دليل CDL في هاواي (Hawaii DOT)؛ 49 CFR 383.51 Table 3."},"54":{"q":"تؤدي ثاني مخالفة لمعبر السكة الحديدية مع الطريق السريع خلال فترة 3 سنوات إلى إسقاط أهلية حامل رخصة CDL في هاواي لمدة لا تقل عن:","options":["60 يومًا","120 يومًا","سنة واحدة","180 يومًا"],"explanation":"تستوجب ثاني مخالفة لمعبر السكة الحديدية خلال 3 سنوات إسقاط أهلية لمدة 120 يومًا كحد أدنى. المصدر: HRS 286-240؛ دليل CDL في هاواي؛ 49 CFR 383.51 Table 3."},"55":{"q":"تؤدي ثالث مخالفة لمعبر السكة الحديدية مع الطريق السريع خلال فترة 3 سنوات إلى إسقاط أهلية لمدة لا تقل عن:","options":["120 يومًا","180 يومًا","سنة واحدة","3 سنوات"],"explanation":"تستوجب ثالث مخالفة لمعبر السكة الحديدية خلال 3 سنوات إسقاط أهلية لمدة سنة واحدة كحد أدنى. المصدر: HRS 286-240؛ دليل CDL في هاواي (Hawaii DOT)؛ 49 CFR 383.51 Table 3."},"56":{"q":"تؤدي أول إدانة لحامل رخصة CDL في هاواي بمخالفة أمر إخراج من الخدمة (OOS) للسائق أو المركبة إلى إسقاط أهلية لمدة:","options":["30 يومًا على الأقل","90 يومًا على الأقل","180 يومًا على الأقل (حتى سنة واحدة)","سنتان على الأقل"],"explanation":"تستوجب أول مخالفة لأمر الإخراج من الخدمة إسقاط أهلية من 180 يومًا حتى سنة واحدة (من 180 يومًا حتى سنتين إذا كان ينقل مواد خطرة أو ركابًا). المصدر: HRS 286-240؛ دليل CDL في هاواي؛ 49 CFR 383.51 Table 4."},"57":{"q":"تؤدي ثاني مخالفة لأمر إخراج من الخدمة في مركبة تجارية آلية خلال فترة 10 سنوات إلى إسقاط أهلية حامل رخصة CDL في هاواي لمدة:","options":["من 180 يومًا إلى سنة واحدة","من سنتين إلى 5 سنوات","من سنة إلى 3 سنوات","مدى الحياة"],"explanation":"تستوجب ثاني مخالفة لأمر الإخراج من الخدمة خلال 10 سنوات إسقاط أهلية من سنتين إلى 5 سنوات (من 3 إلى 5 سنوات للمواد الخطرة/الركاب). المصدر: HRS 286-240؛ دليل CDL في هاواي (Hawaii DOT)؛ 49 CFR 383.51 Table 4."},"58":{"q":"عندما تُفرض مدة إسقاط أهلية في هاواي فوق مدة مفروضة سابقًا (على سبيل المثال، ثالث مخالفة خطيرة تلي المخالفتين السابقتين)، تكون المدة الجديدة:","options":["تُنفَّذ بالتزامن مع المدة السابقة","تُخفَّض بمقدار النصف","تُضاف إلى (تُنفَّذ بالتتابع مع) المدة السابقة","تُلغى إذا طُلبت جلسة استماع"],"explanation":"تُنفَّذ مدد إسقاط الأهلية في هاواي بالتتابع: تكون المدة المفروضة حديثًا بالإضافة إلى أي مدة إسقاط أهلية مفروضة سابقًا. المصدر: HRS 286-240؛ دليل CDL في هاواي؛ 49 CFR 383.51."},"59":{"q":"بموجب قانون \"أفسح الطريق\" (Move Over) في هاواي، عندما يقترب سائق تجاري من مركبة طوارئ متوقفة تعرض أضواءً وامضة على طريق متعدد المسارات، فما الذي يلزم القانون السائق بفعله من بين ما يلي؟","options":["أن يخفّف السرعة إلى سرعة معقولة وحذرة، وأن ينتقل عند توفر الأمان إلى مسار غير ملاصق بعيداً عن مركبة الطوارئ","أن يحافظ على السرعة المعلنة لكن يضغط على البوق مرتين أثناء المرور","أن يتوقف تماماً على الكتف حتى يتم إطفاء أضواء مركبة الطوارئ","أن يخفّض السرعة بمقدار 10 mph بالضبط دون الحد المعلن ويبقى في المسار الأيمن"],"explanation":"يلزم قانون \"أفسح الطريق\" في هاواي (HRS 291C-27) السائقَ المقترب بتخفيف السرعة إلى سرعة معقولة وحذرة تناسب الظروف، وإذا كان ذلك آمناً، الانتقال إلى المسار الملاصق بعيداً عن مركبة الطوارئ (أو مسارين أبعد، مع ترك مسار واحد فاصل). المصدر: HRS 291C-27."},"60":{"q":"يحمي قانون \"أفسح الطريق\" في هاواي المركبات المتوقفة ذات الأضواء الوامضة. أيٌّ مما يلي مُسمّى تحديداً بوصفه \"مركبة طوارئ\" محمية بموجب قانون هاواي؟","options":["سيارة أجرة تنتظر راكباً","شاحنة سحب (قطر)","شاحنة توصيل صغيرة بأضواء التحذير مُشغّلة","سيارة ركاب تقوم بتغيير إطار مثقوب"],"explanation":"يُدرج HRS 291C-27 شاحنات السحب ضمن مركبات الطوارئ المحمية، إلى جانب مركبات الشرطة والإطفاء وخدمات الطوارئ الطبية وسلامة المحيط ودوريات خدمة الطرق السريعة والمأمور (الشريف) والدفاع المدني وشعبة الموانئ ومركبات إنفاذ DLNR. المصدر: HRS 291C-27."},"61":{"q":"عندما يجب على مركبة تحمل لوحات المواد الخطرة أو حافلة تقلّ ركاباً أن تتوقف عند مزلقان سكة حديد في هاواي، فأين يجب أن تتوقف بالنسبة لأقرب قضيب سكة؟","options":["ليس أقل من 5 feet ولكن ليس أكثر من 25 feet من أقرب قضيب","ليس أقل من 25 feet ولكن ليس أكثر من 75 feet من أقرب قضيب","ليس أقل من 15 feet ولكن ليس أكثر من 50 feet من أقرب قضيب","30 feet بالضبط من أقرب قضيب"],"explanation":"يلزم قانون هاواي (HRS 291C-93)، كما يعكسه دليل CDL في هاواي، المركبةَ بالتوقف ضمن 50 feet ولكن ليس أقل من 15 feet من أقرب قضيب، ثم الإصغاء والنظر في كلا الاتجاهين. المصدر: HRS 291C-93؛ دليل CDL في هاواي."},"62":{"q":"وفقاً لقانون هاواي ودليل CDL في هاواي، أيُّ مركبة يُطلب منها التوقف عند كل مزلقان سكة حديد حتى عندما لا يكون أي قطار في الأفق؟","options":["شاحنة مسطّحة فارغة (مستقيمة)","أي شاحنة بمقطورة يزيد طولها عن 40 feet","شاحنة بيك أب تقطر مقطورة خدمية","مركبة تحمل مواد متفجرة أو سوائل قابلة للاشتعال كحمولة"],"explanation":"يلزم HRS 291C-93 المركباتِ التي تنقل ركاباً بأجر، وحافلات المدارس التي تنقل أطفالاً، والمركبات التي تحمل مواد متفجرة أو سوائل قابلة للاشتعال كحمولة، بالتوقف. أما الشاحنة الفارغة أو شاحنة الشحن العام فلا يُطلب منها التوقف ما لم تحمل لوحات المواد الخطرة. المصدر: HRS 291C-93؛ دليل CDL في هاواي."},"63":{"q":"عندما يجب على سائق CDL في هاواي التوقف عند مزلقان سكة حديد ثم المضي عبر القضبان، فماذا يتطلب القانون فيما يتعلق بالتروس؟","options":["التحويل إلى أدنى ترس بمجرد أن تكون العجلات الأمامية على القضيب الأول","العبور بترس لا يحتاج إلى تغيير ترس، وعدم تبديل التروس أثناء الوجود على القضبان","التحويل إلى الوضع المحايد والانزلاق عبر القضبان","استخدام أعلى ترس ممكن لتجاوز القضبان بسرعة"],"explanation":"يلزم HRS 291C-93 السائقَ بالعبور بترس لا يتطلب تغيير التروس، ويجب على السائق ألا يبدّل التروس أثناء العبور فوق القضبان. المصدر: HRS 291C-93؛ دليل CDL في هاواي."},"64":{"q":"بموجب قانون هاواي، فإن الحافلة أو المركبة الحاملة للوحات التي يجب عليها عادةً التوقف عند مزلقان سكة حديد لا يُطلب منها التوقف في أيّ من الحالات التالية؟","options":["عندما يكون للمزلقان قضيبان فقط","عندما يستطيع السائق أن يرى مسافة لا تقل عن 400 feet على طول السكة","عندما يوجّه ضابط شرطة أو إشارة تحكم مروري حركة المرور بالمضي","عندما تكون المركبة متأخرة عن جدولها الزمني"],"explanation":"يعفي HRS 291C-93 من التوقف الإلزامي حيث يوجّه ضابط شرطة أو إشارة تحكم مروري عاملة حركةَ المرور بالمضي؛ كما لا ينطبق عند مزالق السكك الحديدية للشوارع داخل منطقة تجارية أو سكنية. المصدر: HRS 291C-93."},"65":{"q":"ينطبق قانون تجاوز حافلة المدرسة في هاواي عندما تكون حافلة متوقفة قد فعّلت إشاراتها البصرية في أي محيط؟","options":["فقط في منطقة مدرسية محددة بعلامات","فقط على الطرق المعلنة بسرعة 25 mph أو أقل","في أي مكان تتوقف فيه الحافلة، بما في ذلك الطرق السريعة محدودة الوصول","في منطقة سكنية"],"explanation":"يربط HRS 291C-95 شرط التوقف بحافلة مدرسية متوقفة على طريق سريع أو طريق في منطقة سكنية مع تفعيل إشاراتها البصرية. المصدر: HRS 291C-95."},"66":{"q":"عندما يلزمك قانون حافلة المدرسة في هاواي بالتوقف لحافلة تُحمّل أو تُنزل أطفالاً، فعلى أي مسافة من الحافلة يجب أن تتوقف؟","options":["ليس أقل من 20 feet من حافلة المدرسة","ليس أقل من 10 feet من حافلة المدرسة","ليس أقل من 30 feet من حافلة المدرسة","ليس أقل من 50 feet من حافلة المدرسة"],"explanation":"يلزم HRS 291C-95 السائقين في مسار الحافلة والمسارات الملاصقة بالتوقف على مسافة لا تقل عن 20 feet من حافلة المدرسة والبقاء متوقفين حتى تستأنف الحركة وتُطفأ الإشارات. تكتفي ولايات كثيرة بقول \"توقّف\"؛ أما هاواي فتحدد 20 feet. المصدر: HRS 291C-95."},"67":{"q":"على طريق سكني غير مقسوم بمسارين في هاواي، تتوقف حافلة مدرسية بأضوائها الحمراء الوامضة وذراع التوقف ممتدة. من الذي يجب أن يتوقف؟","options":["فقط حركة المرور خلف الحافلة يجب أن تتوقف","فقط حركة المرور في المسار نفسه الذي فيه الحافلة يجب أن تتوقف","حركة المرور في كلا الاتجاهين يجب أن تتوقف","لا أحد يجب أن يتوقف لعدم وجود جزيرة وسطية"],"explanation":"على طريق غير مقسوم، ينطبق HRS 291C-95 على المركبات في مسار الحافلة وجميع المسارات الملاصقة بصرف النظر عن الاتجاه، لذا يجب أن تتوقف حركة المرور خلف الحافلة والقادمة في الاتجاه المعاكس على مسافة لا تقل عن 20 feet. المصدر: HRS 291C-95."},"68":{"q":"بموجب قانون حافلة المدرسة في هاواي، متى يسمح استثناء الطريق المقسوم لحركة المرور القادمة بالمتابعة دون التوقف لحافلة متوقفة؟","options":["كلما كان للطريق مساران أو أكثر في كل اتجاه","كلما كان للطريق خط وسطي مرسوم","فقط عندما يلوّح حارس عبور لحركة المرور بالمرور","عندما تكون الحافلة والمركبة على طريقين مختلفين يفصل بينهما فراغ فاصل أو حاجز مادي أو قسم فاصل مُبيَّن بوضوح"],"explanation":"ينص HRS 291C-95 على أن شرط التوقف لا ينطبق عندما تكون الحافلة والمركبة على طريقين مختلفين؛ وحيث يكون الطريق السكني مقسوماً بفراغ فاصل أو حاجز مادي أو قسم فاصل مُبيَّن بوضوح، فإن السائقين على الجانب نفسه للحافلة فقط هم من يجب أن يتوقفوا. المصدر: HRS 291C-95."},"69":{"q":"تشير حافلة مدرسية في هاواي إلى التوقف بمصابيحها الحمراء التي تومض بالتناوب. على أي مسافة يجب أن تكون مصابيح الإشارة تلك مرئية بوضوح بموجب القانون؟","options":["200 feet في ضوء الشمس العادي","500 feet في ضوء الشمس العادي","1,000 feet في ضوء الشمس العادي","300 feet في ضوء الشمس العادي"],"explanation":"يصف HRS 291C-95 مصابيح الإشارة الحمراء الأربعة للحافلة بأنها تومض بالتناوب وتكون مرئية بوضوح على مسافة 500 feet في ضوء الشمس العادي. المصدر: HRS 291C-95."},"70":{"q":"ينطبق قيد المسار الأيسر لعام 2024 في هاواي على المركبات التجارية الثقيلة عند أي وزن للمركبة؟","options":["10,000 pounds أو أكثر","5,000 pounds أو أكثر","26,001 pounds أو أكثر","80,000 pounds أو أكثر"],"explanation":"يمنع HRS 291C-55 (الساري اعتباراً من 1 يناير 2024) المركبةَ التجارية التي تزن 10,000 pounds أو أكثر من المسار الأقصى يساراً حيث يوجد ثلاثة مسارات أو أكثر في الاتجاه نفسه، إلا عند مجاراة سرعة المرور أو التجاوز أو الانعطاف/الخروج يساراً. المصدر: HRS 291C-55."},"71":{"q":"ينطبق حظر المسار الأيسر للمركبات الثقيلة في هاواي (الساري عام 2024) على الطرق التي بها كم مساراً في الاتجاه نفسه؟","options":["مساران أو أكثر في الاتجاه نفسه","أربعة مسارات أو أكثر في الاتجاه نفسه","أي طريق متعدد المسارات بغض النظر عن عدد المسارات","ثلاثة مسارات أو أكثر في الاتجاه نفسه"],"explanation":"ينطبق HRS 291C-55 فقط حيث يكون للطريق ثلاثة مسارات أو أكثر لحركة المرور المتحركة في الاتجاه نفسه؛ وهناك، لا يجوز للمركبة التجارية التي تزن 10,000 lbs أو أكثر استخدام المسار الأقصى يساراً إلا لمجاراة السرعة أو التجاوز أو الانعطاف/الخروج يساراً. المصدر: HRS 291C-55."},"72":{"q":"بموجب قانون المسار الأيسر للمركبات التجارية الثقيلة في هاواي، أيُّ استخدام للمسار الأقصى يساراً لا يزال مسموحاً؟","options":["السير في المسار الأيسر للحفاظ على سرعة ثابتة على منحدر طويل هابط","اللحاق بمركبة أخرى وتجاوزها متجهةً في الاتجاه نفسه","البقاء يساراً لتجنب حركة الاندماج المتكررة على اليمين","استخدام المسار الأيسر في أي وقت تكون فيه حركة المرور خفيفة"],"explanation":"يسمح HRS 291C-55 للمركبة التجارية الثقيلة بالوجود في المسار الأقصى يساراً فقط عند مجاراة تدفق المرور القائم، أو اللحاق والتجاوز، أو الاستعداد للانعطاف يساراً أو الخروج. المصدر: HRS 291C-55."},"73":{"q":"على طريق سريع متعدد المسارات في هاواي، فإن المركبة التجارية التي تتحرك أبطأ من السرعة المعتادة لحركة المرور ينبغي عموماً أن تسير في أي مسار؟","options":["المسار الأوسط لموازنة تدفق المرور","المسار الأقصى يساراً للابتعاد عن حركة الاندماج","المسار الأيمن المتاح، أو أقرب ما يمكن عملياً إلى الحافة اليمنى للطريق","أي مسار، طالما تُستخدم إشارات الانعطاف"],"explanation":"يلزم HRS 291C-41 المركبةَ التي تسير أبطأ من السرعة المعتادة للمرور بالبقاء يميناً — في المسار الأيمن أو أقرب ما يمكن عملياً إلى الحافة اليمنى — إلا عند التجاوز أو الاستعداد للانعطاف يساراً. المصدر: HRS 291C-41."},"74":{"q":"كيف يُحدَّد قانونياً الحد الأقصى للسرعة لمقطع من طريق سريع في هاواي؟","options":["بموجب مرسوم من المقاطعة أو بعلامات رسمية يضعها مدير النقل","بحد أقصى ثابت واحد على مستوى الولاية يبلغ 70 mph لجميع الطرق السريعة","من قبل الحكومة الفيدرالية لجميع الطرق بين الولايات فقط","حسب تقدير كل منطقة شرطة على حدة"],"explanation":"ليس لهاواي حد أقصى تشريعي واحد على مستوى الولاية؛ فبموجب HRS 291C-102 يُحدَّد الحد الأقصى (والأدنى) للسرعة بمرسوم من المقاطعة أو بعلامات رسمية يضعها مدير النقل، ويجب على السائقين الالتزام بالحد المعلن. المصدر: HRS 291C-102."},"75":{"q":"ما هي قاعدة السرعة الأساسية التي يجب على سائق CDL في هاواي اتباعها بغض النظر عن الحد المعلن؟","options":["القيادة دائماً بسرعة لا تقل عن الحد المعلن للحفاظ على تدفق المرور","مجاراة سرعة أبطأ مركبة على الطريق في جميع الأوقات","القيادة بسرعة 5 mph دون الحد المعلن كلما كانت هناك حمولة","عدم القيادة بسرعة أكبر مما هو معقول وحذر بالنسبة للظروف الفعلية والمحتملة"],"explanation":"يحظر HRS 291C-101 (القاعدة الأساسية) القيادةَ بسرعة أكبر مما هو معقول وحذر بالنظر إلى المخاطر والظروف الفعلية والمحتملة؛ وقد تحتاج المركبة التجارية إلى السير دون الحد المعلن في المطر أو الضباب أو الازدحام المروري. المصدر: HRS 291C-101."},"76":{"q":"بعد أن يوقف سائق CDL في هاواي شاحنة على طريق ذي مسارين وباتجاهين، أين يجب وضع مثلثات التحذير العاكسة الثلاثة؟","options":["وضع الثلاثة جميعاً في صف على بُعد 50 feet خلف المركبة","ضمن 10 feet من المؤخرة، و200 feet خلف المركبة، و200 feet أمامها","ضمن 10 feet من المؤخرة، وحوالي 100 feet خلف المركبة، وحوالي 100 feet أمامها","واحد عند المصد الأمامي واثنان على الكتف بجوار المقصورة"],"explanation":"يوجّه دليل CDL في هاواي (تبعاً لـ 49 CFR 392.22)، على طريق ذي اتجاهين، بوضع مثلث واحد ضمن 10 feet من المؤخرة على جانب المرور، وواحد على بُعد حوالي 100 feet إلى الخلف، وواحد على بُعد حوالي 100 feet إلى الأمام. المصدر: دليل CDL في هاواي."},"77":{"q":"عندما يتوقف سائق CDL في هاواي على طريق سريع باتجاه واحد أو مقسوم، أين ينبغي وضع مثلثات التحذير؟","options":["متباعدة بالتساوي على بُعد 50 و100 و150 feet أمام المركبة","على بُعد حوالي 10 feet و100 feet و200 feet باتجاه حركة المرور القادمة خلف المركبة","واحد على بُعد 10 feet خلفها واثنان على بُعد 500 feet خلفها على الكتف","الثلاثة جميعاً ضمن 25 feet من مؤخرة المركبة"],"explanation":"يوجّه دليل CDL في هاواي بأنه على طريق باتجاه واحد أو مقسوم تُوضع المثلثات باتجاه حركة المرور القادمة على بُعد حوالي 10 feet و100 feet و200 feet من المركبة. المصدر: دليل CDL في هاواي."},"78":{"q":"يتوقف سائق CDL في هاواي على طريق ذي مسارين بعد قمة تلة مباشرةً تحجب رؤية حركة المرور القادمة. ماذا ينبغي للسائق أن يفعل بمثلث التحذير الخلفي؟","options":["تركه عند المسافة القياسية 100 feet لأن المسافات لا تتغير أبداً","وضعه مباشرةً على الخط الوسطي على بُعد 10 feet خلف الشاحنة فقط","تخطّي المثلث الخلفي لأن التلة تخفي الشاحنة بالفعل","تحريك المثلث الخلفي إلى الجانب البعيد من التلة، حتى 500 feet من الشاحنة، لتحذير السائقين قبل العائق"],"explanation":"ينص دليل CDL في هاواي على أنه إذا كانت تلة أو منعطف أو عائق آخر يمنع السائقين من رؤية الشاحنة ضمن 500 feet، فينبغي تحريك جهاز التحذير الخلفي إلى الخلف على الطريق — حتى 500 feet — لكي يحصل السائقون القادمون على تحذير كافٍ. المصدر: دليل CDL في هاواي."},"79":{"q":"في هاواي، إلى أين يذهب فعلياً المتقدم للحصول على CDL لتقديم الطلب والحصول على رخصة القيادة التجارية؟","options":["إلى مكتب ميداني إقليمي تابع لـ FMCSA","إلى أحد مكاتب ترخيص السائقين في المقاطعات (مثل خدمات عملاء هونولولو، ومالية ماوي/كاواي، وVRLD مقاطعة هاواي)","بإرسال الطلب بالبريد إلى مقر Hawaii DOT في هونولولو","في أي موقع لخدمة البريد الأمريكية على مستوى الولاية"],"explanation":"تُصدَر رخص CDL في هاواي عبر مكاتب ترخيص السائقين الأربعة في المقاطعات، التي تعمل تحت إشراف مكتب سلامة المركبات الآلية (MVSO) التابع لـ Hawaii DOT. المصدر: إشعار \"كيفية التقدم للحصول على CDL\" من Hawaii DOT MVSO وصفحات CDL للمقاطعات (CSD هونولولو، ومالية ماوي/كاواي، وVRLD مقاطعة هاواي)."},"80":{"q":"كم عدد فئات الإقرار الذاتي المتمايزة للتشغيل التجاري التي يجب على المتقدم للحصول على CDL في هاواي الاختيار من بينها عند الإقرار الذاتي بنوع قيادته؟","options":["اثنتان","أربع","ثلاث","ست"],"explanation":"يُقرّ المتقدمون في هاواي ذاتياً بإحدى أربع فئات: بين الولايات غير معفاة، أو بين الولايات معفاة، أو داخل الولاية غير معفاة، أو داخل الولاية معفاة. المصدر: الأسئلة الشائعة حول متطلبات الشهادة الطبية لـ CDL من Hawaii DOT MVSO (مُراجَع 5/19/2025)."},"81":{"q":"أيٌّ من فئات الإقرار الذاتي الأربع في هاواي لا تتطلب تقديم شهادة الفاحص الطبي (النموذج MCSA-5876)؟","options":["بين الولايات معفاة","بين الولايات غير معفاة","داخل الولاية غير معفاة","جميع الفئات الأربع تتطلب MEC"],"explanation":"وفقاً للأسئلة الشائعة لـ Hawaii MVSO، فإن السائقين الذين يُقرّون ذاتياً بأنهم \"بين الولايات معفاة\" (أو داخل الولاية معفاة) غير مطالبين بتقديم MEC؛ ولا يُطالب بذلك إلا السائقون من فئتي بين الولايات غير معفاة وداخل الولاية غير معفاة. المصدر: الأسئلة الشائعة حول متطلبات الشهادة الطبية من Hawaii DOT MVSO (مُراجَع 5/19/2025)."},"82":{"q":"اعتباراً من 19 مايو 2025، كيف يجب تقديم شهادة الفاحص الطبي (MCSA-5876) لسائق CDL غير المعفى في هاواي؟","options":["كنسخة ورقية مادية تُسلَّم في مكتب CDL بالمقاطعة","يرفعها السائق إلى بوابة موقع Hawaii DOT MVSO الإلكتروني","يرسلها صاحب عمل السائق بالبريد إلى FMCSA","مباشرةً إلى قاعدة بيانات السجل الوطني لـ FMCSA عبر الفاحص الطبي المعتمد"],"explanation":"اعتباراً من 19 مايو 2025، لم تعد HDOT ومكاتب CDL في المقاطعات تقبل نسخ MEC المادية؛ إذ يقدّم الفاحص الطبي المعتمد MEC مباشرةً إلى السجل الوطني لـ FMCSA، الذي ينقل البيانات إلى نظام رخص القيادة في هاواي. المصدر: الأسئلة الشائعة حول متطلبات الشهادة الطبية من Hawaii DOT MVSO (مُراجَع 5/19/2025)."},"83":{"q":"ما الأجزاء الثلاثة التي يتكوّن منها اختبار مهارات CDL في هاواي، والتي يجب اجتيازها جميعاً في الموعد نفسه؟","options":["الفرامل الهوائية، واختبار المواد الخطرة التحريري، والقيادة على الطريق","الفحص قبل الرحلة، وفحص النظر، واختبار المعرفة العامة","الفحص قبل الرحلة، والتحكم الأساسي بالمركبة، والقيادة على الطريق","الرجوع للخلف، والربط/فك الربط، واختبار تخصيص تحريري"],"explanation":"يتكوّن اختبار مهارات CDL في هاواي من ثلاثة أجزاء: الفحص قبل الرحلة، والتحكم الأساسي بالمركبة، واختبار القيادة على الطريق، وكلها تُجتاز في موعد واحد. المصدر: إشعار \"كيفية التقدم للحصول على CDL\" من Hawaii DOT MVSO وصفحة مكتب CDL في CSD هونولولو."},"84":{"q":"كم مدة صلاحية تصريح التعلّم (تصريح المتعلّم التجاري) لـ CDL في هاواي؟","options":["ستة أشهر","سنة واحدة","سنتان","180 يوماً"],"explanation":"تصريح التعلّم لـ CDL في هاواي صالح لمدة سنة واحدة ويتيح لحامله التدرّب على القيادة تحت إشراف. المصدر: إشعار \"كيفية التقدم للحصول على CDL\" من Hawaii DOT MVSO."},"85":{"q":"بعد إصدار CLP في هاواي، كم يجب على الحامل أن ينتظر قبل أن يتمكن من إجراء اختبار مهارات CDL؟","options":["30 يوماً","7 أيام","10 أيام","14 يوماً"],"explanation":"تتطلب القاعدة الفيدرالية المطبَّقة في هاواي الاحتفاظ بـ CLP لمدة 14 يوماً على الأقل قبل اختبار المهارات؛ وتشير CSD هونولولو إلى أنه يمكن تحديد مواعيد اختبار المهارات بعد 14 يوماً من إصدار التصريح. المصدر: صفحة مكتب CDL في CSD هونولولو؛ 49 CFR 383.25."},"86":{"q":"ما التدريب الذي يجب على المتقدم للحصول على CDL من الفئة A/B في هاواي إكماله قبل إجراء اختبار مهارات CDL (الساري اعتباراً من 7 فبراير 2022)؟","options":["دورة قيادة دفاعية تديرها الولاية","ندوة سلامة صفّية مدتها 40 ساعة من Hawaii DOT","تدريب مهني في موقع العمل بإشراف صاحب العمل فقط","تدريب سائق المستوى المبتدئ (ELDT) المسجَّل لدى FMCSA"],"explanation":"منذ 7 فبراير 2022، يجب على المتقدمين للحصول على CDL أولي من الفئة A/B (وبعض التخصيصات) إكمال تدريب سائق المستوى المبتدئ (ELDT) من FMCSA مع مزوّد مدرَج في سجل مزوّدي التدريب التابع لـ FMCSA قبل الاختبار. المصدر: قاعدة ELDT من FMCSA كما تطبّقها صفحة مكتب CDL في CSD هونولولو."},"87":{"q":"ما الحد الأدنى للعمر للحصول على CDL كامل (غير مقيّد) في هاواي؟","options":["18","19","25","21"],"explanation":"تشترط هاواي أن يكون عمر المتقدم 21 للحصول على CDL كامل (يمكن الحصول على تصريح CDL عند سن 18). المصدر: إشعار \"كيفية التقدم للحصول على CDL\" من Hawaii DOT MVSO وصفحة مكتب CDL في CSD هونولولو."},"88":{"q":"ما الحد الأدنى لمعيار النظر الذي يجب على المتقدم للحصول على CDL في هاواي استيفاؤه في اختبار النظر؟","options":["20/40 في كل عين (التصحيح مقبول)","20/20 في كل عين، دون تصحيح فقط","20/50 في العين الأفضل","20/30 بالعينين معاً"],"explanation":"تشترط هاواي حداً أدنى قدره 20/40 في كل عين، مع السماح بالعدسات التصحيحية، في اختبار النظر لـ CDL. المصدر: صفحة مكتب CDL في CSD هونولولو؛ Hawaii DOT MVSO."},"89":{"q":"أيٌّ مما يلي جزء من الوثائق المطلوبة عند التقدم للحصول على CDL في هاواي؟","options":["خطاب موثّق من صاحب عمل حالي في مجال النقل بالشاحنات","رخصة قيادة أساسية (غير تجارية) سارية من هاواي إضافة إلى إثبات الهوية ورقم الضمان الاجتماعي والإقامة","جواز سفر يكون هو الإثبات الوحيد المقبول للهوية","ثلاث سنوات من الإقرارات الضريبية المعتمدة"],"explanation":"يجب على المتقدمين للحصول على CDL في هاواي تقديم رخصة قيادة سارية من هاواي وإثبات الهوية/العمر (مثل شهادة الميلاد) ورقم الضمان الاجتماعي والإقامة. المصدر: إشعار \"كيفية التقدم للحصول على CDL\" من Hawaii DOT MVSO وصفحة مكتب CDL في CSD هونولولو."},"90":{"q":"إذا كان سائق في هاواي يعمل في التجارة بين الولايات المعفاة وغير المعفاة معاً، فبأي وضع يجب أن يُقرّ ذاتياً؟","options":["بين الولايات غير معفاة","بين الولايات معفاة","داخل الولاية معفاة","أيٌّ منهما، يجوز للسائق الاختيار بحرية"],"explanation":"يلزم Hawaii MVSO السائقَ الذي يعمل في كلا النوعين باختيار \"بين الولايات غير معفاة\" ليبقى مؤهلاً لكليهما، وهو ما يتطلب أيضاً تقديم MEC. المصدر: الأسئلة الشائعة حول متطلبات الشهادة الطبية من Hawaii DOT MVSO (مُراجَع 5/19/2025)."},"91":{"q":"خلال الانتقال إلى تقديم MEC إلكترونياً، كم مدة يوصي Hawaii MVSO بأن يحمل فيها سائق CDL نسخة من شهادة الفاحص الطبي الخاصة به بعد تقديمها إلى الفاحص الطبي؟","options":["لا تزيد عن 30 يوماً من التقديم","لا تزيد عن 60 يوماً من التقديم","لا تزيد عن 15 يوماً من التقديم","سنة واحدة بالضبط"],"explanation":"يوصي Hawaii MVSO بحمل نسخة MEC لمدة لا تزيد عن 15 يوماً من وقت تقديمها إلى الفاحص الطبي، لتغطية أي تأخيرات محتملة في التحديث الإلكتروني. المصدر: الأسئلة الشائعة حول متطلبات الشهادة الطبية من Hawaii DOT MVSO (مُراجَع 5/19/2025)."},"92":{"q":"تنتهي صلاحية الشهادة الطبية لحامل CDL في هاواي ولا يقدّم شهادة جديدة. في أي يوم تُزال جميع امتيازات CDL، مما يستلزم زيارة شخصية إلى مكتب CDL؟","options":["اليوم 54","اليوم 30","اليوم 90","اليوم 15"],"explanation":"وفقاً لـ Hawaii MVSO، إذا حُدّثت MEC خلال 53 يوماً فلا حاجة إلى حضور شخصي أو رسوم إعادة تفعيل؛ وفي اليوم 54 تُزال جميع امتيازات CDL ويجب على السائق زيارة مكتب CDL لإعادة التفعيل. المصدر: الأسئلة الشائعة حول متطلبات الشهادة الطبية من Hawaii DOT MVSO (مُراجَع 5/19/2025)."},"93":{"q":"ماذا يحدث لأهلية سائق في هاواي لحظة انتهاء صلاحية شهادته الطبية الصادرة عن DOT؟","options":["يصبح فوراً غير مؤهل لقيادة مركبة آلية تجارية","يحتفظ بكامل امتيازات CDL لفترة سماح تلقائية مدتها 90 يوماً","لا يتغير شيء حتى موعد تجديد CDL التالي","يجوز له مواصلة القيادة داخل الولاية فقط دون أي بطاقة طبية"],"explanation":"ينص Hawaii MVSO على أنه لحظة انتهاء صلاحية الشهادة الطبية، يصبح السائق غير مؤهل لتشغيل مركبة آلية تجارية؛ ثم يرسل MVSO إشعاراً بأن السائق لم يعد مؤهلاً بدنياً. المصدر: الأسئلة الشائعة حول متطلبات الشهادة الطبية من Hawaii DOT MVSO (مُراجَع 5/19/2025)."},"94":{"q":"في هاواي، قبل كم من الوقت من انتهاء الصلاحية يجوز عادةً لحامل CDL تجديد رخصة قيادته التجارية؟","options":["فقط في تاريخ انتهاء الصلاحية المحدد أو بعده","حتى 30 يوماً قبل تاريخ انتهاء الصلاحية","حتى 6 أشهر قبل تاريخ انتهاء الصلاحية","حتى سنتين قبل تاريخ انتهاء الصلاحية"],"explanation":"تسمح مكاتب المقاطعات في هاواي (مثل ماوي) بتجديد CDL في غضون ستة (6) أشهر قبل تاريخ انتهاء الصلاحية. المصدر: صفحة \"تجديد رخصة القيادة التجارية\" لمقاطعة ماوي."},"95":{"q":"كم مرة يجب على حامل CDL في هاواي تجديد تخصيص المواد الخطرة (HazMat)، بصرف النظر عن دورة الرخصة الأساسية؟","options":["كل 8 سنوات دون فحص خلفية","كل سنتين مع اختبار طريق جديد","كل 5 سنوات، بما في ذلك تقييم تهديد أمني من TSA","مرة واحدة فقط، فلا تنتهي صلاحيته بعد الإصدار الأول"],"explanation":"يجب تجديد تخصيص HazMat كل 5 سنوات ويتطلب اجتياز اختبار معرفة HazMat إضافةً إلى تقييم تهديد أمني من TSA (فحص خلفية قائم على بصمات الأصابع). المصدر: صفحة تجديد CDL لمقاطعة ماوي؛ برنامج تخصيص HazMat من TSA؛ 49 CFR Part 1572."},"96":{"q":"ما التزام الشهادة الطبية الواقع على سائقي هاواي الذين يحملون رخصة قيادة من الفئة 3 أو الفئة 4 ويشغّلون مركبة آلية تجارية؟","options":["يجب عليهم تقديم MEC إلى السجل الوطني لـ FMCSA مثل حاملي الفئة A","لا يقدّمون MEC إلى فاحص طبي لكن يجب أن يحملوا نسخة عند تشغيل مركبة آلية تجارية","هم معفون تماماً ولا يحتاجون إلى أي شهادة طبية على الإطلاق","يجب عليهم إرسال MEC ورقية بالبريد إلى MVSO كل سنة"],"explanation":"ينص Hawaii MVSO على أن حاملي رخص الفئة 3/4 الذين يشغّلون مركبة آلية تجارية لا يقدّمون MEC إلى فاحصهم الطبي لكنهم مطالبون مع ذلك بحمل نسخة من MEC عند تشغيل مركبة آلية تجارية. المصدر: الأسئلة الشائعة حول متطلبات الشهادة الطبية من Hawaii DOT MVSO (مُراجَع 5/19/2025)."},"97":{"q":"أيُّ وكالة في هاواي مسؤولة عن الإشراف على عملية الشهادة الطبية لـ CDL والتي يُوجَّه إليها الإقرار الذاتي؟","options":["إدارة الصحة في ولاية هاواي","شعبة المرور في قسم شرطة هونولولو","مكتب سلامة المركبات الآلية (MVSO) التابع لـ Hawaii DOT","وزارة العمل الأمريكية"],"explanation":"يدير مكتب سلامة المركبات الآلية (MVSO) التابع لـ Hawaii DOT الشهادة الطبية لـ CDL والإقرار الذاتي، بالتعاون مع مكاتب CDL في المقاطعات ومع FMCSA. المصدر: الأسئلة الشائعة حول متطلبات الشهادة الطبية من Hawaii DOT MVSO (مُراجَع 5/19/2025)."},"98":{"q":"بموجب قواعد هاواي المحدَّثة تبعاً لـ 49 CFR 391.46، ما الذي أصبح صحيحاً الآن بالنسبة لسائق مصاب بداء السكري المُعالَج بالأنسولين (ITDM) المضبوط جيداً ويسعى للحصول على شهادة طبية؟","options":["لا يزال يجب على السائق التقدم إلى MVSO للحصول على إعفاء ITDM منفصل داخل الولاية قبل أي شهادة","السائق مستبعَد بشكل دائم من حمل CDL في هاواي","يحتاج السائق فقط إلى مذكرة من أي صيدلي، وليس من فاحص طبي","يمكن لفاحص طبي معتمد إصدار MEC؛ ولم يعد طلب إعفاء ITDM منفصل داخل الولاية من MVSO مطلوباً"],"explanation":"وفقاً لـ 49 CFR 391.46 كما اعتمده Hawaii MVSO، يجوز لفاحص طبي معتمد إصدار MEC لسائق ITDM مستقر ومضبوط جيداً (باستخدام تقييم MCSA-5870)؛ ولم يعد طلب إعفاء ITDM منفصل داخل الولاية من MVSO مطلوباً. المصدر: الأسئلة الشائعة حول متطلبات الشهادة الطبية من Hawaii DOT MVSO (مُراجَع 5/19/2025)."}}};
